import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface MasterDataRow {
  officeId: string;
  officeName: string;
  officeType: string;
  officeJurisdiction: string;
  headOfficeName: string;
  subDivisionName: string;
}

export interface BookingDataRow {
  officeId: string; // Col A
  officeName: string; // Col B
  productName: string; // Col C
  articles: number; // Col D
  postage: number; // Col E
  vas: number; // Col F
  tax: number; // Col G
  prepaidFm: number; // Col H
  prepaidPs: number; // Col I
  prepaidSs: number; // Col J
  totalAmount: number; // Col K (Revenue)
  avgWeight: number; // Col L

  // Enriched fields from Master Data
  subDivision?: string;
  headOffice?: string;
  officeType?: string;
}

export interface AnalysisSummary {
  subDivisionName: string;
  articleCount: number;
  totalRevenue: number;
}

export interface OfficeSummary {
  officeName: string;
  articleCount: number;
  totalRevenue: number;
}

export enum ProductGroup {
  ALL = 'Total Revenue',
  DOMESTIC = 'Domestic Mail Revenue',
  PARCEL = 'Parcel Revenue',
  INTERNATIONAL = 'International Mail Revenue'
}

export interface FilterState {
  officeId: string;
  officeName: string;
  productName: string;
}

import * as XLSX from 'xlsx';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { BookingDataRow, MasterDataRow } from './types';
import { MASTER_DATA } from './constants';

export const parseExcelFile = (file: File): Promise<BookingDataRow[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const data = e.target?.result;
      if (!data) return reject("No data read");

      const workbook = XLSX.read(data, { type: 'binary' });
      const sheetName = workbook.SheetNames[0];
      const sheet = workbook.Sheets[sheetName];
      // Use header: 1 to get array of arrays, then map manually to ensure Col A = Index 0
      const jsonData = XLSX.utils.sheet_to_json(sheet, { header: 1 }) as any[][];

      // Remove empty rows or header rows if necessary. 
      // Assuming row 1 is header, data starts from row 2 (index 1), OR if purely raw data, start index 0.
      // The prompt says "Ignore extra blank rows". 
      // We will look for rows where Index 0 (Office ID) is present and looks valid.

      const parsedData: BookingDataRow[] = [];

      jsonData.forEach((row, index) => {
        // Simple heuristic to skip header: check if col D (articles) is a number
        const articles = parseFloat(row[3]);
        if (isNaN(articles) && index === 0) return; // Likely header row

        const officeId = row[0] ? String(row[0]).trim() : '';
        if (!officeId) return; // Skip empty rows

        // Find Master Data
        const master = MASTER_DATA.find(m => m.officeId === officeId);

        const entry: BookingDataRow = {
          officeId: officeId,
          officeName: row[1],
          productName: row[2],
          articles: Number(row[3]) || 0,
          postage: Number(row[4]) || 0,
          vas: Number(row[5]) || 0,
          tax: Number(row[6]) || 0,
          prepaidFm: Number(row[7]) || 0,
          prepaidPs: Number(row[8]) || 0,
          prepaidSs: Number(row[9]) || 0,
          totalAmount: Number(row[10]) || 0, // Column K
          avgWeight: Number(row[11]) || 0,

          // Enrichment
          subDivision: master?.subDivisionName || 'Unknown',
          headOffice: master?.headOfficeName || 'Unknown',
          officeType: master?.officeType || 'Unknown'
        };
        parsedData.push(entry);
      });

      resolve(parsedData);
    };
    reader.onerror = (err) => reject(err);
    reader.readAsBinaryString(file);
  });
};

export const formatCurrency = (val: number) => {
  return new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR' }).format(val);
};

export const exportToPDF = (headers: string[], data: any[][], title: string, landscape = false) => {
  const doc = new jsPDF(landscape ? 'l' : 'p', 'mm', 'a4');
  doc.text(title, 14, 15);
  autoTable(doc, {
    head: [headers],
    body: data,
    startY: 20,
    theme: 'grid',
    styles: { fontSize: 8 },
    headStyles: { fillColor: [41, 128, 185] }
  });
  doc.save(`${title.replace(/\s+/g, '_')}.pdf`);
};

export const exportToExcel = (data: any[], fileName: string) => {
  const ws = XLSX.utils.json_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Report");
  XLSX.writeFile(wb, `${fileName}.xlsx`);
};

import React, { useMemo, useState } from 'react';
import { BookingDataRow, FilterState } from '../types';
import { formatCurrency, exportToPDF } from '../utils';
import { Search, Printer } from 'lucide-react';

interface DataSheetProps {
  data: BookingDataRow[];
}

const DataSheet: React.FC<DataSheetProps> = ({ data }) => {
  const [filters, setFilters] = useState<FilterState>({
    officeId: '',
    officeName: '',
    productName: ''
  });

  const filteredData = useMemo(() => {
    return data.filter(row => {
      const matchId = row.officeId.toLowerCase().includes(filters.officeId.toLowerCase());
      const matchName = row.officeName.toLowerCase().includes(filters.officeName.toLowerCase());
      const matchProduct = row.productName.toLowerCase().includes(filters.productName.toLowerCase());
      return matchId && matchName && matchProduct;
    });
  }, [data, filters]);

  const totals = useMemo(() => {
    return filteredData.reduce((acc, curr) => ({
      articles: acc.articles + curr.articles,
      postage: acc.postage + curr.postage,
      vas: acc.vas + curr.vas,
      tax: acc.tax + curr.tax,
      totalAmount: acc.totalAmount + curr.totalAmount
    }), { articles: 0, postage: 0, vas: 0, tax: 0, totalAmount: 0 });
  }, [filteredData]);

  const handlePrint = () => {
    const tableData = filteredData.map(row => [
      row.officeId,
      row.officeName,
      row.productName,
      row.articles,
      formatCurrency(row.totalAmount)
    ]);

    // Append total row
    tableData.push(['', 'GRAND TOTAL', '', totals.articles, formatCurrency(totals.totalAmount)]);

    exportToPDF(
      ['Office ID', 'Office Name', 'Product Name', 'Articles', 'Total Amount'],
      tableData,
      'Mail Booking Data Sheet',
      true
    );
  };

  return (
    <div className="space-y-4">
      {/* Filters */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 bg-white p-4 rounded-lg shadow-sm border border-slate-200">
        <div className="relative">
          <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
          <input
            type="text"
            placeholder="Search Office ID"
            className="pl-10 w-full border border-slate-300 rounded-md py-2 focus:ring-2 focus:ring-blue-500 focus:outline-none"
            value={filters.officeId}
            onChange={e => setFilters({ ...filters, officeId: e.target.value })}
          />
        </div>
        <div className="relative">
          <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
          <input
            type="text"
            placeholder="Search Office Name"
            className="pl-10 w-full border border-slate-300 rounded-md py-2 focus:ring-2 focus:ring-blue-500 focus:outline-none"
            value={filters.officeName}
            onChange={e => setFilters({ ...filters, officeName: e.target.value })}
          />
        </div>
        <div className="relative">
          <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
          <input
            type="text"
            placeholder="Search Product Name"
            className="pl-10 w-full border border-slate-300 rounded-md py-2 focus:ring-2 focus:ring-blue-500 focus:outline-none"
            value={filters.productName}
            onChange={e => setFilters({ ...filters, productName: e.target.value })}
          />
        </div>
        <button
          onClick={handlePrint}
          className="flex items-center justify-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-md hover:bg-blue-700 transition-colors"
        >
          <Printer className="h-4 w-4" /> Export PDF
        </button>
      </div>

      {/* Table */}
      <div className="bg-white rounded-lg shadow overflow-hidden border border-slate-200">
        <div className="overflow-x-auto max-h-[70vh]">
          <table className="min-w-full divide-y divide-slate-200">
            <thead className="bg-slate-50 sticky top-0 z-10">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Office ID</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Office Name</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Product Name</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-slate-500 uppercase tracking-wider">Articles</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-slate-500 uppercase tracking-wider">Postage</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-slate-500 uppercase tracking-wider">Total Amount</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-slate-200">
              {filteredData.map((row, idx) => (
                <tr key={`${row.officeId}-${idx}`} className="hover:bg-slate-50">
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-slate-900">{row.officeId}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">{row.officeName}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">{row.productName}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 text-right">{row.articles}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 text-right">{row.postage.toFixed(2)}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-900 font-medium text-right">{formatCurrency(row.totalAmount)}</td>
                </tr>
              ))}
            </tbody>
            <tfoot className="bg-slate-100 sticky bottom-0 font-semibold">
              <tr>
                <td colSpan={3} className="px-6 py-4 text-sm text-slate-900 text-center">GRAND TOTAL</td>
                <td className="px-6 py-4 text-sm text-slate-900 text-right">{totals.articles}</td>
                <td className="px-6 py-4 text-sm text-slate-900 text-right">{totals.postage.toFixed(2)}</td>
                <td className="px-6 py-4 text-sm text-slate-900 text-right">{formatCurrency(totals.totalAmount)}</td>
              </tr>
            </tfoot>
          </table>
        </div>
      </div>
    </div>
  );
};

export default DataSheet;

import React, { useState, useMemo } from 'react';
import { BookingDataRow, ProductGroup, AnalysisSummary, OfficeSummary } from '../types';
import { PRODUCTS, MASTER_DATA } from '../constants';
import { formatCurrency, exportToPDF, exportToExcel } from '../utils';
import { BarChart, IndianRupee, Package, Globe, FileText, Download } from 'lucide-react';

interface DashboardAnalysisProps {
  data: BookingDataRow[];
}

const DashboardAnalysis: React.FC<DashboardAnalysisProps> = ({ data }) => {
  const [selectedContext, setSelectedContext] = useState<string | null>(null);
  const [contextType, setContextType] = useState<'Category' | 'Product' | null>(null);

  // --- Aggregation Logic for Top Cards ---
  const revenueStats = useMemo(() => {
    const calculate = (products: string[] | null) => {
      return data
        .filter(r => products ? products.includes(r.productName) : true)
        .reduce((sum, r) => sum + r.totalAmount, 0);
    };

    return {
      total: calculate(null),
      domestic: calculate(PRODUCTS.DOMESTIC),
      parcel: calculate(PRODUCTS.PARCEL),
      international: calculate(PRODUCTS.INTERNATIONAL),
    };
  }, [data]);

  // --- Aggregation Logic for Product Cards ---
  const productStats = useMemo(() => {
    const stats: Record<string, { articles: number; revenue: number }> = {};
    PRODUCTS.ALL.forEach(p => stats[p] = { articles: 0, revenue: 0 });

    data.forEach(row => {
      if (stats[row.productName]) {
        stats[row.productName].articles += row.articles;
        stats[row.productName].revenue += row.totalAmount;
      }
    });
    return stats;
  }, [data]);

  // --- Logic for Reports (Table Data) ---
  const reportData = useMemo(() => {
    if (!selectedContext) return null;

    let filteredData = [];
    if (contextType === 'Category') {
       if (selectedContext === ProductGroup.ALL) filteredData = data;
       else if (selectedContext === ProductGroup.DOMESTIC) filteredData = data.filter(d => PRODUCTS.DOMESTIC.includes(d.productName));
       else if (selectedContext === ProductGroup.PARCEL) filteredData = data.filter(d => PRODUCTS.PARCEL.includes(d.productName));
       else if (selectedContext === ProductGroup.INTERNATIONAL) filteredData = data.filter(d => PRODUCTS.INTERNATIONAL.includes(d.productName));
    } else {
       // Single Product
       filteredData = data.filter(d => d.productName === selectedContext);
    }

    // Sub-Division Wise
    const subDivMap = new Map<string, AnalysisSummary>();
    filteredData.forEach(row => {
      const name = row.subDivision || 'Unknown';
      const current = subDivMap.get(name) || { subDivisionName: name, articleCount: 0, totalRevenue: 0 };
      current.articleCount += row.articles;
      current.totalRevenue += row.totalAmount;
      subDivMap.set(name, current);
    });
    const subDivReport = Array.from(subDivMap.values()).sort((a,b) => b.totalRevenue - a.totalRevenue);

    // PO Wise
    const poMap = new Map<string, OfficeSummary>();
    filteredData.forEach(row => {
      const name = row.officeName;
      const current = poMap.get(name) || { officeName: name, articleCount: 0, totalRevenue: 0 };
      current.articleCount += row.articles;
      current.totalRevenue += row.totalAmount;
      poMap.set(name, current);
    });
    const poReport = Array.from(poMap.values()).sort((a,b) => b.totalRevenue - a.totalRevenue);

    return { subDivReport, poReport };
  }, [data, selectedContext, contextType]);

  // --- Non-Booking Analysis ---
  const nonBookingStats = useMemo(() => {
    const bookedIds = new Set(data.map(r => r.officeId));

    // Using MASTER_DATA from constants to check against
    const allBOs = MASTER_DATA.filter(m => m.officeType === 'B.O');
    const allPOs = MASTER_DATA.filter(m => m.officeType === 'P.O' || m.officeType === 'H.O' || m.officeType === 'S.O'); // Assuming SO/HO fall under PO umbrella or generic non-BO

    const bookedBOs = allBOs.filter(m => bookedIds.has(m.officeId));
    const notBookedBOs = allBOs.filter(m => !bookedIds.has(m.officeId));

    const bookedPOs = allPOs.filter(m => bookedIds.has(m.officeId));
    const notBookedPOs = allPOs.filter(m => !bookedIds.has(m.officeId));

    return {
      bo: { total: allBOs.length, booked: bookedBOs.length, notBooked: notBookedBOs.length, list: notBookedBOs },
      po: { total: allPOs.length, booked: bookedPOs.length, notBooked: notBookedPOs.length, list: notBookedPOs }
    };
  }, [data]);


  const handleCardClick = (context: string, type: 'Category' | 'Product') => {
    setSelectedContext(context);
    setContextType(type);
    // Scroll to report
    setTimeout(() => {
      document.getElementById('report-section')?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const exportReport = (type: 'pdf' | 'excel', reportType: 'subdiv' | 'po') => {
    if (!reportData) return;
    const isSubDiv = reportType === 'subdiv';
    const rawData = isSubDiv ? reportData.subDivReport : reportData.poReport;
    const fileName = `${selectedContext} - ${isSubDiv ? 'SubDivision' : 'PO'} Report`;

    if (type === 'excel') {
      exportToExcel(rawData, fileName);
    } else {
      const headers = isSubDiv 
        ? ['Sl No', 'Sub-Division Name', 'Articles', 'Postage Amount']
        : ['Sl No', 'Name of the PO', 'Articles', 'Postage Amount'];

      const rows = rawData.map((row, i) => [
        i + 1,
        isSubDiv ? (row as AnalysisSummary).subDivisionName : (row as OfficeSummary).officeName,
        row.articleCount,
        formatCurrency(row.totalRevenue)
      ]);

      // Totals
      const totalArts = rawData.reduce((s, c) => s + c.articleCount, 0);
      const totalRev = rawData.reduce((s, c) => s + c.totalRevenue, 0);
      rows.push(['', 'TOTAL', totalArts, formatCurrency(totalRev)]);

      exportToPDF(headers, rows, fileName);
    }
  };

  return (
    <div className="space-y-8 pb-10">

      {/* SECTION 1: REVENUE VERTICALS */}
      <section>
        <h2 className="text-xl font-bold text-slate-800 mb-4 flex items-center gap-2">
          <IndianRupee className="text-blue-600" /> Revenue Verticals
        </h2>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <RevenueCard 
            title={ProductGroup.ALL} 
            amount={revenueStats.total} 
            icon={<BarChart />} 
            active={selectedContext === ProductGroup.ALL}
            onClick={() => handleCardClick(ProductGroup.ALL, 'Category')}
          />
          <RevenueCard 
            title={ProductGroup.DOMESTIC} 
            amount={revenueStats.domestic} 
            icon={<FileText />} 
            active={selectedContext === ProductGroup.DOMESTIC}
            onClick={() => handleCardClick(ProductGroup.DOMESTIC, 'Category')}
          />
          <RevenueCard 
            title={ProductGroup.PARCEL} 
            amount={revenueStats.parcel} 
            icon={<Package />} 
            active={selectedContext === ProductGroup.PARCEL}
            onClick={() => handleCardClick(ProductGroup.PARCEL, 'Category')}
          />
          <RevenueCard 
            title={ProductGroup.INTERNATIONAL} 
            amount={revenueStats.international} 
            icon={<Globe />} 
            active={selectedContext === ProductGroup.INTERNATIONAL}
            onClick={() => handleCardClick(ProductGroup.INTERNATIONAL, 'Category')}
          />
        </div>
      </section>

      {/* SECTION 2: PRODUCT CARDS */}
      <section>
        <h2 className="text-xl font-bold text-slate-800 mb-4 flex items-center gap-2">
          <Package className="text-blue-600" /> Product Performance
        </h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
          {PRODUCTS.ALL.map(product => (
            <div 
              key={product}
              onClick={() => handleCardClick(product, 'Product')}
              className={`p-4 rounded-xl border cursor-pointer transition-all duration-200 shadow-sm hover:shadow-md 
                ${selectedContext === product ? 'border-blue-500 bg-blue-50 ring-2 ring-blue-200' : 'border-slate-200 bg-white hover:border-blue-300'}`}
            >
              <h3 className="text-sm font-semibold text-slate-700 min-h-[40px] mb-2">{product}</h3>
              <div className="flex justify-between items-end">
                <div>
                  <p className="text-xs text-slate-500">Articles</p>
                  <p className="font-bold text-slate-900">{productStats[product].articles}</p>
                </div>
                <div className="text-right">
                  <p className="text-xs text-slate-500">Revenue</p>
                  <p className="font-bold text-blue-700">{formatCurrency(productStats[product].revenue)}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* SECTION 3: REPORT SECTION */}
      {selectedContext && reportData && (
        <section id="report-section" className="bg-slate-100 p-6 rounded-2xl border border-slate-200 animate-in fade-in slide-in-from-bottom-4 duration-500">
           <div className="mb-6">
             <h2 className="text-2xl font-bold text-slate-800">Detailed Report: <span className="text-blue-600">{selectedContext}</span></h2>
             <p className="text-slate-500">Analysis broken down by Sub-Division and Post Office</p>
           </div>

           <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
             {/* Sub Division Report */}
             <ReportTable 
                title="Sub-Division Wise Summary"
                headers={['#', 'Sub-Division', 'Articles', 'Revenue']}
                rows={reportData.subDivReport.map((r, i) => [i+1, r.subDivisionName, r.articleCount, r.totalRevenue])}
                onExportExcel={() => exportReport('excel', 'subdiv')}
                onExportPDF={() => exportReport('pdf', 'subdiv')}
             />

             {/* PO Report */}
             <ReportTable 
                title="Post Office Wise Summary"
                headers={['#', 'Post Office', 'Articles', 'Revenue']}
                rows={reportData.poReport.map((r, i) => [i+1, r.officeName, r.articleCount, r.totalRevenue])}
                onExportExcel={() => exportReport('excel', 'po')}
                onExportPDF={() => exportReport('pdf', 'po')}
             />
           </div>
        </section>
      )}

      {/* SECTION 4: NON-BOOKING ANALYSIS */}
      <section className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h2 className="text-xl font-bold text-slate-800 mb-6">Non-Booking Analysis</h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          <StatBox title="Branch Offices (BO)" total={nonBookingStats.bo.total} booked={nonBookingStats.bo.booked} notBooked={nonBookingStats.bo.notBooked} />
          <StatBox title="Post Offices (PO/SO/HO)" total={nonBookingStats.po.total} booked={nonBookingStats.po.booked} notBooked={nonBookingStats.po.notBooked} />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <ZeroBookingTable title="BOs with ZERO Booking" offices={nonBookingStats.bo.list} />
          <ZeroBookingTable title="POs with ZERO Booking" offices={nonBookingStats.po.list} />
        </div>
      </section>

    </div>
  );
};

// --- Sub Components ---

const RevenueCard = ({ title, amount, icon, active, onClick }: any) => (
  <div 
    onClick={onClick}
    className={`p-6 rounded-xl shadow-sm border cursor-pointer transition-all duration-200 flex items-center justify-between
    ${active ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white border-slate-200 hover:border-blue-300 text-slate-800'}`}
  >
    <div>
      <p className={`text-sm font-medium ${active ? 'text-blue-100' : 'text-slate-500'}`}>{title}</p>
      <p className="text-2xl font-bold mt-1">{formatCurrency(amount)}</p>
    </div>
    <div className={`p-3 rounded-full ${active ? 'bg-white/20' : 'bg-slate-100 text-blue-600'}`}>
      {icon}
    </div>
  </div>
);

const ReportTable = ({ title, headers, rows, onExportExcel, onExportPDF }: any) => {
  const totalArts = rows.reduce((s: number, r: any) => s + r[2], 0);
  const totalRev = rows.reduce((s: number, r: any) => s + r[3], 0);

  return (
    <div className="bg-white rounded-lg shadow overflow-hidden flex flex-col h-[500px]">
      <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
        <h3 className="font-semibold text-slate-700">{title}</h3>
        <div className="flex gap-2">
           <button onClick={onExportExcel} className="p-2 text-green-600 hover:bg-green-50 rounded" title="Excel"><Download size={16}/></button>
           <button onClick={onExportPDF} className="p-2 text-red-600 hover:bg-red-50 rounded" title="PDF"><FileText size={16}/></button>
        </div>
      </div>
      <div className="overflow-auto flex-1">
        <table className="w-full text-sm text-left">
          <thead className="bg-slate-50 sticky top-0">
            <tr>
              {headers.map((h: string) => <th key={h} className="px-4 py-3 font-medium text-slate-500">{h}</th>)}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
             {rows.map((row: any, i: number) => (
               <tr key={i} className="hover:bg-slate-50">
                 <td className="px-4 py-2 text-slate-500">{row[0]}</td>
                 <td className="px-4 py-2 font-medium">{row[1]}</td>
