import React, { useState } from 'react';
import DataSheet from './components/DataSheet';
import DashboardAnalysis from './components/DashboardAnalysis';
import { parseExcelFile } from './utils';
import { BookingDataRow } from './types';
import { LayoutDashboard, Table, UploadCloud, AlertCircle } from 'lucide-react';

function App() {
  const [activeTab, setActiveTab] = useState<'datasheet' | 'dashboard'>('datasheet');
  const [data, setData] = useState<BookingDataRow[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setLoading(true);
    setError(null);
    try {
      const parsedData = await parseExcelFile(file);
      if (parsedData.length === 0) {
        throw new Error("No valid booking data found in the uploaded file.");
      }
      setData(parsedData);
      // Switch to dashboard if data loads successfully for instant gratification
      setActiveTab('dashboard'); 
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to parse file");
    } finally {
      setLoading(false);
      // Reset input
      event.target.value = ''; 
    }
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Header */}
      <header className="bg-white shadow-sm border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="w-8 h-8 bg-blue-600 rounded-md flex items-center justify-center text-white font-bold">
               IP
             </div>
             <h1 className="text-xl font-bold text-slate-800 hidden sm:block">Mail Booking Monitoring</h1>
          </div>

          <div className="flex gap-2 bg-slate-100 p-1 rounded-lg">
             <button
               onClick={() => setActiveTab('datasheet')}
               className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-all ${
                 activeTab === 'datasheet' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-900'
               }`}
             >
               <Table size={16} /> Data Sheet
             </button>
             <button
               onClick={() => setActiveTab('dashboard')}
               className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-all ${
                 activeTab === 'dashboard' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-900'
               }`}
             >
               <LayoutDashboard size={16} /> Analysis
             </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Empty State / Upload Area */}
        {data.length === 0 && (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center">
            <div className="bg-white p-10 rounded-2xl shadow-sm border border-slate-200 max-w-lg w-full">
              <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-6">
                <UploadCloud size={32} />
              </div>
              <h2 className="text-2xl font-bold text-slate-800 mb-2">Upload Booking Data</h2>
              <p className="text-slate-500 mb-8">Select your Excel (.xlsx) or CSV file containing the booking data. The system will automatically map the columns.</p>

              <label className="block w-full">
                <span className="sr-only">Choose file</span>
                <input 
                  type="file" 
                  accept=".csv, .xlsx, .xls"
                  onChange={handleFileUpload}
                  className="block w-full text-sm text-slate-500
                    file:mr-4 file:py-3 file:px-6
                    file:rounded-full file:border-0
                    file:text-sm file:font-semibold
                    file:bg-blue-600 file:text-white
                    hover:file:bg-blue-700
                    cursor-pointer bg-slate-50 rounded-full border border-slate-200"
                />
              </label>

              {loading && <p className="mt-4 text-blue-600 animate-pulse">Processing file...</p>}
              {error && (
                <div className="mt-4 p-3 bg-red-50 text-red-600 rounded-lg flex items-center gap-2 text-sm text-left">
                  <AlertCircle size={16} /> {error}
                </div>
              )}
            </div>
          </div>
        )}

        {/* Content Tabs */}
        {data.length > 0 && (
          <>
            <div className="mb-6 flex justify-between items-center">
               <p className="text-sm text-slate-500">
                 Loaded <span className="font-bold text-slate-800">{data.length}</span> records.
               </p>
               <label className="cursor-pointer text-sm text-blue-600 hover:underline flex items-center gap-1">
                 <UploadCloud size={14}/> Upload New File
                 <input type="file" accept=".csv, .xlsx, .xls" className="hidden" onChange={handleFileUpload} />
               </label>
            </div>

            {activeTab === 'datasheet' && <DataSheet data={data} />}
            {activeTab === 'dashboard' && <DashboardAnalysis data={data} />}
          </>
        )}
      </main>
    </div>
  );
}

export default App;

