};

const ReportTable = ({ title, headers, rows, onExportExcel, onExportPDF }: any) => {
  const totalArts = rows.reduce((s: number, r: any) => s + r[2], 0);
  const totalPostage = rows.reduce((s: number, r: any) => s + r[3], 0);
  const totalRev = rows.reduce((s: number, r: any) => s + r[4], 0);

  return (
    <div className="bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden flex flex-col h-[600px]">
      <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
        <h3 className="font-semibold text-slate-700">{title}</h3>
        <div className="flex gap-2">
           <button onClick={onExportExcel} className="p-2 text-green-700 hover:bg-green-100 rounded border border-transparent hover:border-green-200 transition-colors" title="Export Excel"><Download size={16}/></button>
           <button onClick={onExportPDF} className="p-2 text-red-700 hover:bg-red-100 rounded border border-transparent hover:border-red-200 transition-colors" title="Export PDF"><FileText size={16}/></button>
        </div>
      </div>
      <div className="overflow-auto flex-1">
        <table className="w-full text-xs text-left">
          <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
