import React, { useState, useEffect, useMemo } from 'react';
import DataSheet from './components/DataSheet';
import DashboardAnalysis from './components/DashboardAnalysis';
import { parseExcelFile, fetchMasterDataFromUrl } from './utils';
import { BookingDataRow, RawBookingRow, MasterDataRow } from './types';
import { MASTER_DATA as DEFAULT_MASTER_DATA } from './constants';
import { LayoutDashboard, Table, UploadCloud, AlertCircle, RefreshCw } from 'lucide-react';

// Link to the published CSV of the Google Sheet provided by user
const MASTER_DATA_URL = 'https://docs.google.com/spreadsheets/d/1sqgOjtJ5uaiI6qIG_LZMZ-D0yaUhJG_FVxZLDeQORFA/export?format=csv';

function App() {
  const [activeTab, setActiveTab] = useState<'datasheet' | 'dashboard'>('datasheet');

  // State for raw uploaded booking data
  const [rawBookingData, setRawBookingData] = useState<RawBookingRow[]>([]);

  // State for Master Data (defaults to hardcoded constants)
  const [masterData, setMasterData] = useState<MasterDataRow[]>(DEFAULT_MASTER_DATA);
  const [isMasterDataLoading, setIsMasterDataLoading] = useState(false);
  const [masterDataSource, setMasterDataSource] = useState<'Default' | 'Synced'>('Default');

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Auto-sync master data on mount
  useEffect(() => {
    handleSyncMasterData(true);
  }, []);

  const handleSyncMasterData = async (silent = false) => {
    if (!silent) setIsMasterDataLoading(true);
    try {
      const data = await fetchMasterDataFromUrl(MASTER_DATA_URL);
      if (data && data.length > 0) {
        setMasterData(data);
        setMasterDataSource('Synced');
        if(!silent) alert(`Successfully synced ${data.length} master data records from Google Sheet.`);
      }
    } catch (e) {
      console.error("Sync failed", e);
      // Fallback is already set
    } finally {
      if (!silent) setIsMasterDataLoading(false);
    }
  };

  // Derive enriched booking data whenever raw data or master data changes
  const enrichedBookingData: BookingDataRow[] = useMemo(() => {
    return rawBookingData.map(row => {
      const master = masterData.find(m => m.officeId === row.officeId);
      return {
        ...row,
        subDivision: master?.subDivisionName || 'Unknown',
        headOffice: master?.headOfficeName || 'Unknown',
        officeType: master?.officeType || 'Unknown'
      };
    });
  }, [rawBookingData, masterData]);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setLoading(true);
    setError(null);
    try {
      // Parse to raw rows
      const rawData = await parseExcelFile(file);
      if (rawData.length === 0) {
        throw new Error("No valid booking data found in the uploaded file.");
      }
      setRawBookingData(rawData);
      setActiveTab('dashboard'); 
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to parse file");
    } finally {
      setLoading(false);
      event.target.value = ''; 
    }
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Header */}
      <header className="bg-white shadow-sm border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="w-8 h-8 bg-blue-600 rounded-md flex items-center justify-center text-white font-bold">
               IP
             </div>
             <h1 className="text-xl font-bold text-slate-800 hidden sm:block">Mail Booking Monitoring</h1>
          </div>

          <div className="flex items-center gap-4">
             {/* Master Data Status */}
             <div className="hidden md:flex items-center gap-2 text-xs text-slate-500 bg-slate-50 px-3 py-1.5 rounded-full border border-slate-200">
               <span className={`w-2 h-2 rounded-full ${masterDataSource === 'Synced' ? 'bg-green-500' : 'bg-amber-500'}`}></span>
               <span>Master Data: {masterDataSource} ({masterData.length} records)</span>
               <button 
                  onClick={() => handleSyncMasterData(false)} 
                  disabled={isMasterDataLoading}
                  className="ml-1 p-1 hover:bg-slate-200 rounded-full text-blue-600"
                  title="Sync Master Data from Google Sheet"
                >
                 <RefreshCw size={12} className={isMasterDataLoading ? 'animate-spin' : ''}/>
               </button>
             </div>

             <div className="flex gap-2 bg-slate-100 p-1 rounded-lg">
                <button
                  onClick={() => setActiveTab('datasheet')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-all ${
                    activeTab === 'datasheet' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-900'
                  }`}
                >
                  <Table size={16} /> Data Sheet
                </button>
                <button
                  onClick={() => setActiveTab('dashboard')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-all ${
                    activeTab === 'dashboard' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-900'
                  }`}
                >
                  <LayoutDashboard size={16} /> Analysis
                </button>
             </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Empty State / Upload Area */}
        {rawBookingData.length === 0 && (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center">
            <div className="bg-white p-10 rounded-2xl shadow-sm border border-slate-200 max-w-lg w-full">
              <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-6">
                <UploadCloud size={32} />
              </div>
              <h2 className="text-2xl font-bold text-slate-800 mb-2">Upload Booking Data</h2>
              <p className="text-slate-500 mb-8">Select your Excel (.xlsx) or CSV file containing the booking data. The system will map it with {masterData.length} master records.</p>

              <label className="block w-full">
                <span className="sr-only">Choose file</span>
                <input 
                  type="file" 
                  accept=".csv, .xlsx, .xls"
                  onChange={handleFileUpload}
