import React, { useMemo, useState } from 'react';
import { BookingDataRow, FilterState } from '../types';
import { formatCurrency, exportToPDF } from '../utils';
import { Search, Printer } from 'lucide-react';

interface DataSheetProps {
  data: BookingDataRow[];
}

const DataSheet: React.FC<DataSheetProps> = ({ data }) => {
  const [filters, setFilters] = useState<FilterState>({
    officeId: '',
    officeName: '',
    productName: ''
  });

  const filteredData = useMemo(() => {
    return data.filter(row => {
      const matchId = row.officeId.toLowerCase().includes(filters.officeId.toLowerCase());
      const matchName = row.officeName.toLowerCase().includes(filters.officeName.toLowerCase());
      const matchProduct = row.productName.toLowerCase().includes(filters.productName.toLowerCase());
      return matchId && matchName && matchProduct;
    });
  }, [data, filters]);

  const totals = useMemo(() => {
    return filteredData.reduce((acc, curr) => ({
      articles: acc.articles + curr.articles,
      postage: acc.postage + curr.postage,
      vas: acc.vas + curr.vas,
      tax: acc.tax + curr.tax,
      totalAmount: acc.totalAmount + curr.totalAmount
    }), { articles: 0, postage: 0, vas: 0, tax: 0, totalAmount: 0 });
  }, [filteredData]);

  const handlePrint = () => {
    const tableData = filteredData.map(row => [
      row.officeId,
      row.officeName,
      row.productName,
      row.articles,
      formatCurrency(row.totalAmount)
    ]);

    // Append total row
    tableData.push(['', 'GRAND TOTAL', '', totals.articles, formatCurrency(totals.totalAmount)]);

    exportToPDF(
      ['Office ID', 'Office Name', 'Product Name', 'Articles', 'Total Amount'],
      tableData,
      'Mail Booking Data Sheet',
      true
    );
  };

  return (
    <div className="space-y-4">
      {/* Filters */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 bg-white p-4 rounded-lg shadow-sm border border-slate-200">
        <div className="relative">
          <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
          <input
            type="text"
            placeholder="Search Office ID"
            className="pl-10 w-full border border-slate-300 rounded-md py-2 focus:ring-2 focus:ring-red-500 focus:outline-none"
            value={filters.officeId}
            onChange={e => setFilters({ ...filters, officeId: e.target.value })}
          />
        </div>
        <div className="relative">
          <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
          <input
            type="text"
            placeholder="Search Office Name"
            className="pl-10 w-full border border-slate-300 rounded-md py-2 focus:ring-2 focus:ring-red-500 focus:outline-none"
            value={filters.officeName}
            onChange={e => setFilters({ ...filters, officeName: e.target.value })}
          />
        </div>
        <div className="relative">
          <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
          <input
            type="text"
            placeholder="Search Product Name"
            className="pl-10 w-full border border-slate-300 rounded-md py-2 focus:ring-2 focus:ring-red-500 focus:outline-none"
            value={filters.productName}
            onChange={e => setFilters({ ...filters, productName: e.target.value })}
          />
        </div>
        <button
          onClick={handlePrint}
          className="flex items-center justify-center gap-2 bg-red-700 text-white px-4 py-2 rounded-md hover:bg-red-800 transition-colors"
        >
          <Printer className="h-4 w-4" /> Export PDF
        </button>
      </div>

      {/* Table */}
      <div className="bg-white rounded-lg shadow overflow-hidden border border-slate-200">
        <div className="overflow-x-auto max-h-[70vh]">
          <table className="min-w-full divide-y divide-slate-200">
            <thead className="bg-slate-50 sticky top-0 z-10">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Office ID</th>
