           <button onClick={onExportPDF} className="flex items-center gap-1 px-3 py-1 bg-red-50 text-red-700 text-xs rounded border border-red-200 hover:bg-red-100 transition-colors" title="Export PDF"><FileText size={14}/> PDF</button>
