const DetailedCard = ({ title, data, icon, colorClass, active, onClick, compact = false, customColor, onColorChange }: any) => {
  const cardStyle = customColor ? {
    backgroundColor: `${customColor}0D`, // ~5% opacity
    borderColor: `${customColor}40`,     // ~25% opacity
  } : {};

  // Clone icon to apply custom color if set
  const renderedIcon = useMemo(() => {
    if (!icon) return null;
    if (customColor && React.isValidElement(icon)) {
      // @ts-ignore
      return React.cloneElement(icon, { className: '', color: customColor });
    }
    return icon;
  }, [icon, customColor]);

  return (
    <div 
      onClick={onClick}
      style={cardStyle}
      className={`group relative p-5 rounded-xl border cursor-pointer transition-all duration-200 shadow-sm hover:shadow-md
      ${active ? 'ring-2 ring-slate-800 ring-offset-2 scale-[1.02]' : ''} 
      ${!customColor ? colorClass : ''}`}
    >
      {/* Color Picker Trigger */}
      <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity z-10" onClick={(e) => e.stopPropagation()}>
         <label className="cursor-pointer p-1.5 rounded-full hover:bg-black/5 block bg-white/50 backdrop-blur-sm border border-black/5 shadow-sm">
             <input 
               type="color" 
               className="sr-only" 
               value={customColor || "#000000"} 
               onChange={(e) => onColorChange && onColorChange(e.target.value)} 
             />
             <Palette size={12} className="text-slate-500" />
         </label>
      </div>

      <div className="flex justify-between items-start mb-3">
        <h3 className={`font-bold text-slate-800 leading-tight ${compact ? 'text-sm min-h-[40px]' : 'text-md'}`}>{title}</h3>
        {renderedIcon && <div className="p-2 bg-white/50 rounded-lg shadow-sm">{renderedIcon}</div>}
      </div>

      <div className="space-y-2">
        <div className="flex justify-between items-center text-sm border-b border-black/5 pb-1">
          <span className="text-slate-600">Articles</span>
          <span className="font-bold text-slate-900">{data.articles}</span>
        </div>
        <div className="flex justify-between items-center text-sm border-b border-black/5 pb-1">
          <span className="text-slate-600">Postage</span>
          <span className="font-bold text-slate-900">{formatCurrency(data.postage)}</span>
