import React, { useState, useMemo } from 'react';
import { BookingDataRow, ProductGroup, AnalysisSummary, OfficeSummary, MasterDataRow } from '../types';
import { PRODUCTS } from '../constants';
import { formatCurrency, exportToPDF, exportToExcel } from '../utils';
import { BarChart, IndianRupee, Package, Globe, FileText, Download, Mail, CheckCircle, Printer, Palette } from 'lucide-react';

interface DashboardAnalysisProps {
  data: BookingDataRow[];
  masterData: MasterDataRow[];
}

// Helper for PDF currency to ensure Rs. is used instead of symbol
const formatCurrencyPDF = (amount: number) => {
  return `Rs. ${amount.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
};

const DashboardAnalysis: React.FC<DashboardAnalysisProps> = ({ data, masterData }) => {
  const [selectedContext, setSelectedContext] = useState<string | null>(null);
  const [contextType, setContextType] = useState<'Category' | 'Product' | null>(null);

  // State for custom card colors
  const [cardColors, setCardColors] = useState<Record<string, string>>({});

  const handleColorChange = (key: string, color: string) => {
    setCardColors(prev => ({ ...prev, [key]: color }));
  };

  // Pre-normalize product lists for case-insensitive matching
  const normalizedProducts = useMemo(() => {
    const normalize = (list: string[]) => list.map(p => p.toLowerCase().trim());
    return {
      domestic: normalize(PRODUCTS.DOMESTIC),
      parcel: normalize(PRODUCTS.PARCEL),
      international: normalize(PRODUCTS.INTERNATIONAL),
      all: normalize(PRODUCTS.ALL)
    };
  }, []);

  // --- Aggregation Logic for Top Cards (Verticals) ---
  const revenueStats = useMemo(() => {
    const calculate = (normList: string[] | null) => {
      const filtered = data.filter(r => {
        if (!normList) return true;
        return normList.includes(r.productName.toLowerCase().trim());
      });
      return filtered.reduce((acc, r) => ({
        articles: acc.articles + r.articles,
        postage: acc.postage + r.postage,
        revenue: acc.revenue + r.totalAmount
      }), { articles: 0, postage: 0, revenue: 0 });
    };

    const domestic = calculate(normalizedProducts.domestic);
    const parcel = calculate(normalizedProducts.parcel);
    const international = calculate(normalizedProducts.international);

    // Mathematical Total: Domestic + Parcel + International
    // This ensures consistency across vertical cards.
    return {
      total: {
        articles: domestic.articles + parcel.articles + international.articles,
        postage: domestic.postage + parcel.postage + international.postage,
        revenue: domestic.revenue + parcel.revenue + international.revenue
      },
      domestic,
      parcel,
      international,
    };
  }, [data, normalizedProducts]);

  // --- Aggregation Logic for Product Cards ---
  const productStats = useMemo(() => {
    const stats: Record<string, { articles: number; postage: number; revenue: number }> = {};
    PRODUCTS.ALL.forEach(p => stats[p] = { articles: 0, postage: 0, revenue: 0 });

    data.forEach(row => {
      const rowProductName = row.productName.toLowerCase().trim();
      // Find the "Display Name" from the original PRODUCTS.ALL that matches this row's product name
      const displayName = PRODUCTS.ALL.find(p => p.toLowerCase().trim() === rowProductName);

      if (displayName && stats[displayName]) {
        stats[displayName].articles += row.articles;
        stats[displayName].postage += row.postage;
        stats[displayName].revenue += row.totalAmount;
      }
    });
    return stats;
  }, [data]);

  // --- Logic for Reports (Table Data) ---
  const reportData = useMemo(() => {
    if (!selectedContext) return null;

    let filteredData = [];
    const lowerContext = selectedContext.toLowerCase().trim();

    if (contextType === 'Category') {
       if (selectedContext === ProductGroup.ALL) filteredData = data.filter(d => normalizedProducts.all.includes(d.productName.toLowerCase().trim()));
       else if (selectedContext === ProductGroup.DOMESTIC) filteredData = data.filter(d => normalizedProducts.domestic.includes(d.productName.toLowerCase().trim()));
       else if (selectedContext === ProductGroup.PARCEL) filteredData = data.filter(d => normalizedProducts.parcel.includes(d.productName.toLowerCase().trim()));
       else if (selectedContext === ProductGroup.INTERNATIONAL) filteredData = data.filter(d => normalizedProducts.international.includes(d.productName.toLowerCase().trim()));
    } else {
       // Single Product Match
       filteredData = data.filter(d => d.productName.toLowerCase().trim() === lowerContext);
    }

    // Sub-Division Wise
    const subDivMap = new Map<string, AnalysisSummary>();
    filteredData.forEach(row => {
      const name = row.subDivision || 'Unknown Sub-Division';
      const current = subDivMap.get(name) || { subDivisionName: name, articleCount: 0, postageAmount: 0, totalRevenue: 0 };
      current.articleCount += row.articles;
      current.postageAmount += row.postage;
      current.totalRevenue += row.totalAmount;
      subDivMap.set(name, current);
    });
    const subDivReport = Array.from(subDivMap.values()).sort((a,b) => b.postageAmount - a.postageAmount);

    // PO Wise (Aggregated by Office Jurisdiction)
    const poMap = new Map<string, OfficeSummary>();
    filteredData.forEach(row => {
      const name = row.officeJurisdiction || 'Unknown Jurisdiction';
      const current = poMap.get(name) || { officeName: name, articleCount: 0, postageAmount: 0, totalRevenue: 0 };
      current.articleCount += row.articles;
      current.postageAmount += row.postage;
      current.totalRevenue += row.totalAmount;
      poMap.set(name, current);
    });
    const poReport = Array.from(poMap.values()).sort((a,b) => b.postageAmount - a.postageAmount);

    return { subDivReport, poReport };
  }, [data, selectedContext, contextType, normalizedProducts]);

  // --- Non-Booking Analysis ---
  const nonBookingStats = useMemo(() => {
    const bookedIds = new Set(data.map(r => r.officeId));

    const allBOs = masterData.filter(m => m.officeType === 'B.O');
    const allPOs = masterData.filter(m => m.officeType !== 'B.O'); 

    const bookedBOs = allBOs.filter(m => bookedIds.has(m.officeId));
    const notBookedBOs = allBOs.filter(m => !bookedIds.has(m.officeId));

    const bookedPOs = allPOs.filter(m => bookedIds.has(m.officeId));
    const notBookedPOs = allPOs.filter(m => !bookedIds.has(m.officeId));

    // Sort Lists by Sub Division Name then Office Name
    const sorter = (a: MasterDataRow, b: MasterDataRow) => {
      if (a.subDivisionName === b.subDivisionName) {
        return a.officeName.localeCompare(b.officeName);
      }
      return a.subDivisionName.localeCompare(b.subDivisionName);
    };

    notBookedBOs.sort(sorter);
    notBookedPOs.sort(sorter);

    return {
      bo: { total: allBOs.length, booked: bookedBOs.length, notBooked: notBookedBOs.length, list: notBookedBOs },
      po: { total: allPOs.length, booked: bookedPOs.length, notBooked: notBookedPOs.length, list: notBookedPOs }
    };
  }, [data, masterData]);


  const handleCardClick = (context: string, type: 'Category' | 'Product') => {
    setSelectedContext(context);
    setContextType(type);
    setTimeout(() => {
      document.getElementById('report-section')?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const exportReport = (type: 'pdf' | 'excel', reportType: 'subdiv' | 'po') => {
    if (!reportData) return;
    const isSubDiv = reportType === 'subdiv';
    const rawData = isSubDiv ? reportData.subDivReport : reportData.poReport;
    const fileName = `${selectedContext} - ${isSubDiv ? 'SubDivision' : 'PO'} Report`;

    if (type === 'excel') {
      const exportData = rawData.map(r => {
        if (isSubDiv) {
            const row = r as AnalysisSummary;
            return {
                'Sub Division Name': row.subDivisionName,
                'No of Articles': row.articleCount,
                'Total Postage': row.postageAmount,
                'Total Revenue': row.totalRevenue
            };
        } else {
            const row = r as OfficeSummary;
            return {
                'Office Name': row.officeName,
                'No of Articles': row.articleCount,
                'Total Postage': row.postageAmount,
                'Total Revenue': row.totalRevenue
            };
        }
      });
      exportToExcel(exportData, fileName);
    } else {
      const headers = isSubDiv 
        ? ['Sl No', 'Name of the Sub Division', 'No of Articles Booked', 'Total Postage Amount', 'Total Revenue']
        : ['Sl No', 'Name of the POs', 'No of Articles Booked', 'Total Postage Amount', 'Total Revenue'];

      const rows = rawData.map((row, i) => [
        i + 1,
        isSubDiv ? (row as AnalysisSummary).subDivisionName : (row as OfficeSummary).officeName,
        row.articleCount,
        formatCurrencyPDF(row.postageAmount),
        formatCurrencyPDF(row.totalRevenue)
      ]);

      // Totals
      const totalArts = rawData.reduce((s, c) => s + c.articleCount, 0);
      const totalPostage = rawData.reduce((s, c) => s + c.postageAmount, 0);
      const totalRevenue = rawData.reduce((s, c) => s + c.totalRevenue, 0);
      rows.push(['', 'TOTAL', totalArts, formatCurrencyPDF(totalPostage), formatCurrencyPDF(totalRevenue)]);

      exportToPDF(headers, rows, fileName);
    }
  };

  const exportZeroBooking = (type: 'pdf' | 'excel', category: 'bo' | 'po') => {
    const data = category === 'bo' ? nonBookingStats.bo.list : nonBookingStats.po.list;
    const title = category === 'bo' ? "List of BOs with ZERO booking" : "List of POs with ZERO booking";
    const fileName = `${title.replace(/\s+/g, '_')}`;
    const jurisdictionHeader = category === 'po' ? 'Head Office' : 'Account Office/Jurisdiction';

    if (type === 'excel') {
        const exportData = data.map(o => ({
            'Office ID': o.officeId,
            'Office Name': o.officeName,
            [jurisdictionHeader]: category === 'po' ? o.headOfficeName : o.officeJurisdiction,
            'Sub Division': o.subDivisionName
        }));
        exportToExcel(exportData, fileName);
    } else {
        const headers = ['Office ID', 'Office Name', jurisdictionHeader, 'Sub Division'];
        const rows = data.map((o: any) => [
          o.officeId, 
          o.officeName, 
          category === 'po' ? o.headOfficeName : o.officeJurisdiction,
          o.subDivisionName
        ]);
        exportToPDF(headers, rows, title);
    }
  };

  // --- Colors Helpers (More Elegant Palette) ---
  const getProductColor = (index: number) => {
    const colors = [
      'bg-red-50 border-red-200 hover:border-red-400',
      'bg-amber-50 border-amber-200 hover:border-amber-400',
      'bg-yellow-50 border-yellow-200 hover:border-yellow-400',
      'bg-orange-50 border-orange-200 hover:border-orange-400',
      'bg-stone-50 border-stone-200 hover:border-stone-400',
      'bg-lime-50 border-lime-200 hover:border-lime-400',
      'bg-emerald-50 border-emerald-200 hover:border-emerald-400',
      'bg-teal-50 border-teal-200 hover:border-teal-400',
      'bg-cyan-50 border-cyan-200 hover:border-cyan-400',
      'bg-sky-50 border-sky-200 hover:border-sky-400',
      'bg-indigo-50 border-indigo-200 hover:border-indigo-400',
      'bg-violet-50 border-violet-200 hover:border-violet-400',
      'bg-fuchsia-50 border-fuchsia-200 hover:border-fuchsia-400',
      'bg-pink-50 border-pink-200 hover:border-pink-400',
      'bg-rose-50 border-rose-200 hover:border-rose-400',
    ];
    return colors[index % colors.length];
  };

  return (
