const RSBTCellReport: React.FC<RSBTCellReportProps> = ({ data, masterData }) => {
  // Product Lists for Report
  const speedPostProducts = ['Inland Speed Post', 'Inland Speed Post Document'];
  const parcelProducts = ['India Post Parcel Retail', 'Indiapost parcel Retail', 'Indiapost Parcel Contractual', 'Speed Post Parcel Domestic'];
  const internationalProducts = [
    'International Air Parcel', 
    'International Speed Post Document', 
    'International Speed Post Merchandise', 
    'Registered Foreign Letter', 
    'Registered International Small Packets'
  ];

  const reportData = useMemo(() => {
    const results: any = { Rural: {}, Urban: {}, Total: {} };

    const categories = [
      { id: 'boSpeed', label: 'BO Speed Post', type: 'B.O', products: speedPostProducts },
      { id: 'boParcel', label: 'BO Parcel', type: 'B.O', products: parcelProducts },
      { id: 'poSpeed', label: 'PO Speed Post', type: 'P.O', products: speedPostProducts },
      { id: 'poParcel', label: 'PO Parcel', type: 'P.O', products: parcelProducts },
      { id: 'poIntl', label: 'PO International', type: 'P.O', products: internationalProducts },
    ];

    categories.forEach(cat => {
      results.Rural[cat.id] = 0;
      results.Urban[cat.id] = 0;
      results.Total[cat.id] = 0;

      data.forEach(row => {
        const rowType = row.officeType === 'B.O' ? 'B.O' : 'P.O';
        const isProductMatch = cat.products.some(p => p.toLowerCase().trim() === row.productName.toLowerCase().trim());
        const isTypeMatch = rowType === cat.type;

        if (isProductMatch && isTypeMatch) {
          const area = row.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
          results[area][cat.id] += row.articles;
          results.Total[cat.id] += row.articles;
        }
      });
    });

    return results;
  }, [data]);

  const officeStats = useMemo(() => {
    const stats = {
      ruralBO: { total: 0, bookedSP: 0, bookedPar: 0 },
      urbanBO: { total: 0, bookedSP: 0, bookedPar: 0 },
      ruralPO: { total: 0, bookedSP: 0, bookedPar: 0 },
      urbanPO: { total: 0, bookedSP: 0, bookedPar: 0 },
    };

    // Prepare set of IDs that booked specific categories
    const spBookedIds = new Set(data.filter(r => speedPostProducts.some(p => p.toLowerCase().trim() === r.productName.toLowerCase().trim())).map(r => r.officeId));
    const parBookedIds = new Set(data.filter(r => parcelProducts.some(p => p.toLowerCase().trim() === r.productName.toLowerCase().trim())).map(r => r.officeId));

    masterData.forEach(m => {
      const isUrban = m.areaType?.toLowerCase().includes('urban');
      const isBO = m.officeType === 'B.O';

      if (isBO) {
        if (isUrban) {
