  const handleExportPDF = () => {
    const headers = ['Category', 'BO Speed Post', 'BO Parcel', 'PO Speed Post', 'PO Parcel', 'PO International'];
    const rows = [
      ['Rural', reportData.Rural.boSpeed, reportData.Rural.boParcel, reportData.Rural.poSpeed, reportData.Rural.poParcel, reportData.Rural.poIntl],
      ['Urban', reportData.Urban.boSpeed, reportData.Urban.boParcel, reportData.Urban.poSpeed, reportData.Urban.poParcel, reportData.Urban.poIntl],
      ['Total', reportData.Total.boSpeed, reportData.Total.boParcel, reportData.Total.poSpeed, reportData.Total.poParcel, reportData.Total.poIntl],
    ];
    exportToPDF(headers, rows, 'RSBT Cell Report (Article Counts)');
  };

  return (
    <div className="space-y-6">
      {/* SECTION 1: OFFICE STATISTICS SUMMARY */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h2 className="text-xl font-bold text-slate-800 mb-6 flex items-center gap-2">
          <Landmark className="text-[#CE2029]" /> Office Type & Performance Summary
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <StatCard title="Rural BOs" total={officeStats.ruralBO.total} icon={<Home size={20} className="text-emerald-600" />} color="bg-emerald-50" />
          <StatCard title="Urban BOs" total={officeStats.urbanBO.total} icon={<Landmark size={20} className="text-blue-600" />} color="bg-blue-50" />
          <StatCard title="Rural SOs/POs" total={officeStats.ruralPO.total} icon={<Home size={20} className="text-emerald-600" />} color="bg-emerald-50" />
          <StatCard title="Urban SOs/POs" total={officeStats.urbanPO.total} icon={<Landmark size={20} className="text-blue-600" />} color="bg-blue-50" />
        </div>

        <div className="mt-8 grid grid-cols-1 md:grid-cols-2 gap-8">
          {/* BO Performance Details */}
          <div className="space-y-4">
            <h3 className="font-bold text-slate-700 border-l-4 border-amber-500 pl-3">Branch Office (BO) Statistics</h3>
            <div className="grid grid-cols-2 gap-3">
              <PerfCard label="Speed Post Booked" value={officeStats.ruralBO.bookedSP + officeStats.urbanBO.bookedSP} sub={`Not: ${(officeStats.ruralBO.total + officeStats.urbanBO.total) - (officeStats.ruralBO.bookedSP + officeStats.urbanBO.bookedSP)}`} />
              <PerfCard label="Parcel Booked" value={officeStats.ruralBO.bookedPar + officeStats.urbanBO.bookedPar} sub={`Not: ${(officeStats.ruralBO.total + officeStats.urbanBO.total) - (officeStats.ruralBO.bookedPar + officeStats.urbanBO.bookedPar)}`} />
            </div>
          </div>

          {/* PO/SO Performance Details */}
