            <div className="grid grid-cols-2 gap-3">
              <PerfCard label="Speed Post Booked" value={officeStats.ruralPO.bookedSP + officeStats.urbanPO.bookedSP} sub={`Not: ${(officeStats.ruralPO.total + officeStats.urbanPO.total) - (officeStats.ruralPO.bookedSP + officeStats.urbanPO.bookedSP)}`} />
