import React, { useMemo, useState, useRef } from 'react';
import { BookingDataRow, MasterDataRow } from '../types';
import { FileSpreadsheet, Download, Printer, Home, Landmark, ChevronDown, ChevronRight, CheckCircle2, XCircle, Search } from 'lucide-react';
import { exportToPDF, exportToExcel, getProductCategory } from '../utils';

interface RSBTCellReportProps {
  data: BookingDataRow[];
  masterData: MasterDataRow[];
}

type DetailType = {
  product: 'Speed Post' | 'Parcel';
  officeType: 'B.O' | 'P.O';
  label: string;
} | null;

const RSBTCellReport: React.FC<RSBTCellReportProps> = ({ data, masterData }) => {
  const [detailView, setDetailView] = useState<DetailType>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const detailRef = useRef<HTMLDivElement>(null);

  const reportData = useMemo(() => {
    const results: any = { Rural: {}, Urban: {}, Total: {} };

    const categories = [
      { id: 'boSpeed', label: 'BO Speed Post', type: 'B.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'boParcel', label: 'BO Parcel', type: 'B.O', targetCat: 'Parcel' },
      { id: 'poSpeed', label: 'PO Speed Post', type: 'P.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'poParcel', label: 'PO Parcel', type: 'P.O', targetCat: 'Parcel' },
      { id: 'poIntl', label: 'PO International', type: 'P.O', targetCat: 'International' },
    ];

    categories.forEach(cat => {
      results.Rural[cat.id] = 0;
      results.Urban[cat.id] = 0;
      results.Total[cat.id] = 0;

      data.forEach(row => {
        const rowType = row.officeType === 'B.O' ? 'B.O' : 'P.O';
        const rowCat = getProductCategory(row.productName);

        let isMatch = rowCat === cat.targetCat;
        if (cat.isSpeed && isMatch) {
            isMatch = row.productName.toLowerCase().includes('speed post');
        }

        if (isMatch && rowType === cat.type) {
          const area = row.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
          results[area][cat.id] += row.articles;
          results.Total[cat.id] += row.articles;
        }
      });
    });

    return results;
  }, [data]);

  const officeStats = useMemo(() => {
    const stats = {
      ruralBO: { total: 0, bookedSP: 0, bookedPar: 0 },
      urbanBO: { total: 0, bookedSP: 0, bookedPar: 0 },
      ruralPO: { total: 0, bookedSP: 0, bookedPar: 0 },
      urbanPO: { total: 0, bookedSP: 0, bookedPar: 0 },
    };

    const spBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Domestic' && r.productName.toLowerCase().includes('speed post')).map(r => r.officeId));
    const parBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Parcel').map(r => r.officeId));

    masterData.forEach(m => {
      const isUrban = m.areaType?.toLowerCase().includes('urban');
      const isBO = m.officeType === 'B.O';

      if (isBO) {
        if (isUrban) {
          stats.urbanBO.total++;
          if (spBookedIds.has(m.officeId)) stats.urbanBO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.urbanBO.bookedPar++;
        } else {
          stats.ruralBO.total++;
          if (spBookedIds.has(m.officeId)) stats.ruralBO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.ruralBO.bookedPar++;
        }
      } else {
        if (isUrban) {
          stats.urbanPO.total++;
          if (spBookedIds.has(m.officeId)) stats.urbanPO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.urbanPO.bookedPar++;
        } else {
          stats.ruralPO.total++;
          if (spBookedIds.has(m.officeId)) stats.ruralPO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.ruralPO.bookedPar++;
        }
      }
    });

    return stats;
  }, [data, masterData]);

  // Data for the detailed office list
  const detailedOfficeData = useMemo(() => {
    if (!detailView) return null;

    const { product, officeType } = detailView;
    const bookedIds = new Set(data.filter(r => {
      const cat = getProductCategory(r.productName);
      if (product === 'Speed Post') {
        return cat === 'Domestic' && r.productName.toLowerCase().includes('speed post');
      }
      return cat === 'Parcel';
    }).map(r => r.officeId));

    const relevantOffices = masterData.filter(m => {
      const typeMatch = officeType === 'B.O' ? m.officeType === 'B.O' : m.officeType !== 'B.O';
      return typeMatch;
    });

    // Group by Sub-Division
    const grouped: Record<string, { Rural: { booked: MasterDataRow[], notBooked: MasterDataRow[] }, Urban: { booked: MasterDataRow[], notBooked: MasterDataRow[] } }> = {};

    relevantOffices.forEach(off => {
      const subDiv = off.subDivisionName || 'Unknown Sub-Division';
      if (!grouped[subDiv]) {
        grouped[subDiv] = {
          Rural: { booked: [], notBooked: [] },
          Urban: { booked: [], notBooked: [] }
        };
      }

      const isUrban = off.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
      const isBooked = bookedIds.has(off.officeId);

      if (isBooked) {
        grouped[subDiv][isUrban as 'Rural' | 'Urban'].booked.push(off);
      } else {
        grouped[subDiv][isUrban as 'Rural' | 'Urban'].notBooked.push(off);
      }
    });

    return grouped;
  }, [detailView, data, masterData]);

  const handlePerfClick = (product: 'Speed Post' | 'Parcel', officeType: 'B.O' | 'P.O') => {
    setDetailView({
      product,
      officeType,
      label: `${officeType === 'B.O' ? 'Branch Office' : 'Sub Office/PO'} - ${product} Booking Detail`
    });
    setTimeout(() => {
      detailRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  const handleExportExcel = () => {
    const exportData = [
      { Category: 'Rural', ...reportData.Rural },
      { Category: 'Urban', ...reportData.Urban },
      { Category: 'Total', ...reportData.Total },
    ];
    exportToExcel(exportData, 'RSBT_Cell_Report');
  };

  const handleExportPDF = () => {
    const headers = ['Category', 'BO Speed Post', 'BO Parcel', 'PO Speed Post', 'PO Parcel', 'PO International'];
    const rows = [
      ['Rural', reportData.Rural.boSpeed, reportData.Rural.boParcel, reportData.Rural.poSpeed, reportData.Rural.poParcel, reportData.Rural.poIntl],
      ['Urban', reportData.Urban.boSpeed, reportData.Urban.boParcel, reportData.Urban.poSpeed, reportData.Urban.poParcel, reportData.Urban.poIntl],
      ['Total', reportData.Total.boSpeed, reportData.Total.boParcel, reportData.Total.poSpeed, reportData.Total.poParcel, reportData.Total.poIntl],
    ];
    exportToPDF(headers, rows, 'RSBT Cell Report (Article Counts)');
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h2 className="text-xl font-bold text-slate-800 mb-6 flex items-center gap-2">
          <Landmark className="text-[#CE2029]" /> Office Type & Performance Summary
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <StatCard title="Rural BOs" total={officeStats.ruralBO.total} icon={<Home size={20} className="text-emerald-600" />} color="bg-emerald-50" />
          <StatCard title="Urban BOs" total={officeStats.urbanBO.total} icon={<Landmark size={20} className="text-blue-600" />} color="bg-blue-50" />
          <StatCard title="Rural SOs/POs" total={officeStats.ruralPO.total} icon={<Home size={20} className="text-emerald-600" />} color="bg-emerald-50" />
          <StatCard title="Urban SOs/POs" total={officeStats.urbanPO.total} icon={<Landmark size={20} className="text-blue-600" />} color="bg-blue-50" />
        </div>

        <div className="mt-8 grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="space-y-4">
            <h3 className="font-bold text-slate-700 border-l-4 border-amber-500 pl-3 flex justify-between items-center">
              <span>Branch Office (BO) Statistics</span>
              <span className="text-[10px] font-normal text-slate-400 italic">Click cards for details</span>
            </h3>
            <div className="grid grid-cols-2 gap-3">
              <PerfCard 
                label="Speed Post Booked" 
                value={officeStats.ruralBO.bookedSP + officeStats.urbanBO.bookedSP} 
                sub={`Not: ${(officeStats.ruralBO.total + officeStats.urbanBO.total) - (officeStats.ruralBO.bookedSP + officeStats.urbanBO.bookedSP)}`} 
                onClick={() => handlePerfClick('Speed Post', 'B.O')}
                isActive={detailView?.product === 'Speed Post' && detailView?.officeType === 'B.O'}
              />
              <PerfCard 
                label="Parcel Booked" 
                value={officeStats.ruralBO.bookedPar + officeStats.urbanBO.bookedPar} 
                sub={`Not: ${(officeStats.ruralBO.total + officeStats.urbanBO.total) - (officeStats.ruralBO.bookedPar + officeStats.urbanBO.bookedPar)}`} 
                onClick={() => handlePerfClick('Parcel', 'B.O')}
                isActive={detailView?.product === 'Parcel' && detailView?.officeType === 'B.O'}
              />
            </div>
          </div>

          <div className="space-y-4">
            <h3 className="font-bold text-slate-700 border-l-4 border-blue-500 pl-3 flex justify-between items-center">
              <span>Sub Office / PO Statistics</span>
              <span className="text-[10px] font-normal text-slate-400 italic">Click cards for details</span>
            </h3>
            <div className="grid grid-cols-2 gap-3">
              <PerfCard 
                label="Speed Post Booked" 
                value={officeStats.ruralPO.bookedSP + officeStats.urbanPO.bookedSP} 
                sub={`Not: ${(officeStats.ruralPO.total + officeStats.urbanPO.total) - (officeStats.ruralPO.bookedSP + officeStats.urbanPO.bookedSP)}`} 
                onClick={() => handlePerfClick('Speed Post', 'P.O')}
                isActive={detailView?.product === 'Speed Post' && detailView?.officeType === 'P.O'}
              />
              <PerfCard 
                label="Parcel Booked" 
                value={officeStats.ruralPO.bookedPar + officeStats.urbanPO.bookedPar} 
                sub={`Not: ${(officeStats.ruralPO.total + officeStats.urbanPO.total) - (officeStats.ruralPO.bookedPar + officeStats.urbanPO.bookedPar)}`} 
                onClick={() => handlePerfClick('Parcel', 'P.O')}
                isActive={detailView?.product === 'Parcel' && detailView?.officeType === 'P.O'}
              />
            </div>
          </div>
        </div>
      </div>

      {/* DETAILED OFFICE LIST SECTION */}
      <div ref={detailRef}>
        {detailView && detailedOfficeData && (
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
              <div>
                <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                   <div className="w-8 h-8 rounded-lg bg-red-50 flex items-center justify-center text-[#CE2029]">
                    {detailView.product === 'Speed Post' ? <Search size={18} /> : <Package size={18} />}
                   </div>
                   {detailView.label}
                </h2>
                <p className="text-xs text-slate-500 mt-1">Categorized by Sub-Division and Area Type</p>
              </div>

              <div className="relative w-full md:w-64">
                <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
                <input
                  type="text"
                  placeholder="Search sub-division..."
                  className="pl-10 w-full border border-slate-200 rounded-lg py-2 text-sm focus:ring-2 focus:ring-[#CE2029] focus:outline-none bg-slate-50"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="space-y-8">
              {Object.entries(detailedOfficeData)
                .filter(([subDiv]) => subDiv.toLowerCase().includes(searchTerm.toLowerCase()))
                .sort(([a], [b]) => a.localeCompare(b))
                .map(([subDiv, areas]) => (
                  <div key={subDiv} className="border border-slate-100 rounded-xl overflow-hidden">
                    <div className="bg-slate-50 px-4 py-3 border-b border-slate-100 flex items-center justify-between">
                      <h3 className="font-bold text-slate-700 uppercase tracking-wider text-sm">{subDiv}</h3>
                      <div className="flex gap-4 text-[10px] font-bold">
                        <span className="flex items-center gap-1 text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded border border-emerald-100">
                          <CheckCircle2 size={12}/> Booked: {areas.Rural.booked.length + areas.Urban.booked.length}
                        </span>
                        <span className="flex items-center gap-1 text-red-600 bg-red-50 px-2 py-0.5 rounded border border-red-100">
                          <XCircle size={12}/> Not: {areas.Rural.notBooked.length + areas.Urban.notBooked.length}
                        </span>
                      </div>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-slate-100">
                      {/* Rural Section */}
                      <AreaSection title="Rural" data={areas.Rural} />
                      {/* Urban Section */}
                      <AreaSection title="Urban" data={areas.Urban} />
                    </div>
                  </div>
              ))}

              {Object.entries(detailedOfficeData).filter(([subDiv]) => subDiv.toLowerCase().includes(searchTerm.toLowerCase())).length === 0 && (
                <div className="text-center py-12 bg-slate-50 rounded-xl border border-dashed border-slate-200">
                  <p className="text-slate-400 text-sm">No matching sub-divisions found.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <FileSpreadsheet className="text-[#CE2029]" /> RSBT Cell Report (Article Volume)
          </h2>
          <div className="flex gap-2">
            <button onClick={handleExportExcel} className="flex items-center gap-1 px-4 py-2 bg-green-50 text-green-700 rounded-lg border border-green-200 hover:bg-green-100 transition-all text-sm font-medium shadow-sm">
              <Download size={16} /> Excel
            </button>
            <button onClick={handleExportPDF} className="flex items-center gap-1 px-4 py-2 bg-red-50 text-[#CE2029] rounded-lg border border-red-200 hover:bg-red-100 transition-all text-sm font-medium shadow-sm">
              <Printer size={16} /> PDF
            </button>
          </div>
        </div>

        <div className="overflow-x-auto rounded-lg border border-slate-200">
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-50 text-slate-600 font-semibold uppercase tracking-wider text-xs">
              <tr>
                <th className="px-6 py-4 border-b">Category / Area</th>
                <th className="px-6 py-4 border-b text-center">BO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">BO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">PO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO International</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {['Rural', 'Urban', 'Total'].map((area) => (
                <tr key={area} className={`${area === 'Total' ? 'bg-slate-50 font-bold' : 'hover:bg-slate-50'} transition-colors`}>
                  <td className="px-6 py-4 text-slate-700">{area}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].boSpeed}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].boParcel}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].poSpeed}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].poParcel}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].poIntl}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

const AreaSection = ({ title, data }: { title: string, data: { booked: MasterDataRow[], notBooked: MasterDataRow[] } }) => (
  <div className="p-4">
    <div className="flex items-center gap-2 mb-3">
      <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest">{title}</h4>
      <div className="h-px flex-1 bg-slate-100"></div>
    </div>

    <div className="grid grid-cols-2 gap-4">
      {/* Booked */}
      <div className="space-y-2">
        <p className="text-[10px] font-bold text-emerald-600 uppercase mb-1">Booked ({data.booked.length})</p>
        <div className="max-h-60 overflow-y-auto pr-1 space-y-1 custom-scrollbar">
          {data.booked.map(off => (
            <div key={off.officeId} className="px-2 py-1.5 bg-emerald-50 border border-emerald-100 rounded text-[11px] font-medium text-emerald-800 hover:bg-emerald-100 transition-colors cursor-default flex items-center gap-1.5">
               <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 shrink-0"></div>
               <span className="truncate">{off.officeName}</span>
            </div>
          ))}
          {data.booked.length === 0 && <p className="text-[10px] text-slate-300 italic">None</p>}
        </div>
      </div>

      {/* Not Booked */}
      <div className="space-y-2">
        <p className="text-[10px] font-bold text-red-600 uppercase mb-1">Not Booked ({data.notBooked.length})</p>
        <div className="max-h-60 overflow-y-auto pr-1 space-y-1 custom-scrollbar">
          {data.notBooked.map(off => (
            <div key={off.officeId} className="px-2 py-1.5 bg-red-50 border border-red-100 rounded text-[11px] font-medium text-red-800 hover:bg-red-100 transition-colors cursor-default flex items-center gap-1.5">
               <div className="w-1.5 h-1.5 rounded-full bg-red-400 shrink-0"></div>
               <span className="truncate">{off.officeName}</span>
            </div>
          ))}
          {data.notBooked.length === 0 && <p className="text-[10px] text-slate-300 italic">None</p>}
        </div>
      </div>
    </div>
  </div>
);

const StatCard = ({ title, total, icon, color }: any) => (
  <div className={`p-4 rounded-xl border border-slate-100 shadow-sm ${color} flex items-center justify-between`}>
    <div>
      <p className="text-xs font-bold text-slate-500 uppercase">{title}</p>
      <p className="text-2xl font-black text-slate-800 mt-1">{total}</p>
    </div>
    <div className="bg-white p-2.5 rounded-lg shadow-sm">{icon}</div>
  </div>
);

const PerfCard = ({ label, value, sub, onClick, isActive }: any) => (
  <button 
    onClick={onClick}
    className={`w-full group text-left p-4 rounded-xl border transition-all duration-200 shadow-sm flex flex-col items-center justify-center text-center relative overflow-hidden
    ${isActive ? 'bg-white ring-2 ring-[#CE2029] border-transparent scale-[1.02]' : 'bg-slate-50 border-slate-200 hover:bg-white hover:border-[#CE2029]/30 hover:shadow-md'}`}
  >
    {isActive && <div className="absolute top-0 right-0 p-1"><ChevronDown size={14} className="text-[#CE2029]" /></div>}
    <p className={`text-[10px] font-black uppercase tracking-tighter mb-1 transition-colors ${isActive ? 'text-[#CE2029]' : 'text-slate-500 group-hover:text-slate-700'}`}>{label}</p>
    <div className="flex items-baseline gap-1.5">
      <span className={`text-xl font-black transition-colors ${isActive ? 'text-[#CE2029]' : 'text-slate-700'}`}>{value}</span>
      <span className="text-[10px] text-slate-400 font-bold">{sub}</span>
    </div>
    <div className="w-full h-1 bg-slate-200 rounded-full mt-2 overflow-hidden">
       <div className={`h-full transition-all duration-500 ${isActive ? 'bg-[#CE2029]' : 'bg-slate-400 group-hover:bg-[#CE2029]/60'}`} style={{ width: `${Math.min(100, (value / (value + parseInt(sub.split(': ')[1] || '0'))) * 100)}%` }}></div>
    </div>
  </button>
);

const Package = ({ size, className }: any) => (
  <svg 
    xmlns="http://www.w3.org/2000/svg" 
    width={size} 
    height={size} 
    viewBox="0 0 24 24" 
    fill="none" 
    stroke="currentColor" 
    strokeWidth="2" 
    strokeLinecap="round" 
    strokeLinejoin="round" 
    className={className}
  >
    <path d="M21 8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16Z"/>
    <path d="m3.3 7 8.7 5 8.7-5"/><path d="M12 22V12"/>
  </svg>
);

export default RSBTCellReport;

import React, { useMemo, useState, useRef } from 'react';
import { BookingDataRow, MasterDataRow } from '../types';
import { FileSpreadsheet, Download, Printer, Home, Landmark, ChevronDown, ChevronRight, CheckCircle2, XCircle, Search } from 'lucide-react';
import { exportToPDF, exportToExcel, getProductCategory } from '../utils';

interface RSBTCellReportProps {
  data: BookingDataRow[];
  masterData: MasterDataRow[];
}

type DetailType = {
  product: 'Speed Post' | 'Parcel';
  officeType: 'B.O' | 'P.O';
  label: string;
} | null;

const RSBTCellReport: React.FC<RSBTCellReportProps> = ({ data, masterData }) => {
  const [detailView, setDetailView] = useState<DetailType>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const detailRef = useRef<HTMLDivElement>(null);

  // Fix: Explicitly type useMemo to allow property access on reportData (fixes 'unknown' type errors)
  const reportData = useMemo<any>(() => {
    const results: any = { Rural: {}, Urban: {}, Total: {} };

    const categories = [
      { id: 'boSpeed', label: 'BO Speed Post', type: 'B.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'boParcel', label: 'BO Parcel', type: 'B.O', targetCat: 'Parcel' },
      { id: 'poSpeed', label: 'PO Speed Post', type: 'P.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'poParcel', label: 'PO Parcel', type: 'P.O', targetCat: 'Parcel' },
      { id: 'poIntl', label: 'PO International', type: 'P.O', targetCat: 'International' },
    ];

    categories.forEach(cat => {
      results.Rural[cat.id] = 0;
      results.Urban[cat.id] = 0;
      results.Total[cat.id] = 0;

      data.forEach(row => {
        const rowType = row.officeType === 'B.O' ? 'B.O' : 'P.O';
        const rowCat = getProductCategory(row.productName);

        let isMatch = rowCat === cat.targetCat;
        if (cat.isSpeed && isMatch) {
            isMatch = row.productName.toLowerCase().includes('speed post');
        }

        if (isMatch && rowType === cat.type) {
          const area = row.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
          results[area][cat.id] += row.articles;
          results.Total[cat.id] += row.articles;
        }
      });
    });

    return results;
  }, [data]);

  const officeStats = useMemo(() => {
    const stats = {
      ruralBO: { total: 0, bookedSP: 0, bookedPar: 0 },
      urbanBO: { total: 0, bookedSP: 0, bookedPar: 0 },
      ruralPO: { total: 0, bookedSP: 0, bookedPar: 0 },
      urbanPO: { total: 0, bookedSP: 0, bookedPar: 0 },
    };

    const spBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Domestic' && r.productName.toLowerCase().includes('speed post')).map(r => r.officeId));
    const parBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Parcel').map(r => r.officeId));

    masterData.forEach(m => {
      const isUrban = m.areaType?.toLowerCase().includes('urban');
      const isBO = m.officeType === 'B.O';

      if (isBO) {
        if (isUrban) {
          stats.urbanBO.total++;
          if (spBookedIds.has(m.officeId)) stats.urbanBO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.urbanBO.bookedPar++;
        } else {
          stats.ruralBO.total++;
          if (spBookedIds.has(m.officeId)) stats.ruralBO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.ruralBO.bookedPar++;
        }
      } else {
        if (isUrban) {
          stats.urbanPO.total++;
          if (spBookedIds.has(m.officeId)) stats.urbanPO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.urbanPO.bookedPar++;
        } else {
          stats.ruralPO.total++;
          if (spBookedIds.has(m.officeId)) stats.ruralPO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.ruralPO.bookedPar++;
        }
      }
    });

    return stats;
  }, [data, masterData]);

  // Data for the detailed office list
  const detailedOfficeData = useMemo(() => {
    if (!detailView) return null;

    const { product, officeType } = detailView;
    const bookedIds = new Set(data.filter(r => {
      const cat = getProductCategory(r.productName);
      if (product === 'Speed Post') {
        return cat === 'Domestic' && r.productName.toLowerCase().includes('speed post');
      }
      return cat === 'Parcel';
    }).map(r => r.officeId));

    const relevantOffices = masterData.filter(m => {
      const typeMatch = officeType === 'B.O' ? m.officeType === 'B.O' : m.officeType !== 'B.O';
      return typeMatch;
    });

    // Group by Sub-Division
    const grouped: Record<string, { Rural: { booked: MasterDataRow[], notBooked: MasterDataRow[] }, Urban: { booked: MasterDataRow[], notBooked: MasterDataRow[] } }> = {};

    relevantOffices.forEach(off => {
      const subDiv = off.subDivisionName || 'Unknown Sub-Division';
      if (!grouped[subDiv]) {
        grouped[subDiv] = {
          Rural: { booked: [], notBooked: [] },
          Urban: { booked: [], notBooked: [] }
        };
      }

      const isUrban = off.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
      const isBooked = bookedIds.has(off.officeId);

      if (isBooked) {
        grouped[subDiv][isUrban as 'Rural' | 'Urban'].booked.push(off);
      } else {
        grouped[subDiv][isUrban as 'Rural' | 'Urban'].notBooked.push(off);
      }
    });

    return grouped;
  }, [detailView, data, masterData]);

  const handlePerfClick = (product: 'Speed Post' | 'Parcel', officeType: 'B.O' | 'P.O') => {
    setDetailView({
      product,
      officeType,
      label: `${officeType === 'B.O' ? 'Branch Office' : 'Sub Office/PO'} - ${product} Booking Detail`
    });
    setTimeout(() => {
      detailRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  const handleExportExcel = () => {
    const exportData = [
      { Category: 'Rural', ...reportData.Rural },
      { Category: 'Urban', ...reportData.Urban },
      { Category: 'Total', ...reportData.Total },
    ];
    exportToExcel(exportData, 'RSBT_Cell_Report');
  };

  const handleExportPDF = () => {
    const headers = ['Category', 'BO Speed Post', 'BO Parcel', 'PO Speed Post', 'PO Parcel', 'PO International'];
    const rows = [
      ['Rural', reportData.Rural.boSpeed, reportData.Rural.boParcel, reportData.Rural.poSpeed, reportData.Rural.poParcel, reportData.Rural.poIntl],
      ['Urban', reportData.Urban.boSpeed, reportData.Urban.boParcel, reportData.Urban.poSpeed, reportData.Urban.poParcel, reportData.Urban.poIntl],
      ['Total', reportData.Total.boSpeed, reportData.Total.boParcel, reportData.Total.poSpeed, reportData.Total.poParcel, reportData.Total.poIntl],
    ];
    exportToPDF(headers, rows, 'RSBT Cell Report (Article Counts)');
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h2 className="text-xl font-bold text-slate-800 mb-6 flex items-center gap-2">
          <Landmark className="text-[#CE2029]" /> Office Type & Performance Summary
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <StatCard title="Rural BOs" total={officeStats.ruralBO.total} icon={<Home size={20} className="text-emerald-600" />} color="bg-emerald-50" />
          <StatCard title="Urban BOs" total={officeStats.urbanBO.total} icon={<Landmark size={20} className="text-blue-600" />} color="bg-blue-50" />
          <StatCard title="Rural SOs/POs" total={officeStats.ruralPO.total} icon={<Home size={20} className="text-emerald-600" />} color="bg-emerald-50" />
          <StatCard title="Urban SOs/POs" total={officeStats.urbanPO.total} icon={<Landmark size={20} className="text-blue-600" />} color="bg-blue-50" />
        </div>

        <div className="mt-8 grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="space-y-4">
            <h3 className="font-bold text-slate-700 border-l-4 border-amber-500 pl-3 flex justify-between items-center">
              <span>Branch Office (BO) Statistics</span>
              <span className="text-[10px] font-normal text-slate-400 italic">Click cards for details</span>
            </h3>
            <div className="grid grid-cols-2 gap-3">
              <PerfCard 
                label="Speed Post Booked" 
                value={officeStats.ruralBO.bookedSP + officeStats.urbanBO.bookedSP} 
                sub={`Not: ${(officeStats.ruralBO.total + officeStats.urbanBO.total) - (officeStats.ruralBO.bookedSP + officeStats.urbanBO.bookedSP)}`} 
                onClick={() => handlePerfClick('Speed Post', 'B.O')}
                isActive={detailView?.product === 'Speed Post' && detailView?.officeType === 'B.O'}
              />
              <PerfCard 
                label="Parcel Booked" 
                value={officeStats.ruralBO.bookedPar + officeStats.urbanBO.bookedPar} 
                sub={`Not: ${(officeStats.ruralBO.total + officeStats.urbanBO.total) - (officeStats.ruralBO.bookedPar + officeStats.urbanBO.bookedPar)}`} 
                onClick={() => handlePerfClick('Parcel', 'B.O')}
                isActive={detailView?.product === 'Parcel' && detailView?.officeType === 'B.O'}
              />
            </div>
          </div>

          <div className="space-y-4">
            <h3 className="font-bold text-slate-700 border-l-4 border-blue-500 pl-3 flex justify-between items-center">
              <span>Sub Office / PO Statistics</span>
              <span className="text-[10px] font-normal text-slate-400 italic">Click cards for details</span>
            </h3>
            <div className="grid grid-cols-2 gap-3">
              <PerfCard 
                label="Speed Post Booked" 
                value={officeStats.ruralPO.bookedSP + officeStats.urbanPO.bookedSP} 
                sub={`Not: ${(officeStats.ruralPO.total + officeStats.urbanPO.total) - (officeStats.ruralPO.bookedSP + officeStats.urbanPO.bookedSP)}`} 
                onClick={() => handlePerfClick('Speed Post', 'P.O')}
                isActive={detailView?.product === 'Speed Post' && detailView?.officeType === 'P.O'}
              />
              <PerfCard 
                label="Parcel Booked" 
                value={officeStats.ruralPO.bookedPar + officeStats.urbanPO.bookedPar} 
                sub={`Not: ${(officeStats.ruralPO.total + officeStats.urbanPO.total) - (officeStats.ruralPO.bookedPar + officeStats.urbanPO.bookedPar)}`} 
                onClick={() => handlePerfClick('Parcel', 'P.O')}
                isActive={detailView?.product === 'Parcel' && detailView?.officeType === 'P.O'}
              />
            </div>
          </div>
        </div>
      </div>

      {/* DETAILED OFFICE LIST SECTION */}
      <div ref={detailRef}>
        {detailView && detailedOfficeData && (
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
              <div>
                <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                   <div className="w-8 h-8 rounded-lg bg-red-50 flex items-center justify-center text-[#CE2029]">
                    {detailView.product === 'Speed Post' ? <Search size={18} /> : <Package size={18} />}
                   </div>
                   {detailView.label}
                </h2>
                <p className="text-xs text-slate-500 mt-1">Categorized by Sub-Division and Area Type</p>
              </div>

              <div className="relative w-full md:w-64">
                <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
                <input
                  type="text"
                  placeholder="Search sub-division..."
                  className="pl-10 w-full border border-slate-200 rounded-lg py-2 text-sm focus:ring-2 focus:ring-[#CE2029] focus:outline-none bg-slate-50"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="space-y-8">
              {Object.entries(detailedOfficeData)
                .filter(([subDiv]) => subDiv.toLowerCase().includes(searchTerm.toLowerCase()))
                .sort(([a], [b]) => a.localeCompare(b))
                .map(([subDiv, areas]) => (
                  <div key={subDiv} className="border border-slate-100 rounded-xl overflow-hidden">
                    <div className="bg-slate-50 px-4 py-3 border-b border-slate-100 flex items-center justify-between">
                      <h3 className="font-bold text-slate-700 uppercase tracking-wider text-sm">{subDiv}</h3>
                      <div className="flex gap-4 text-[10px] font-bold">
                        <span className="flex items-center gap-1 text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded border border-emerald-100">
                          <CheckCircle2 size={12}/> Booked: {areas.Rural.booked.length + areas.Urban.booked.length}
                        </span>
                        <span className="flex items-center gap-1 text-red-600 bg-red-50 px-2 py-0.5 rounded border border-red-100">
                          <XCircle size={12}/> Not: {areas.Rural.notBooked.length + areas.Urban.notBooked.length}
                        </span>
                      </div>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-slate-100">
                      {/* Rural Section */}
                      <AreaSection title="Rural" data={areas.Rural} />
                      {/* Urban Section */}
                      <AreaSection title="Urban" data={areas.Urban} />
                    </div>
                  </div>
              ))}

              {Object.entries(detailedOfficeData).filter(([subDiv]) => subDiv.toLowerCase().includes(searchTerm.toLowerCase())).length === 0 && (
                <div className="text-center py-12 bg-slate-50 rounded-xl border border-dashed border-slate-200">
                  <p className="text-slate-400 text-sm">No matching sub-divisions found.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <FileSpreadsheet className="text-[#CE2029]" /> RSBT Cell Report (Article Volume)
          </h2>
          <div className="flex gap-2">
            <button onClick={handleExportExcel} className="flex items-center gap-1 px-4 py-2 bg-green-50 text-green-700 rounded-lg border border-green-200 hover:bg-green-100 transition-all text-sm font-medium shadow-sm">
              <Download size={16} /> Excel
            </button>
            <button onClick={handleExportPDF} className="flex items-center gap-1 px-4 py-2 bg-red-50 text-[#CE2029] rounded-lg border border-red-200 hover:bg-red-100 transition-all text-sm font-medium shadow-sm">
              <Printer size={16} /> PDF
            </button>
          </div>
        </div>

        <div className="overflow-x-auto rounded-lg border border-slate-200">
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-50 text-slate-600 font-semibold uppercase tracking-wider text-xs">
              <tr>
                <th className="px-6 py-4 border-b">Category / Area</th>
                <th className="px-6 py-4 border-b text-center">BO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">BO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">PO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO International</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {['Rural', 'Urban', 'Total'].map((area) => (
                <tr key={area} className={`${area === 'Total' ? 'bg-slate-50 font-bold' : 'hover:bg-slate-50'} transition-colors`}>
                  <td className="px-6 py-4 text-slate-700">{area}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].boSpeed}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].boParcel}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].poSpeed}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].poParcel}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].poIntl}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

const AreaSection = ({ title, data }: { title: string, data: { booked: MasterDataRow[], notBooked: MasterDataRow[] } }) => (
  <div className="p-4">
    <div className="flex items-center gap-2 mb-3">
      <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest">{title}</h4>
      <div className="h-px flex-1 bg-slate-100"></div>
    </div>

    <div className="grid grid-cols-2 gap-4">
      {/* Booked */}
      <div className="space-y-2">
        <p className="text-[10px] font-bold text-emerald-600 uppercase mb-1">Booked ({data.booked.length})</p>
        <div className="max-h-60 overflow-y-auto pr-1 space-y-1 custom-scrollbar">
          {data.booked.map(off => (
            <div key={off.officeId} className="px-2 py-1.5 bg-emerald-50 border border-emerald-100 rounded text-[11px] font-medium text-emerald-800 hover:bg-emerald-100 transition-colors cursor-default flex items-center gap-1.5">
               <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 shrink-0"></div>
               <span className="truncate">{off.officeName}</span>
            </div>
          ))}
          {data.booked.length === 0 && <p className="text-[10px] text-slate-300 italic">None</p>}
        </div>
      </div>

      {/* Not Booked */}
      <div className="space-y-2">
        <p className="text-[10px] font-bold text-red-600 uppercase mb-1">Not Booked ({data.notBooked.length})</p>
        <div className="max-h-60 overflow-y-auto pr-1 space-y-1 custom-scrollbar">
          {data.notBooked.map(off => (
            <div key={off.officeId} className="px-2 py-1.5 bg-red-50 border border-red-100 rounded text-[11px] font-medium text-red-800 hover:bg-red-100 transition-colors cursor-default flex items-center gap-1.5">
               <div className="w-1.5 h-1.5 rounded-full bg-red-400 shrink-0"></div>
               <span className="truncate">{off.officeName}</span>
            </div>
          ))}
          {data.notBooked.length === 0 && <p className="text-[10px] text-slate-300 italic">None</p>}
        </div>
      </div>
    </div>
  </div>
);

const StatCard = ({ title, total, icon, color }: any) => (
  <div className={`p-4 rounded-xl border border-slate-100 shadow-sm ${color} flex items-center justify-between`}>
    <div>
      <p className="text-xs font-bold text-slate-500 uppercase">{title}</p>
      <p className="text-2xl font-black text-slate-800 mt-1">{total}</p>
    </div>
    <div className="bg-white p-2.5 rounded-lg shadow-sm">{icon}</div>
  </div>
);

const PerfCard = ({ label, value, sub, onClick, isActive }: any) => (
  <button 
    onClick={onClick}
    className={`w-full group text-left p-4 rounded-xl border transition-all duration-200 shadow-sm flex flex-col items-center justify-center text-center relative overflow-hidden
    ${isActive ? 'bg-white ring-2 ring-[#CE2029] border-transparent scale-[1.02]' : 'bg-slate-50 border-slate-200 hover:bg-white hover:border-[#CE2029]/30 hover:shadow-md'}`}
  >
    {isActive && <div className="absolute top-0 right-0 p-1"><ChevronDown size={14} className="text-[#CE2029]" /></div>}
    <p className={`text-[10px] font-black uppercase tracking-tighter mb-1 transition-colors ${isActive ? 'text-[#CE2029]' : 'text-slate-500 group-hover:text-slate-700'}`}>{label}</p>
    <div className="flex items-baseline gap-1.5">
      <span className={`text-xl font-black transition-colors ${isActive ? 'text-[#CE2029]' : 'text-slate-700'}`}>{value}</span>
      <span className="text-[10px] text-slate-400 font-bold">{sub}</span>
    </div>
    <div className="w-full h-1 bg-slate-200 rounded-full mt-2 overflow-hidden">
       <div className={`h-full transition-all duration-500 ${isActive ? 'bg-[#CE2029]' : 'bg-slate-400 group-hover:bg-[#CE2029]/60'}`} style={{ width: `${Math.min(100, (value / (value + parseInt(sub.split(': ')[1] || '0'))) * 100)}%` }}></div>
    </div>
  </button>
);

const Package = ({ size, className }: any) => (
  <svg 
    xmlns="http://www.w3.org/2000/svg" 
    width={size} 
    height={size} 
    viewBox="0 0 24 24" 
    fill="none" 
    stroke="currentColor" 
    strokeWidth="2" 
    strokeLinecap="round" 
    strokeLinejoin="round" 
    className={className}
  >
    <path d="M21 8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16Z"/>
    <path d="m3.3 7 8.7 5 8.7-5"/><path d="M12 22V12"/>
  </svg>
);

export default RSBTCellReport;

import React, { useMemo, useState, useRef } from 'react';
import { BookingDataRow, MasterDataRow } from '../types';
import { FileSpreadsheet, Download, Printer, Home, Landmark, ChevronDown, ChevronRight, CheckCircle2, XCircle, Search, FileText } from 'lucide-react';
import { exportToPDF, exportToExcel, getProductCategory } from '../utils';

interface RSBTCellReportProps {
  data: BookingDataRow[];
  masterData: MasterDataRow[];
}

type DetailType = {
  product: 'Speed Post' | 'Parcel';
  officeType: 'B.O' | 'P.O';
  label: string;
} | null;

const RSBTCellReport: React.FC<RSBTCellReportProps> = ({ data, masterData }) => {
  const [detailView, setDetailView] = useState<DetailType>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const detailRef = useRef<HTMLDivElement>(null);

  const reportData = useMemo<any>(() => {
    const results: any = { Rural: {}, Urban: {}, Total: {} };

    const categories = [
      { id: 'boSpeed', label: 'BO Speed Post', type: 'B.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'boParcel', label: 'BO Parcel', type: 'B.O', targetCat: 'Parcel' },
      { id: 'poSpeed', label: 'PO Speed Post', type: 'P.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'poParcel', label: 'PO Parcel', type: 'P.O', targetCat: 'Parcel' },
      { id: 'poIntl', label: 'PO International', type: 'P.O', targetCat: 'International' },
    ];

    categories.forEach(cat => {
      results.Rural[cat.id] = 0;
      results.Urban[cat.id] = 0;
      results.Total[cat.id] = 0;

      data.forEach(row => {
        const rowType = row.officeType === 'B.O' ? 'B.O' : 'P.O';
        const rowCat = getProductCategory(row.productName);

        let isMatch = rowCat === cat.targetCat;
        if (cat.isSpeed && isMatch) {
            isMatch = row.productName.toLowerCase().includes('speed post');
        }

        if (isMatch && rowType === cat.type) {
          const area = row.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
          results[area][cat.id] += row.articles;
          results.Total[cat.id] += row.articles;
        }
      });
    });

    return results;
  }, [data]);

  const officeStats = useMemo(() => {
    const stats = {
      ruralBO: { total: 0, bookedSP: 0, bookedPar: 0 },
      urbanBO: { total: 0, bookedSP: 0, bookedPar: 0 },
      ruralPO: { total: 0, bookedSP: 0, bookedPar: 0 },
      urbanPO: { total: 0, bookedSP: 0, bookedPar: 0 },
    };

    const spBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Domestic' && r.productName.toLowerCase().includes('speed post')).map(r => r.officeId));
    const parBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Parcel').map(r => r.officeId));

    masterData.forEach(m => {
      const isUrban = m.areaType?.toLowerCase().includes('urban');
      const isBO = m.officeType === 'B.O';

      if (isBO) {
        if (isUrban) {
          stats.urbanBO.total++;
          if (spBookedIds.has(m.officeId)) stats.urbanBO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.urbanBO.bookedPar++;
        } else {
          stats.ruralBO.total++;
          if (spBookedIds.has(m.officeId)) stats.ruralBO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.ruralBO.bookedPar++;
        }
      } else {
        if (isUrban) {
          stats.urbanPO.total++;
          if (spBookedIds.has(m.officeId)) stats.urbanPO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.urbanPO.bookedPar++;
        } else {
          stats.ruralPO.total++;
          if (spBookedIds.has(m.officeId)) stats.ruralPO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.ruralPO.bookedPar++;
        }
      }
    });

    return stats;
  }, [data, masterData]);

  const detailedOfficeData = useMemo(() => {
    if (!detailView) return null;

    const { product, officeType } = detailView;
    const bookedIds = new Set(data.filter(r => {
      const cat = getProductCategory(r.productName);
      if (product === 'Speed Post') {
        return cat === 'Domestic' && r.productName.toLowerCase().includes('speed post');
      }
      return cat === 'Parcel';
    }).map(r => r.officeId));

    const relevantOffices = masterData.filter(m => {
      const typeMatch = officeType === 'B.O' ? m.officeType === 'B.O' : m.officeType !== 'B.O';
      return typeMatch;
    });

    const grouped: Record<string, { Rural: { booked: MasterDataRow[], notBooked: MasterDataRow[] }, Urban: { booked: MasterDataRow[], notBooked: MasterDataRow[] } }> = {};

    relevantOffices.forEach(off => {
      const subDiv = off.subDivisionName || 'Unknown Sub-Division';
      if (!grouped[subDiv]) {
        grouped[subDiv] = {
          Rural: { booked: [], notBooked: [] },
          Urban: { booked: [], notBooked: [] }
        };
      }

      const isUrban = off.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
      const isBooked = bookedIds.has(off.officeId);

      if (isBooked) {
        grouped[subDiv][isUrban as 'Rural' | 'Urban'].booked.push(off);
      } else {
        grouped[subDiv][isUrban as 'Rural' | 'Urban'].notBooked.push(off);
      }
    });

    return grouped;
  }, [detailView, data, masterData]);

  const handlePerfClick = (product: 'Speed Post' | 'Parcel', officeType: 'B.O' | 'P.O') => {
    setDetailView({
      product,
      officeType,
      label: `${officeType === 'B.O' ? 'Branch Office' : 'Sub Office/PO'} - ${product} Booking Detail`
    });
    setTimeout(() => {
      detailRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  const handleExportExcel = () => {
    const exportData = [
      { Category: 'Rural', ...reportData.Rural },
      { Category: 'Urban', ...reportData.Urban },
      { Category: 'Total', ...reportData.Total },
    ];
    exportToExcel(exportData, 'RSBT_Cell_Report');
  };

  const handleExportPDF = () => {
    const headers = ['Category', 'BO Speed Post', 'BO Parcel', 'PO Speed Post', 'PO Parcel', 'PO International'];
    const rows = [
      ['Rural', reportData.Rural.boSpeed, reportData.Rural.boParcel, reportData.Rural.poSpeed, reportData.Rural.poParcel, reportData.Rural.poIntl],
      ['Urban', reportData.Urban.boSpeed, reportData.Urban.boParcel, reportData.Urban.poSpeed, reportData.Urban.poParcel, reportData.Urban.poIntl],
      ['Total', reportData.Total.boSpeed, reportData.Total.boParcel, reportData.Total.poSpeed, reportData.Total.poParcel, reportData.Total.poIntl],
    ];
    exportToPDF(headers, rows, 'RSBT Cell Report (Article Counts)');
  };

  const handleExportDetailedList = (format: 'pdf' | 'excel') => {
    if (!detailedOfficeData || !detailView) return;

    const flatData: any[] = [];
    Object.entries(detailedOfficeData).forEach(([subDiv, areas]) => {
      ['Rural', 'Urban'].forEach(areaType => {
        const area = areas[areaType as 'Rural' | 'Urban'];
        area.booked.forEach(off => {
          flatData.push({
            'Sub-Division': subDiv,
            'Area Type': areaType,
            'Office Name': off.officeName,
            'Office ID': off.officeId,
            'Status': 'Booked'
          });
        });
        area.notBooked.forEach(off => {
          flatData.push({
            'Sub-Division': subDiv,
            'Area Type': areaType,
            'Office Name': off.officeName,
            'Office ID': off.officeId,
            'Status': 'Not Booked'
          });
        });
      });
    });

    const fileName = `Detailed_${detailView.officeType}_${detailView.product.replace(/\s+/g, '_')}_Report`;

    if (format === 'excel') {
      exportToExcel(flatData, fileName);
    } else {
      const headers = ['Sub-Division', 'Area Type', 'Office Name', 'Office ID', 'Status'];
      const rows = flatData.map(d => [d['Sub-Division'], d['Area Type'], d['Office Name'], d['Office ID'], d['Status']]);
      exportToPDF(headers, rows, `${detailView.label} - Summary List`);
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h2 className="text-xl font-bold text-slate-800 mb-6 flex items-center gap-2">
          <Landmark className="text-[#CE2029]" /> Office Type & Performance Summary
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <StatCard title="Rural BOs" total={officeStats.ruralBO.total} icon={<Home size={20} className="text-emerald-600" />} color="bg-emerald-50" />
          <StatCard title="Urban BOs" total={officeStats.urbanBO.total} icon={<Landmark size={20} className="text-blue-600" />} color="bg-blue-50" />
          <StatCard title="Rural SOs/POs" total={officeStats.ruralPO.total} icon={<Home size={20} className="text-emerald-600" />} color="bg-emerald-50" />
          <StatCard title="Urban SOs/POs" total={officeStats.urbanPO.total} icon={<Landmark size={20} className="text-blue-600" />} color="bg-blue-50" />
        </div>

        <div className="mt-8 grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="space-y-4">
            <h3 className="font-bold text-slate-700 border-l-4 border-amber-500 pl-3 flex justify-between items-center">
              <span>Branch Office (BO) Statistics</span>
              <span className="text-[10px] font-normal text-slate-400 italic">Click cards for details</span>
            </h3>
            <div className="grid grid-cols-2 gap-3">
              <PerfCard 
                label="Speed Post Booked" 
                value={officeStats.ruralBO.bookedSP + officeStats.urbanBO.bookedSP} 
                sub={`Not: ${(officeStats.ruralBO.total + officeStats.urbanBO.total) - (officeStats.ruralBO.bookedSP + officeStats.urbanBO.bookedSP)}`} 
                onClick={() => handlePerfClick('Speed Post', 'B.O')}
                isActive={detailView?.product === 'Speed Post' && detailView?.officeType === 'B.O'}
              />
              <PerfCard 
                label="Parcel Booked" 
                value={officeStats.ruralBO.bookedPar + officeStats.urbanBO.bookedPar} 
                sub={`Not: ${(officeStats.ruralBO.total + officeStats.urbanBO.total) - (officeStats.ruralBO.bookedPar + officeStats.urbanBO.bookedPar)}`} 
                onClick={() => handlePerfClick('Parcel', 'B.O')}
                isActive={detailView?.product === 'Parcel' && detailView?.officeType === 'B.O'}
              />
            </div>
          </div>

          <div className="space-y-4">
            <h3 className="font-bold text-slate-700 border-l-4 border-blue-500 pl-3 flex justify-between items-center">
              <span>Sub Office / PO Statistics</span>
              <span className="text-[10px] font-normal text-slate-400 italic">Click cards for details</span>
            </h3>
            <div className="grid grid-cols-2 gap-3">
              <PerfCard 
                label="Speed Post Booked" 
                value={officeStats.ruralPO.bookedSP + officeStats.urbanPO.bookedSP} 
                sub={`Not: ${(officeStats.ruralPO.total + officeStats.urbanPO.total) - (officeStats.ruralPO.bookedSP + officeStats.urbanPO.bookedSP)}`} 
                onClick={() => handlePerfClick('Speed Post', 'P.O')}
                isActive={detailView?.product === 'Speed Post' && detailView?.officeType === 'P.O'}
              />
              <PerfCard 
                label="Parcel Booked" 
                value={officeStats.ruralPO.bookedPar + officeStats.urbanPO.bookedPar} 
                sub={`Not: ${(officeStats.ruralPO.total + officeStats.urbanPO.total) - (officeStats.ruralPO.bookedPar + officeStats.urbanPO.bookedPar)}`} 
                onClick={() => handlePerfClick('Parcel', 'P.O')}
                isActive={detailView?.product === 'Parcel' && detailView?.officeType === 'P.O'}
              />
            </div>
          </div>
        </div>
      </div>

      <div ref={detailRef}>
        {detailView && detailedOfficeData && (
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
              <div className="flex-1">
                <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                   <div className="w-8 h-8 rounded-lg bg-red-50 flex items-center justify-center text-[#CE2029]">
                    {detailView.product === 'Speed Post' ? <Search size={18} /> : <Package size={18} />}
                   </div>
                   {detailView.label}
                </h2>
                <div className="flex items-center gap-4 mt-1">
                   <p className="text-xs text-slate-500">Categorized by Sub-Division and Area Type</p>
                   <div className="flex gap-2">
                      <button onClick={() => handleExportDetailedList('excel')} className="flex items-center gap-1 px-2 py-0.5 bg-green-50 text-green-700 text-[10px] font-bold rounded border border-green-200 hover:bg-green-100 transition-colors">
                        <Download size={10}/> EXCEL
                      </button>
                      <button onClick={() => handleExportDetailedList('pdf')} className="flex items-center gap-1 px-2 py-0.5 bg-red-50 text-[#CE2029] text-[10px] font-bold rounded border border-red-200 hover:bg-red-100 transition-colors">
                        <FileText size={10}/> PDF
                      </button>
                   </div>
                </div>
              </div>

              <div className="relative w-full md:w-64">
                <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
                <input
                  type="text"
                  placeholder="Search sub-division..."
                  className="pl-10 w-full border border-slate-200 rounded-lg py-2 text-sm focus:ring-2 focus:ring-[#CE2029] focus:outline-none bg-slate-50"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="space-y-8">
              {Object.entries(detailedOfficeData)
                .filter(([subDiv]) => subDiv.toLowerCase().includes(searchTerm.toLowerCase()))
                .sort(([a], [b]) => a.localeCompare(b))
                .map(([subDiv, areas]) => (
                  <div key={subDiv} className="border border-slate-100 rounded-xl overflow-hidden">
                    <div className="bg-slate-50 px-4 py-3 border-b border-slate-100 flex items-center justify-between">
                      <h3 className="font-bold text-slate-700 uppercase tracking-wider text-sm">{subDiv}</h3>
                      <div className="flex gap-4 text-[10px] font-bold">
                        <span className="flex items-center gap-1 text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded border border-emerald-100">
                          <CheckCircle2 size={12}/> Booked: {areas.Rural.booked.length + areas.Urban.booked.length}
                        </span>
                        <span className="flex items-center gap-1 text-red-600 bg-red-50 px-2 py-0.5 rounded border border-red-100">
                          <XCircle size={12}/> Not: {areas.Rural.notBooked.length + areas.Urban.notBooked.length}
                        </span>
                      </div>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-slate-100">
                      <AreaSection title="Rural" data={areas.Rural} />
                      <AreaSection title="Urban" data={areas.Urban} />
                    </div>
                  </div>
              ))}

              {Object.entries(detailedOfficeData).filter(([subDiv]) => subDiv.toLowerCase().includes(searchTerm.toLowerCase())).length === 0 && (
                <div className="text-center py-12 bg-slate-50 rounded-xl border border-dashed border-slate-200">
                  <p className="text-slate-400 text-sm">No matching sub-divisions found.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <FileSpreadsheet className="text-[#CE2029]" /> RSBT Cell Report (Article Volume)
          </h2>
          <div className="flex gap-2">
            <button onClick={handleExportExcel} className="flex items-center gap-1 px-4 py-2 bg-green-50 text-green-700 rounded-lg border border-green-200 hover:bg-green-100 transition-all text-sm font-medium shadow-sm">
              <Download size={16} /> Excel
            </button>
            <button onClick={handleExportPDF} className="flex items-center gap-1 px-4 py-2 bg-red-50 text-[#CE2029] rounded-lg border border-red-200 hover:bg-red-100 transition-all text-sm font-medium shadow-sm">
              <Printer size={16} /> PDF
            </button>
          </div>
        </div>

        <div className="overflow-x-auto rounded-lg border border-slate-200">
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-50 text-slate-600 font-semibold uppercase tracking-wider text-xs">
              <tr>
                <th className="px-6 py-4 border-b">Category / Area</th>
                <th className="px-6 py-4 border-b text-center">BO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">BO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">PO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO International</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {['Rural', 'Urban', 'Total'].map((area) => (
                <tr key={area} className={`${area === 'Total' ? 'bg-slate-50 font-bold' : 'hover:bg-slate-50'} transition-colors`}>
                  <td className="px-6 py-4 text-slate-700">{area}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].boSpeed}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].boParcel}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].poSpeed}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].poParcel}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].poIntl}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

const AreaSection = ({ title, data }: { title: string, data: { booked: MasterDataRow[], notBooked: MasterDataRow[] } }) => (
  <div className="p-4">
    <div className="flex items-center gap-2 mb-3">
      <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest">{title}</h4>
      <div className="h-px flex-1 bg-slate-100"></div>
    </div>

    <div className="grid grid-cols-2 gap-4">
      <div className="space-y-2">
        <p className="text-[10px] font-bold text-emerald-600 uppercase mb-1">Booked ({data.booked.length})</p>
        <div className="max-h-60 overflow-y-auto pr-1 space-y-1 custom-scrollbar">
          {data.booked.map(off => (
            <div key={off.officeId} className="px-2 py-1.5 bg-emerald-50 border border-emerald-100 rounded text-[11px] font-medium text-emerald-800 hover:bg-emerald-100 transition-colors cursor-default flex items-center gap-1.5">
               <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 shrink-0"></div>
               <span className="truncate">{off.officeName}</span>
            </div>
          ))}
          {data.booked.length === 0 && <p className="text-[10px] text-slate-300 italic">None</p>}
        </div>
      </div>

      <div className="space-y-2">
        <p className="text-[10px] font-bold text-red-600 uppercase mb-1">Not Booked ({data.notBooked.length})</p>
        <div className="max-h-60 overflow-y-auto pr-1 space-y-1 custom-scrollbar">
          {data.notBooked.map(off => (
            <div key={off.officeId} className="px-2 py-1.5 bg-red-50 border border-red-100 rounded text-[11px] font-medium text-red-800 hover:bg-red-100 transition-colors cursor-default flex items-center gap-1.5">
               <div className="w-1.5 h-1.5 rounded-full bg-red-400 shrink-0"></div>
               <span className="truncate">{off.officeName}</span>
            </div>
          ))}
          {data.notBooked.length === 0 && <p className="text-[10px] text-slate-300 italic">None</p>}
        </div>
      </div>
    </div>
  </div>
);

const StatCard = ({ title, total, icon, color }: any) => (
  <div className={`p-4 rounded-xl border border-slate-100 shadow-sm ${color} flex items-center justify-between`}>
    <div>
      <p className="text-xs font-bold text-slate-500 uppercase">{title}</p>
      <p className="text-2xl font-black text-slate-800 mt-1">{total}</p>
    </div>
    <div className="bg-white p-2.5 rounded-lg shadow-sm">{icon}</div>
  </div>
);

const PerfCard = ({ label, value, sub, onClick, isActive }: any) => (
  <button 
    onClick={onClick}
    className={`w-full group text-left p-4 rounded-xl border transition-all duration-200 shadow-sm flex flex-col items-center justify-center text-center relative overflow-hidden
    ${isActive ? 'bg-white ring-2 ring-[#CE2029] border-transparent scale-[1.02]' : 'bg-slate-50 border-slate-200 hover:bg-white hover:border-[#CE2029]/30 hover:shadow-md'}`}
  >
    {isActive && <div className="absolute top-0 right-0 p-1"><ChevronDown size={14} className="text-[#CE2029]" /></div>}
    <p className={`text-[10px] font-black uppercase tracking-tighter mb-1 transition-colors ${isActive ? 'text-[#CE2029]' : 'text-slate-500 group-hover:text-slate-700'}`}>{label}</p>
    <div className="flex items-baseline gap-1.5">
      <span className={`text-xl font-black transition-colors ${isActive ? 'text-[#CE2029]' : 'text-slate-700'}`}>{value}</span>
      <span className="text-[10px] text-slate-400 font-bold">{sub}</span>
    </div>
    <div className="w-full h-1 bg-slate-200 rounded-full mt-2 overflow-hidden">
       <div className={`h-full transition-all duration-500 ${isActive ? 'bg-[#CE2029]' : 'bg-slate-400 group-hover:bg-[#CE2029]/60'}`} style={{ width: `${Math.min(100, (value / (value + parseInt(sub.split(': ')[1] || '0'))) * 100)}%` }}></div>
    </div>
  </button>
);

const Package = ({ size, className }: any) => (
  <svg 
    xmlns="http://www.w3.org/2000/svg" 
    width={size} 
    height={size} 
    viewBox="0 0 24 24" 
    fill="none" 
    stroke="currentColor" 
    strokeWidth="2" 
    strokeLinecap="round" 
    strokeLinejoin="round" 
    className={className}
  >
    <path d="M21 8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16Z"/>
    <path d="m3.3 7 8.7 5 8.7-5"/><path d="M12 22V12"/>
  </svg>
);

export default RSBTCellReport;

import React, { useMemo, useState, useRef } from 'react';
import { BookingDataRow, MasterDataRow } from '../types';
import { FileSpreadsheet, Download, Printer, Home, Landmark, ChevronDown, ChevronRight, CheckCircle2, XCircle, Search, FileText } from 'lucide-react';
import { exportToPDF, exportToExcel, getProductCategory } from '../utils';

interface RSBTCellReportProps {
  data: BookingDataRow[];
  masterData: MasterDataRow[];
}

type DetailType = {
  product: 'Speed Post' | 'Parcel';
  officeType: 'B.O' | 'P.O';
  label: string;
} | null;

// Add explicit interfaces for complex nested report structures
interface OfficeListSummary {
  booked: MasterDataRow[];
  notBooked: MasterDataRow[];
}

interface SubDivisionSummary {
  Rural: OfficeListSummary;
  Urban: OfficeListSummary;
}

const RSBTCellReport: React.FC<RSBTCellReportProps> = ({ data, masterData }) => {
  const [detailView, setDetailView] = useState<DetailType>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const detailRef = useRef<HTMLDivElement>(null);

  // Fix: Use explicit type for reportData to ensure proper indexing in JSX and export functions
  const reportData = useMemo<Record<string, Record<string, number>>>(() => {
    const results: Record<string, Record<string, number>> = { Rural: {}, Urban: {}, Total: {} };

    const categories = [
      { id: 'boSpeed', label: 'BO Speed Post', type: 'B.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'boParcel', label: 'BO Parcel', type: 'B.O', targetCat: 'Parcel' },
      { id: 'poSpeed', label: 'PO Speed Post', type: 'P.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'poParcel', label: 'PO Parcel', type: 'P.O', targetCat: 'Parcel' },
      { id: 'poIntl', label: 'PO International', type: 'P.O', targetCat: 'International' },
    ];

    categories.forEach(cat => {
      results.Rural[cat.id] = 0;
      results.Urban[cat.id] = 0;
      results.Total[cat.id] = 0;

      data.forEach(row => {
        const rowType = row.officeType === 'B.O' ? 'B.O' : 'P.O';
        const rowCat = getProductCategory(row.productName);

        let isMatch = rowCat === cat.targetCat;
        if (cat.isSpeed && isMatch) {
            isMatch = row.productName.toLowerCase().includes('speed post');
        }

        if (isMatch && rowType === cat.type) {
          const area = row.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
          results[area][cat.id] += row.articles;
          results.Total[cat.id] += row.articles;
        }
      });
    });

    return results;
  }, [data]);

  const officeStats = useMemo(() => {
    const stats = {
      ruralBO: { total: 0, bookedSP: 0, bookedPar: 0 },
      urbanBO: { total: 0, bookedSP: 0, bookedPar: 0 },
      ruralPO: { total: 0, bookedSP: 0, bookedPar: 0 },
      urbanPO: { total: 0, bookedSP: 0, bookedPar: 0 },
    };

    const spBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Domestic' && r.productName.toLowerCase().includes('speed post')).map(r => r.officeId));
    const parBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Parcel').map(r => r.officeId));

    masterData.forEach(m => {
      const isUrban = m.areaType?.toLowerCase().includes('urban');
      const isBO = m.officeType === 'B.O';

      if (isBO) {
        if (isUrban) {
          stats.urbanBO.total++;
          if (spBookedIds.has(m.officeId)) stats.urbanBO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.urbanBO.bookedPar++;
        } else {
          stats.ruralBO.total++;
          if (spBookedIds.has(m.officeId)) stats.ruralBO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.ruralBO.bookedPar++;
        }
      } else {
        if (isUrban) {
          stats.urbanPO.total++;
          if (spBookedIds.has(m.officeId)) stats.urbanPO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.urbanPO.bookedPar++;
        } else {
          stats.ruralPO.total++;
          if (spBookedIds.has(m.officeId)) stats.ruralPO.bookedSP++;
          if (parBookedIds.has(m.officeId)) stats.ruralPO.bookedPar++;
        }
      }
    });

    return stats;
  }, [data, masterData]);

  // Fix: Explicitly type detailedOfficeData to ensure areas.Rural/Urban access works correctly in the map loop
  const detailedOfficeData = useMemo<Record<string, SubDivisionSummary> | null>(() => {
    if (!detailView) return null;

    const { product, officeType } = detailView;
    const bookedIds = new Set(data.filter(r => {
      const cat = getProductCategory(r.productName);
      if (product === 'Speed Post') {
        return cat === 'Domestic' && r.productName.toLowerCase().includes('speed post');
      }
      return cat === 'Parcel';
    }).map(r => r.officeId));

    const relevantOffices = masterData.filter(m => {
      const typeMatch = officeType === 'B.O' ? m.officeType === 'B.O' : m.officeType !== 'B.O';
      return typeMatch;
    });

    const grouped: Record<string, SubDivisionSummary> = {};

    relevantOffices.forEach(off => {
      const subDiv = off.subDivisionName || 'Unknown Sub-Division';
      if (!grouped[subDiv]) {
        grouped[subDiv] = {
          Rural: { booked: [], notBooked: [] },
          Urban: { booked: [], notBooked: [] }
        };
      }

      const isUrban = off.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
      const isBooked = bookedIds.has(off.officeId);

      if (isBooked) {
        grouped[subDiv][isUrban as 'Rural' | 'Urban'].booked.push(off);
      } else {
        grouped[subDiv][isUrban as 'Rural' | 'Urban'].notBooked.push(off);
      }
    });

    return grouped;
  }, [detailView, data, masterData]);

  const handlePerfClick = (product: 'Speed Post' | 'Parcel', officeType: 'B.O' | 'P.O') => {
    setDetailView({
      product,
      officeType,
      label: `${officeType === 'B.O' ? 'Branch Office' : 'Sub Office/PO'} - ${product} Booking Detail`
    });
    setTimeout(() => {
      detailRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  const handleExportExcel = () => {
    const exportData = [
      { Category: 'Rural', ...reportData.Rural },
      { Category: 'Urban', ...reportData.Urban },
      { Category: 'Total', ...reportData.Total },
    ];
    exportToExcel(exportData, 'RSBT_Cell_Report');
  };

  const handleExportPDF = () => {
    const headers = ['Category', 'BO Speed Post', 'BO Parcel', 'PO Speed Post', 'PO Parcel', 'PO International'];
    const rows = [
      ['Rural', reportData.Rural.boSpeed, reportData.Rural.boParcel, reportData.Rural.poSpeed, reportData.Rural.poParcel, reportData.Rural.poIntl],
      ['Urban', reportData.Urban.boSpeed, reportData.Urban.boParcel, reportData.Urban.poSpeed, reportData.Urban.poParcel, reportData.Urban.poIntl],
      ['Total', reportData.Total.boSpeed, reportData.Total.boParcel, reportData.Total.poSpeed, reportData.Total.poParcel, reportData.Total.poIntl],
    ];
    exportToPDF(headers, rows, 'RSBT Cell Report (Article Counts)');
  };

  const handleExportDetailedList = (format: 'pdf' | 'excel') => {
    if (!detailedOfficeData || !detailView) return;

    const flatData: any[] = [];
    Object.entries(detailedOfficeData).forEach(([subDiv, areas]) => {
      ['Rural', 'Urban'].forEach(areaType => {
        const area = (areas as SubDivisionSummary)[areaType as 'Rural' | 'Urban'];
        area.booked.forEach(off => {
          flatData.push({
            'Sub-Division': subDiv,
            'Area Type': areaType,
            'Office Name': off.officeName,
            'Office ID': off.officeId,
            'Status': 'Booked'
          });
        });
        area.notBooked.forEach(off => {
          flatData.push({
            'Sub-Division': subDiv,
            'Area Type': areaType,
            'Office Name': off.officeName,
            'Office ID': off.officeId,
            'Status': 'Not Booked'
          });
        });
      });
    });

    const fileName = `Detailed_${detailView.officeType}_${detailView.product.replace(/\s+/g, '_')}_Report`;

    if (format === 'excel') {
      exportToExcel(flatData, fileName);
    } else {
      const headers = ['Sub-Division', 'Area Type', 'Office Name', 'Office ID', 'Status'];
      const rows = flatData.map(d => [d['Sub-Division'], d['Area Type'], d['Office Name'], d['Office ID'], d['Status']]);
      exportToPDF(headers, rows, `${detailView.label} - Summary List`);
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h2 className="text-xl font-bold text-slate-800 mb-6 flex items-center gap-2">
          <Landmark className="text-[#CE2029]" /> Office Type & Performance Summary
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <StatCard title="Rural BOs" total={officeStats.ruralBO.total} icon={<Home size={20} className="text-emerald-600" />} color="bg-emerald-50" />
          <StatCard title="Urban BOs" total={officeStats.urbanBO.total} icon={<Landmark size={20} className="text-blue-600" />} color="bg-blue-50" />
          <StatCard title="Rural SOs/POs" total={officeStats.ruralPO.total} icon={<Home size={20} className="text-emerald-600" />} color="bg-emerald-50" />
          <StatCard title="Urban SOs/POs" total={officeStats.urbanPO.total} icon={<Landmark size={20} className="text-blue-600" />} color="bg-blue-50" />
        </div>

        <div className="mt-8 grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="space-y-4">
            <h3 className="font-bold text-slate-700 border-l-4 border-amber-500 pl-3 flex justify-between items-center">
              <span>Branch Office (BO) Statistics</span>
              <span className="text-[10px] font-normal text-slate-400 italic">Click cards for details</span>
            </h3>
            <div className="grid grid-cols-2 gap-3">
              <PerfCard 
                label="Speed Post Booked" 
                value={officeStats.ruralBO.bookedSP + officeStats.urbanBO.bookedSP} 
                sub={`Not: ${(officeStats.ruralBO.total + officeStats.urbanBO.total) - (officeStats.ruralBO.bookedSP + officeStats.urbanBO.bookedSP)}`} 
                onClick={() => handlePerfClick('Speed Post', 'B.O')}
                isActive={detailView?.product === 'Speed Post' && detailView?.officeType === 'B.O'}
              />
              <PerfCard 
                label="Parcel Booked" 
                value={officeStats.ruralBO.bookedPar + officeStats.urbanBO.bookedPar} 
                sub={`Not: ${(officeStats.ruralBO.total + officeStats.urbanBO.total) - (officeStats.ruralBO.bookedPar + officeStats.urbanBO.bookedPar)}`} 
                onClick={() => handlePerfClick('Parcel', 'B.O')}
                isActive={detailView?.product === 'Parcel' && detailView?.officeType === 'B.O'}
              />
            </div>
          </div>

          <div className="space-y-4">
            <h3 className="font-bold text-slate-700 border-l-4 border-blue-500 pl-3 flex justify-between items-center">
              <span>Sub Office / PO Statistics</span>
              <span className="text-[10px] font-normal text-slate-400 italic">Click cards for details</span>
            </h3>
            <div className="grid grid-cols-2 gap-3">
              <PerfCard 
                label="Speed Post Booked" 
                value={officeStats.ruralPO.bookedSP + officeStats.urbanPO.bookedSP} 
                sub={`Not: ${(officeStats.ruralPO.total + officeStats.urbanPO.total) - (officeStats.ruralPO.bookedSP + officeStats.urbanPO.bookedSP)}`} 
                onClick={() => handlePerfClick('Speed Post', 'P.O')}
                isActive={detailView?.product === 'Speed Post' && detailView?.officeType === 'P.O'}
              />
              <PerfCard 
                label="Parcel Booked" 
                value={officeStats.ruralPO.bookedPar + officeStats.urbanPO.bookedPar} 
                sub={`Not: ${(officeStats.ruralPO.total + officeStats.urbanPO.total) - (officeStats.ruralPO.bookedPar + officeStats.urbanPO.bookedPar)}`} 
                onClick={() => handlePerfClick('Parcel', 'P.O')}
                isActive={detailView?.product === 'Parcel' && detailView?.officeType === 'P.O'}
              />
            </div>
          </div>
        </div>
      </div>

      <div ref={detailRef}>
        {detailView && detailedOfficeData && (
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
              <div className="flex-1">
                <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                   <div className="w-8 h-8 rounded-lg bg-red-50 flex items-center justify-center text-[#CE2029]">
                    {detailView.product === 'Speed Post' ? <Search size={18} /> : <Package size={18} />}
                   </div>
                   {detailView.label}
                </h2>
                <div className="flex items-center gap-4 mt-1">
                   <p className="text-xs text-slate-500">Categorized by Sub-Division and Area Type</p>
                   <div className="flex gap-2">
                      <button onClick={() => handleExportDetailedList('excel')} className="flex items-center gap-1 px-2 py-0.5 bg-green-50 text-green-700 text-[10px] font-bold rounded border border-green-200 hover:bg-green-100 transition-colors">
                        <Download size={10}/> EXCEL
                      </button>
                      <button onClick={() => handleExportDetailedList('pdf')} className="flex items-center gap-1 px-2 py-0.5 bg-red-50 text-[#CE2029] text-[10px] font-bold rounded border border-red-200 hover:bg-red-100 transition-colors">
                        <FileText size={10}/> PDF
                      </button>
                   </div>
                </div>
              </div>

              <div className="relative w-full md:w-64">
                <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
                <input
                  type="text"
                  placeholder="Search sub-division..."
                  className="pl-10 w-full border border-slate-200 rounded-lg py-2 text-sm focus:ring-2 focus:ring-[#CE2029] focus:outline-none bg-slate-50"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="space-y-8">
              {Object.entries(detailedOfficeData)
                .filter(([subDiv]) => subDiv.toLowerCase().includes(searchTerm.toLowerCase()))
                .sort(([a], [b]) => a.localeCompare(b))
                .map(([subDiv, areas]: [string, SubDivisionSummary]) => (
                  <div key={subDiv} className="border border-slate-100 rounded-xl overflow-hidden">
                    <div className="bg-slate-50 px-4 py-3 border-b border-slate-100 flex items-center justify-between">
                      <h3 className="font-bold text-slate-700 uppercase tracking-wider text-sm">{subDiv}</h3>
                      <div className="flex gap-4 text-[10px] font-bold">
                        <span className="flex items-center gap-1 text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded border border-emerald-100">
                          <CheckCircle2 size={12}/> Booked: {areas.Rural.booked.length + areas.Urban.booked.length}
                        </span>
                        <span className="flex items-center gap-1 text-red-600 bg-red-50 px-2 py-0.5 rounded border border-red-100">
                          <XCircle size={12}/> Not: {areas.Rural.notBooked.length + areas.Urban.notBooked.length}
                        </span>
                      </div>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-slate-100">
                      <AreaSection title="Rural" data={areas.Rural} />
                      <AreaSection title="Urban" data={areas.Urban} />
                    </div>
                  </div>
              ))}

              {Object.entries(detailedOfficeData).filter(([subDiv]) => subDiv.toLowerCase().includes(searchTerm.toLowerCase())).length === 0 && (
                <div className="text-center py-12 bg-slate-50 rounded-xl border border-dashed border-slate-200">
                  <p className="text-slate-400 text-sm">No matching sub-divisions found.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <FileSpreadsheet className="text-[#CE2029]" /> RSBT Cell Report (Article Volume)
          </h2>
          <div className="flex gap-2">
            <button onClick={handleExportExcel} className="flex items-center gap-1 px-4 py-2 bg-green-50 text-green-700 rounded-lg border border-green-200 hover:bg-green-100 transition-all text-sm font-medium shadow-sm">
              <Download size={16} /> Excel
            </button>
            <button onClick={handleExportPDF} className="flex items-center gap-1 px-4 py-2 bg-red-50 text-[#CE2029] rounded-lg border border-red-200 hover:bg-red-100 transition-all text-sm font-medium shadow-sm">
              <Printer size={16} /> PDF
            </button>
          </div>
        </div>

        <div className="overflow-x-auto rounded-lg border border-slate-200">
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-50 text-slate-600 font-semibold uppercase tracking-wider text-xs">
              <tr>
                <th className="px-6 py-4 border-b">Category / Area</th>
                <th className="px-6 py-4 border-b text-center">BO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">BO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">PO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO International</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {['Rural', 'Urban', 'Total'].map((area) => (
                <tr key={area} className={`${area === 'Total' ? 'bg-slate-50 font-bold' : 'hover:bg-slate-50'} transition-colors`}>
                  <td className="px-6 py-4 text-slate-700">{area}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].boSpeed}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].boParcel}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].poSpeed}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].poParcel}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{reportData[area].poIntl}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

const AreaSection = ({ title, data }: { title: string, data: OfficeListSummary }) => (
  <div className="p-4">
    <div className="flex items-center gap-2 mb-3">
      <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest">{title}</h4>
      <div className="h-px flex-1 bg-slate-100"></div>
    </div>

    <div className="grid grid-cols-2 gap-4">
      <div className="space-y-2">
        <p className="text-[10px] font-bold text-emerald-600 uppercase mb-1">Booked ({data.booked.length})</p>
        <div className="max-h-60 overflow-y-auto pr-1 space-y-1 custom-scrollbar">
          {data.booked.map(off => (
            <div key={off.officeId} className="px-2 py-1.5 bg-emerald-50 border border-emerald-100 rounded text-[11px] font-medium text-emerald-800 hover:bg-emerald-100 transition-colors cursor-default flex items-center gap-1.5">
               <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 shrink-0"></div>
               <span className="truncate">{off.officeName}</span>
            </div>
          ))}
          {data.booked.length === 0 && <p className="text-[10px] text-slate-300 italic">None</p>}
        </div>
      </div>

      <div className="space-y-2">
        <p className="text-[10px] font-bold text-red-600 uppercase mb-1">Not Booked ({data.notBooked.length})</p>
        <div className="max-h-60 overflow-y-auto pr-1 space-y-1 custom-scrollbar">
          {data.notBooked.map(off => (
            <div key={off.officeId} className="px-2 py-1.5 bg-red-50 border border-red-100 rounded text-[11px] font-medium text-red-800 hover:bg-red-100 transition-colors cursor-default flex items-center gap-1.5">
               <div className="w-1.5 h-1.5 rounded-full bg-red-400 shrink-0"></div>
               <span className="truncate">{off.officeName}</span>
            </div>
          ))}
          {data.notBooked.length === 0 && <p className="text-[10px] text-slate-300 italic">None</p>}
        </div>
      </div>
    </div>
  </div>
);

const StatCard = ({ title, total, icon, color }: any) => (
  <div className={`p-4 rounded-xl border border-slate-100 shadow-sm ${color} flex items-center justify-between`}>
    <div>
      <p className="text-xs font-bold text-slate-500 uppercase">{title}</p>
      <p className="text-2xl font-black text-slate-800 mt-1">{total}</p>
    </div>
    <div className="bg-white p-2.5 rounded-lg shadow-sm">{icon}</div>
  </div>
);

const PerfCard = ({ label, value, sub, onClick, isActive }: any) => (
  <button 
    onClick={onClick}
    className={`w-full group text-left p-4 rounded-xl border transition-all duration-200 shadow-sm flex flex-col items-center justify-center text-center relative overflow-hidden
    ${isActive ? 'bg-white ring-2 ring-[#CE2029] border-transparent scale-[1.02]' : 'bg-slate-50 border-slate-200 hover:bg-white hover:border-[#CE2029]/30 hover:shadow-md'}`}
  >
    {isActive && <div className="absolute top-0 right-0 p-1"><ChevronDown size={14} className="text-[#CE2029]" /></div>}
    <p className={`text-[10px] font-black uppercase tracking-tighter mb-1 transition-colors ${isActive ? 'text-[#CE2029]' : 'text-slate-500 group-hover:text-slate-700'}`}>{label}</p>
    <div className="flex items-baseline gap-1.5">
      <span className={`text-xl font-black transition-colors ${isActive ? 'text-[#CE2029]' : 'text-slate-700'}`}>{value}</span>
      <span className="text-[10px] text-slate-400 font-bold">{sub}</span>
    </div>
    <div className="w-full h-1 bg-slate-200 rounded-full mt-2 overflow-hidden">
       <div className={`h-full transition-all duration-500 ${isActive ? 'bg-[#CE2029]' : 'bg-slate-400 group-hover:bg-[#CE2029]/60'}`} style={{ width: `${Math.min(100, (value / (value + parseInt(sub.split(': ')[1] || '0'))) * 100)}%` }}></div>
    </div>
  </button>
);

const Package = ({ size, className }: any) => (
  <svg 
    xmlns="http://www.w3.org/2000/svg" 
    width={size} 
    height={size} 
    viewBox="0 0 24 24" 
    fill="none" 
    stroke="currentColor" 
    strokeWidth="2" 
    strokeLinecap="round" 
    strokeLinejoin="round" 
    className={className}
  >
    <path d="M21 8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16Z"/>
    <path d="m3.3 7 8.7 5 8.7-5"/><path d="M12 22V12"/>
  </svg>
);

export default RSBTCellReport;

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { BookingDataRow, MasterDataRow } from '../types';
import { FileSpreadsheet, Download, Printer, Home, Landmark, ChevronDown, CheckCircle2, XCircle, Search, Filter, Mail, Package, Globe } from 'lucide-react';
import { exportToPDF, exportToExcel, getProductCategory, formatCurrency } from '../utils';

interface RSBTCellReportProps {
  data: BookingDataRow[];
  masterData: MasterDataRow[];
}

type MailType = 'Speed Post' | 'Parcel' | 'International';
type BookingStatus = 'All' | 'Booked' | 'Not Booked';
type AreaFilter = 'All' | 'Rural' | 'Urban';

const RSBTCellReport: React.FC<RSBTCellReportProps> = ({ data, masterData }) => {
  // Filters State
  const [filterType, setFilterType] = useState<MailType>('Speed Post');
  const [filterStatus, setFilterStatus] = useState<BookingStatus>('All');
  const [filterArea, setFilterArea] = useState<AreaFilter>('All');
  const [filterSubDiv, setFilterSubDiv] = useState('');

  const detailRef = useRef<HTMLDivElement>(null);

  // 1. Top Summary Data (Volume Counts)
  const volumeStats = useMemo<any>(() => {
    const results: any = { Rural: {}, Urban: {}, Total: {} };
    const categories = [
      { id: 'boSpeed', type: 'B.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'boParcel', type: 'B.O', targetCat: 'Parcel' },
      { id: 'poSpeed', type: 'P.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'poParcel', type: 'P.O', targetCat: 'Parcel' },
      { id: 'poIntl', type: 'P.O', targetCat: 'International' },
    ];

    categories.forEach(cat => {
      results.Rural[cat.id] = 0; results.Urban[cat.id] = 0; results.Total[cat.id] = 0;
      data.forEach(row => {
        const rowType = row.officeType === 'B.O' ? 'B.O' : 'P.O';
        const rowCat = getProductCategory(row.productName);
        let isMatch = rowCat === cat.targetCat;
        if (cat.isSpeed && isMatch) isMatch = row.productName.toLowerCase().includes('speed post');
        if (isMatch && rowType === cat.type) {
          const area = row.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
          results[area][cat.id] += row.articles;
          results.Total[cat.id] += row.articles;
        }
      });
    });
    return results;
  }, [data]);

  // 2. Performance Card Stats (Entity Counts)
  const performanceStats = useMemo(() => {
    const stats = {
      bo: { total: 0, bookedSP: 0, bookedPar: 0 },
      po: { total: 0, bookedSP: 0, bookedPar: 0 },
    };

    const spBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Domestic' && r.productName.toLowerCase().includes('speed post')).map(r => r.officeId));
    const parBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Parcel').map(r => r.officeId));

    masterData.forEach(m => {
      const isBO = m.officeType === 'B.O';
      if (isBO) {
        stats.bo.total++;
        if (spBookedIds.has(m.officeId)) stats.bo.bookedSP++;
        if (parBookedIds.has(m.officeId)) stats.bo.bookedPar++;
      } else {
        stats.po.total++;
        if (spBookedIds.has(m.officeId)) stats.po.bookedSP++;
        if (parBookedIds.has(m.officeId)) stats.po.bookedPar++;
      }
    });
    return stats;
  }, [data, masterData]);

  // 3. Main 7-Column Report Logic
  const detailedReportList = useMemo(() => {
    // Determine which bookings match the current Mail Type
    const typeBookings = data.filter(r => {
      const cat = getProductCategory(r.productName);
      if (filterType === 'Speed Post') return cat === 'Domestic' && r.productName.toLowerCase().includes('speed post');
      if (filterType === 'Parcel') return cat === 'Parcel';
      return cat === 'International';
    });

    // Map by Office ID for fast lookup
    const bookingMap = new Map<string, { articles: number, postage: number }>();
    typeBookings.forEach(b => {
      const current = bookingMap.get(b.officeId) || { articles: 0, postage: 0 };
      current.articles += b.articles;
      current.postage += b.totalAmount;
      bookingMap.set(b.officeId, current);
    });

    // Process Master Data with Filters
    return masterData
      .map(office => {
        const booking = bookingMap.get(office.officeId);
        return {
          ...office,
          articles: booking ? booking.articles : 0,
          postage: booking ? booking.postage : 0,
          isBooked: !!booking
        };
      })
      .filter(office => {
        // Area Filter
        if (filterArea !== 'All' && office.areaType !== filterArea) return false;

        // Status Filter
        if (filterStatus === 'Booked' && !office.isBooked) return false;
        if (filterStatus === 'Not Booked' && office.isBooked) return false;

        // Sub-Division Filter
        if (filterSubDiv && !office.subDivisionName.toLowerCase().includes(filterSubDiv.toLowerCase())) return false;

        return true;
      })
      .sort((a, b) => a.officeName.localeCompare(b.officeName));
  }, [masterData, data, filterType, filterStatus, filterArea, filterSubDiv]);

  const handleCardClick = (type: MailType, status: BookingStatus) => {
    setFilterType(type);
    setFilterStatus(status);
    setTimeout(() => {
      detailRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  const exportMainReport = (format: 'pdf' | 'excel') => {
    const fileName = `Detailed_Monitoring_${filterType}_${filterStatus}_${filterArea}`;
    const headers = ['Sl No', 'Name of the Office', 'Office ID', 'Sub-Division Name', 'Rural/Urban', 'Number', 'Postage'];

    const rows = detailedReportList.map((row, i) => [
      i + 1,
      row.officeName,
      row.officeId,
      row.subDivisionName,
      row.areaType,
      row.articles,
      row.postage.toFixed(2)
    ]);

    if (format === 'excel') {
      const excelData = detailedReportList.map((row, i) => ({
        'Sl No': i + 1,
        'Name of the Office': row.officeName,
        'Office ID': row.officeId,
        'Sub-Division Name': row.subDivisionName,
        'Rural/Urban': row.areaType,
        'Number (Articles)': row.articles,
        'Postage Amount': row.postage
      }));
      exportToExcel(excelData, fileName);
    } else {
      exportToPDF(headers, rows, `${filterType} Monitoring Report - ${filterStatus} (${filterArea})`, true);
    }
  };

  const getSubDivisions = useMemo(() => {
    const subs = Array.from(new Set(masterData.map(m => m.subDivisionName)));
    return subs.sort();
  }, [masterData]);

  return (
    <div className="space-y-8 pb-10">
      {/* 1. TOP PERFORMANCE CARDS */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2 border-b border-slate-100 pb-2">
            <div className="p-1.5 bg-amber-50 text-amber-600 rounded-lg"><Home size={18}/></div>
            Branch Office (BO) Performance
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <PerfButton 
              label="Speed Post Booked" 
              value={performanceStats.bo.bookedSP} 
              total={performanceStats.bo.total} 
              color="text-emerald-700" 
              icon={<Mail size={16}/>}
              onClick={() => handleCardClick('Speed Post', 'Booked')}
            />
            <PerfButton 
              label="Parcel Booked" 
              value={performanceStats.bo.bookedPar} 
              total={performanceStats.bo.total} 
              color="text-amber-700" 
              icon={<Package size={16}/>}
              onClick={() => handleCardClick('Parcel', 'Booked')}
            />
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2 border-b border-slate-100 pb-2">
            <div className="p-1.5 bg-blue-50 text-blue-600 rounded-lg"><Landmark size={18}/></div>
            Sub Office / PO Performance
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <PerfButton 
              label="Speed Post Booked" 
              value={performanceStats.po.bookedSP} 
              total={performanceStats.po.total} 
              color="text-emerald-700" 
              icon={<Mail size={16}/>}
              onClick={() => handleCardClick('Speed Post', 'Booked')}
            />
            <PerfButton 
              label="Parcel Booked" 
              value={performanceStats.po.bookedPar} 
              total={performanceStats.po.total} 
              color="text-amber-700" 
              icon={<Package size={16}/>}
              onClick={() => handleCardClick('Parcel', 'Booked')}
            />
          </div>
        </div>
      </div>

      {/* 2. DETAILED 7-COLUMN REPORT SECTION */}
      <div ref={detailRef} className="bg-white p-6 rounded-2xl shadow-md border border-slate-200 space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div>
            <h2 className="text-xl font-extrabold text-slate-800 flex items-center gap-2">
              <ClipboardList className="text-[#CE2029]" /> Detailed Monitoring Report
            </h2>
            <p className="text-xs text-slate-500 mt-1">Unified view of all offices with specific article counts</p>
          </div>
          <div className="flex gap-2">
             <button onClick={() => exportMainReport('excel')} className="flex items-center gap-1.5 px-4 py-2 bg-green-50 text-green-700 rounded-lg border border-green-200 hover:bg-green-100 transition-all text-sm font-bold shadow-sm">
               <Download size={16}/> Excel
             </button>
             <button onClick={() => exportMainReport('pdf')} className="flex items-center gap-1.5 px-4 py-2 bg-red-50 text-[#CE2029] rounded-lg border border-red-200 hover:bg-red-100 transition-all text-sm font-bold shadow-sm">
               <Printer size={16}/> Print Report
             </button>
          </div>
        </div>

        {/* 4 SEARCH FILTERS BAR */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 p-4 bg-slate-50 rounded-xl border border-slate-200">
           {/* Filter 1: Type */}
           <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase text-slate-500 flex items-center gap-1">
                <Filter size={10}/> 1. Type
              </label>
              <select 
                value={filterType} 
                onChange={e => setFilterType(e.target.value as MailType)}
                className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm font-medium focus:ring-2 focus:ring-red-500 outline-none"
              >
                <option value="Speed Post">Speed Post</option>
                <option value="Parcel">Parcel</option>
                <option value="International">International Mail</option>
              </select>
           </div>

           {/* Filter 2: Sub-Division */}
           <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase text-slate-500 flex items-center gap-1">
                <Search size={10}/> 2. Sub-Division
              </label>
              <div className="relative">
                <input 
                  type="text"
                  placeholder="All Sub-Divisions..."
                  value={filterSubDiv}
                  onChange={e => setFilterSubDiv(e.target.value)}
                  className="w-full bg-white border border-slate-200 rounded-lg pl-3 pr-8 py-2 text-sm font-medium focus:ring-2 focus:ring-red-500 outline-none"
                  list="subdiv-list"
                />
                <datalist id="subdiv-list">
                  {getSubDivisions.map(s => <option key={s} value={s} />)}
                </datalist>
              </div>
           </div>

           {/* Filter 3: Rural/Urban */}
           <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase text-slate-500 flex items-center gap-1">
                <Globe size={10}/> 3. Area Type
              </label>
              <select 
                value={filterArea} 
                onChange={e => setFilterArea(e.target.value as AreaFilter)}
                className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm font-medium focus:ring-2 focus:ring-red-500 outline-none"
              >
                <option value="All">All Areas</option>
                <option value="Rural">Rural</option>
                <option value="Urban">Urban</option>
              </select>
           </div>

           {/* Filter 4: Booked/Not Booked */}
           <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase text-slate-500 flex items-center gap-1">
                <CheckCircle2 size={10}/> 4. Booking Status
              </label>
              <select 
                value={filterStatus} 
                onChange={e => setFilterStatus(e.target.value as BookingStatus)}
                className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm font-medium focus:ring-2 focus:ring-red-500 outline-none"
              >
                <option value="All">Show All</option>
                <option value="Booked">Booked Only</option>
                <option value="Not Booked">Not Booked Only</option>
              </select>
           </div>
        </div>

        {/* DATA TABLE (7 COLUMNS) */}
        <div className="overflow-hidden rounded-xl border border-slate-200 shadow-inner bg-slate-50">
           <div className="overflow-x-auto max-h-[600px] custom-scrollbar">
             <table className="w-full text-sm text-left border-collapse">
               <thead className="bg-slate-800 text-white font-bold sticky top-0 z-20">
                 <tr>
                    <th className="px-4 py-3 border-r border-slate-700 w-16">Sl No</th>
                    <th className="px-4 py-3 border-r border-slate-700">Name of the Office</th>
                    <th className="px-4 py-3 border-r border-slate-700">Office ID</th>
                    <th className="px-4 py-3 border-r border-slate-700">Sub-Division Name</th>
                    <th className="px-4 py-3 border-r border-slate-700">Rural/Urban</th>
                    <th className="px-4 py-3 border-r border-slate-700 text-center">Number</th>
                    <th className="px-4 py-3 text-right">Postage</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-200 bg-white">
                 {detailedReportList.map((row, idx) => (
                   <tr key={row.officeId} className="hover:bg-slate-50 transition-colors group">
                     <td className="px-4 py-3 text-slate-500 font-medium">{idx + 1}</td>
                     <td className="px-4 py-3 font-bold text-slate-900">{row.officeName}</td>
                     <td className="px-4 py-3 text-slate-600 font-mono text-xs">{row.officeId}</td>
                     <td className="px-4 py-3 text-slate-700">{row.subDivisionName}</td>
                     <td className="px-4 py-3">
                        <span className={`text-[10px] font-black uppercase px-2 py-0.5 rounded-full ${row.areaType === 'Urban' ? 'bg-blue-100 text-blue-700' : 'bg-emerald-100 text-emerald-700'}`}>
                          {row.areaType}
                        </span>
                     </td>
                     <td className={`px-4 py-3 text-center font-black ${row.articles > 0 ? 'text-blue-700' : 'text-slate-300'}`}>
                        {row.articles}
                     </td>
                     <td className="px-4 py-3 text-right font-black text-slate-900 bg-slate-50/50">
                        {row.postage > 0 ? formatCurrency(row.postage) : '-'}
                     </td>
                   </tr>
                 ))}
                 {detailedReportList.length === 0 && (
                   <tr>
                     <td colSpan={7} className="px-4 py-12 text-center text-slate-400 italic bg-white">
                        No offices found matching the selected criteria.
                     </td>
                   </tr>
                 )}
               </tbody>
               {detailedReportList.length > 0 && (
                 <tfoot className="bg-slate-800 text-white font-black sticky bottom-0 z-20">
                    <tr>
                       <td colSpan={5} className="px-4 py-4 text-center tracking-[0.2em] uppercase text-xs">Page Total</td>
                       <td className="px-4 py-4 text-center text-lg">{detailedReportList.reduce((acc, r) => acc + r.articles, 0)}</td>
                       <td className="px-4 py-4 text-right text-lg">{formatCurrency(detailedReportList.reduce((acc, r) => acc + r.postage, 0))}</td>
                    </tr>
                 </tfoot>
               )}
             </table>
           </div>
        </div>
      </div>

      {/* 3. RSBT VOLUME SUMMARY TABLE */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2 mb-6">
          <FileSpreadsheet className="text-[#CE2029]" /> RSBT Cell Volume Summary
        </h2>
        <div className="overflow-x-auto rounded-xl border border-slate-200">
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-50 text-slate-600 font-bold uppercase tracking-widest text-[10px]">
              <tr>
                <th className="px-6 py-4 border-b">Category / Area</th>
                <th className="px-6 py-4 border-b text-center">BO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">BO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">PO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO International</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {['Rural', 'Urban', 'Total'].map((area) => (
                <tr key={area} className={`${area === 'Total' ? 'bg-slate-50 font-bold' : 'hover:bg-slate-50'} transition-colors`}>
                  <td className="px-6 py-4 text-slate-700">{area}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{volumeStats[area].boSpeed}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{volumeStats[area].boParcel}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{volumeStats[area].poSpeed}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{volumeStats[area].poParcel}</td>
                  <td className="px-6 py-4 text-center text-slate-800">{volumeStats[area].poIntl}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

// Component Helpers
const PerfButton = ({ label, value, total, color, icon, onClick }: any) => {
  const percentage = total > 0 ? Math.round((value / total) * 100) : 0;
  return (
    <button 
      onClick={onClick}
      className="group w-full p-4 rounded-xl border border-slate-100 bg-slate-50 hover:bg-white hover:border-red-200 hover:shadow-md transition-all duration-200 flex flex-col items-center justify-center text-center gap-1"
    >
      <div className="flex items-center gap-1.5 text-[10px] font-black text-slate-500 uppercase tracking-tighter transition-colors group-hover:text-red-700">
        {icon} {label}
      </div>
      <div className={`text-2xl font-black ${color}`}>{value} <span className="text-xs text-slate-400 font-medium">/ {total}</span></div>
      <div className="w-full h-1.5 bg-slate-200 rounded-full mt-2 overflow-hidden">
        <div className={`h-full bg-emerald-500 transition-all duration-500`} style={{ width: `${percentage}%` }}></div>
      </div>
      <div className="text-[9px] font-bold text-slate-400 mt-1 uppercase">{percentage}% Productivity</div>
    </button>
  );
};

