);

export default RSBTCellReport;

import React, { useMemo, useState, useRef } from 'react';
import { BookingDataRow, MasterDataRow } from '../types';
import { FileSpreadsheet, Download, Printer, Home, Landmark, Filter, Search, Mail, Package, Globe, CheckCircle2, ClipboardList } from 'lucide-react';
import { exportToPDF, exportToExcel, getProductCategory, formatCurrency } from '../utils';

interface RSBTCellReportProps {
  data: BookingDataRow[];
  masterData: MasterDataRow[];
}

type MailType = 'Speed Post' | 'Parcel' | 'International';
type BookingStatus = 'All' | 'Booked' | 'Not Booked';
type AreaFilter = 'All' | 'Rural' | 'Urban';
type OfficeTypeFilter = 'All' | 'P.O' | 'B.O';

const RSBTCellReport: React.FC<RSBTCellReportProps> = ({ data, masterData }) => {
  // 5 Filters State
  const [filterType, setFilterType] = useState<MailType>('Speed Post');
  const [filterSubDiv, setFilterSubDiv] = useState('');
  const [filterArea, setFilterArea] = useState<AreaFilter>('All');
  const [filterOfficeType, setFilterOfficeType] = useState<OfficeTypeFilter>('All');
  const [filterStatus, setFilterStatus] = useState<BookingStatus>('All');

  const detailRef = useRef<HTMLDivElement>(null);

  // 1. Volume Stats for the summary table
  const volumeStats = useMemo<any>(() => {
    const results: any = { Rural: {}, Urban: {}, Total: {} };
    const categories = [
      { id: 'boSpeed', type: 'B.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'boParcel', type: 'B.O', targetCat: 'Parcel' },
      { id: 'poSpeed', type: 'P.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'poParcel', type: 'P.O', targetCat: 'Parcel' },
      { id: 'poIntl', type: 'P.O', targetCat: 'International' },
    ];

    categories.forEach(cat => {
      results.Rural[cat.id] = 0; results.Urban[cat.id] = 0; results.Total[cat.id] = 0;
      data.forEach(row => {
        const rowType = row.officeType === 'B.O' ? 'B.O' : 'P.O';
        const rowCat = getProductCategory(row.productName);
        let isMatch = rowCat === cat.targetCat;
        if (cat.isSpeed && isMatch) isMatch = row.productName.toLowerCase().includes('speed post');
        if (isMatch && rowType === cat.type) {
          const area = row.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
          results[area][cat.id] += row.articles;
          results.Total[cat.id] += row.articles;
        }
      });
    });
    return results;
  }, [data]);

  // 2. Performance Summaries
  const performanceStats = useMemo(() => {
    const stats = {
      bo: { total: 0, bookedSP: 0, bookedPar: 0 },
      po: { total: 0, bookedSP: 0, bookedPar: 0 },
    };

    const spBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Domestic' && r.productName.toLowerCase().includes('speed post')).map(r => r.officeId));
    const parBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Parcel').map(r => r.officeId));

    masterData.forEach(m => {
      const isBO = m.officeType === 'B.O';
      if (isBO) {
        stats.bo.total++;
        if (spBookedIds.has(m.officeId)) stats.bo.bookedSP++;
        if (parBookedIds.has(m.officeId)) stats.bo.bookedPar++;
      } else {
        stats.po.total++;
        if (spBookedIds.has(m.officeId)) stats.po.bookedSP++;
        if (parBookedIds.has(m.officeId)) stats.po.bookedPar++;
      }
    });
    return stats;
  }, [data, masterData]);

  // 3. Main Filtered List (7 Columns Logic)
  const detailedReportList = useMemo(() => {
    // Current bookings based on Mail Type selection
    const typeBookings = data.filter(r => {
      const cat = getProductCategory(r.productName);
      if (filterType === 'Speed Post') return cat === 'Domestic' && r.productName.toLowerCase().includes('speed post');
      if (filterType === 'Parcel') return cat === 'Parcel';
      return cat === 'International';
    });

    const bookingMap = new Map<string, { articles: number, postage: number }>();
    typeBookings.forEach(b => {
      const current = bookingMap.get(b.officeId) || { articles: 0, postage: 0 };
      current.articles += b.articles;
      current.postage += b.totalAmount;
      bookingMap.set(b.officeId, current);
    });

    return masterData
      .map(office => {
        const booking = bookingMap.get(office.officeId);
        return {
          ...office,
          articles: booking ? booking.articles : 0,
          postage: booking ? booking.postage : 0,
          isBooked: !!booking
        };
      })
      .filter(office => {
        // Filter 1: Sub-Division
        if (filterSubDiv && !office.subDivisionName.toLowerCase().includes(filterSubDiv.toLowerCase())) return false;

        // Filter 2: Rural/Urban
        if (filterArea !== 'All' && office.areaType !== filterArea) return false;

        // Filter 3: PO/BO
        if (filterOfficeType !== 'All' && office.officeType !== filterOfficeType) return false;

        // Filter 4: Booking Status
        if (filterStatus === 'Booked' && !office.isBooked) return false;
        if (filterStatus === 'Not Booked' && office.isBooked) return false;

        return true;
      })
      .sort((a, b) => a.officeName.localeCompare(b.officeName));
  }, [masterData, data, filterType, filterSubDiv, filterArea, filterOfficeType, filterStatus]);

  const handleQuickAction = (type: MailType, status: BookingStatus, officeType: OfficeTypeFilter) => {
    setFilterType(type);
    setFilterStatus(status);
    setFilterOfficeType(officeType);
    setTimeout(() => {
      detailRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  const exportReport = (format: 'pdf' | 'excel') => {
    const fileName = `RSBT_Detailed_${filterType}_${filterOfficeType}_${filterStatus}`;
    const headers = ['Sl No', 'Name of the Office', 'Office ID', 'Sub-Division Name', 'Office Type', 'Number', 'Postage'];

    const rows = detailedReportList.map((row, i) => [
      i + 1,
      row.officeName,
      row.officeId,
      row.subDivisionName,
      row.officeType,
      row.articles,
      row.postage.toFixed(2)
    ]);

    if (format === 'excel') {
      const excelData = detailedReportList.map((row, i) => ({
        'Sl No': i + 1,
        'Name of the Office': row.officeName,
        'Office ID': row.officeId,
        'Sub-Division Name': row.subDivisionName,
        'Office Type': row.officeType,
        'Number (Articles)': row.articles,
        'Postage': row.postage
      }));
      exportToExcel(excelData, fileName);
    } else {
      exportToPDF(headers, rows, `${filterType} Detailed Monitoring Report`, true);
    }
  };

  const getSubDivisions = useMemo(() => {
    return Array.from(new Set(masterData.map(m => m.subDivisionName))).sort();
  }, [masterData]);

  return (
    <div className="space-y-8 pb-10">
      {/* QUICK STAT CARDS */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2 border-b border-slate-100 pb-2">
            <div className="p-1.5 bg-amber-50 text-amber-600 rounded-lg"><Home size={18}/></div>
            Branch Office (BO) Performance
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <QuickStatButton 
              label="Speed Post Booked" 
              value={performanceStats.bo.bookedSP} 
              total={performanceStats.bo.total} 
              icon={<Mail size={16}/>}
              onClick={() => handleQuickAction('Speed Post', 'Booked', 'B.O')}
            />
            <QuickStatButton 
              label="Parcel Booked" 
              value={performanceStats.bo.bookedPar} 
              total={performanceStats.bo.total} 
              icon={<Package size={16}/>}
              onClick={() => handleQuickAction('Parcel', 'Booked', 'B.O')}
            />
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2 border-b border-slate-100 pb-2">
            <div className="p-1.5 bg-blue-50 text-blue-600 rounded-lg"><Landmark size={18}/></div>
            Sub Office / PO Performance
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <QuickStatButton 
              label="Speed Post Booked" 
              value={performanceStats.po.bookedSP} 
              total={performanceStats.po.total} 
              icon={<Mail size={16}/>}
              onClick={() => handleQuickAction('Speed Post', 'Booked', 'P.O')}
            />
            <QuickStatButton 
              label="Parcel Booked" 
              value={performanceStats.po.bookedPar} 
              total={performanceStats.po.total} 
              icon={<Package size={16}/>}
              onClick={() => handleQuickAction('Parcel', 'Booked', 'P.O')}
            />
          </div>
        </div>
      </div>

      {/* DETAILED MONITORING SECTION */}
      <div ref={detailRef} className="bg-white p-6 rounded-2xl shadow-lg border border-slate-200 space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div>
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2">
              <ClipboardList className="text-[#CE2029]" /> Detailed Monitoring Dashboard
            </h2>
            <p className="text-[11px] text-slate-500 font-medium">Filtering {detailedReportList.length} offices based on current criteria</p>
          </div>
          <div className="flex gap-2">
             <button onClick={() => exportReport('excel')} className="flex items-center gap-1.5 px-3 py-2 bg-green-50 text-green-700 rounded-lg border border-green-200 hover:bg-green-100 transition-all text-xs font-bold">
               <Download size={14}/> EXCEL
             </button>
             <button onClick={() => exportReport('pdf')} className="flex items-center gap-1.5 px-3 py-2 bg-red-50 text-[#CE2029] rounded-lg border border-red-200 hover:bg-red-100 transition-all text-xs font-bold">
               <Printer size={14}/> PDF REPORT
             </button>
          </div>
        </div>

        {/* 5 SEARCH FILTERS */}
        <div className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-5 gap-3 p-4 bg-slate-50 rounded-xl border border-slate-200 shadow-inner">
           {/* 1. Sub-Division */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">1. Sub-Division</label>
              <div className="relative">
                <input 
                  type="text"
                  placeholder="All Sub-Div..."
                  value={filterSubDiv}
                  onChange={e => setFilterSubDiv(e.target.value)}
                  className="w-full bg-white border border-slate-200 rounded-md pl-2 pr-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
                  list="subdiv-opts"
                />
                <datalist id="subdiv-opts">
                  {getSubDivisions.map(s => <option key={s} value={s} />)}
                </datalist>
              </div>
           </div>

           {/* 2. Rural/Urban */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">2. Rural/Urban</label>
              <select 
                value={filterArea} 
                onChange={e => setFilterArea(e.target.value as AreaFilter)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Areas</option>
                <option value="Rural">Rural Only</option>
                <option value="Urban">Urban Only</option>
              </select>
           </div>

           {/* 3. Booked/Not Booked */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">3. Status</label>
              <select 
                value={filterStatus} 
                onChange={e => setFilterStatus(e.target.value as BookingStatus)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Offices</option>
                <option value="Booked">Booked Only</option>
                <option value="Not Booked">Not Booked Only</option>
              </select>
           </div>

           {/* 4. Type (Mail Type) */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">4. Mail Type</label>
              <select 
                value={filterType} 
                onChange={e => setFilterType(e.target.value as MailType)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="Speed Post">Speed Post</option>
                <option value="Parcel">Parcel</option>
                <option value="International">International</option>
              </select>
           </div>

           {/* 5. PO/BO */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">5. PO/BO</label>
              <select 
                value={filterOfficeType} 
                onChange={e => setFilterOfficeType(e.target.value as OfficeTypeFilter)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Types</option>
                <option value="P.O">P.O Only</option>
                <option value="B.O">B.O Only</option>
              </select>
           </div>
        </div>

        {/* 7-COLUMN TABLE */}
        <div className="overflow-hidden rounded-xl border border-slate-200 shadow-inner">
           <div className="overflow-x-auto max-h-[500px] custom-scrollbar">
             <table className="w-full text-xs text-left">
               <thead className="bg-slate-800 text-white font-black uppercase tracking-wider sticky top-0 z-10">
                 <tr>
                    <th className="px-4 py-3 border-r border-slate-700 w-16">Sl No</th>
                    <th className="px-4 py-3 border-r border-slate-700">Name of the Office</th>
                    <th className="px-4 py-3 border-r border-slate-700">Office ID</th>
                    <th className="px-4 py-3 border-r border-slate-700">Sub-Division Name</th>
                    <th className="px-4 py-3 border-r border-slate-700 text-center">Office Type</th>
                    <th className="px-4 py-3 border-r border-slate-700 text-center">Number</th>
                    <th className="px-4 py-3 text-right">Postage</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-100 bg-white">
                 {detailedReportList.map((row, idx) => (
                   <tr key={row.officeId} className="hover:bg-slate-50 transition-colors">
                     <td className="px-4 py-3 text-slate-400 font-bold">{idx + 1}</td>
                     <td className="px-4 py-3 font-bold text-slate-800">{row.officeName}</td>
                     <td className="px-4 py-3 text-slate-500 font-mono text-[10px]">{row.officeId}</td>
                     <td className="px-4 py-3 text-slate-600 font-medium">{row.subDivisionName}</td>
                     <td className="px-4 py-3 text-center">
                        <span className={`px-2 py-0.5 rounded text-[9px] font-black border ${row.officeType === 'B.O' ? 'bg-amber-50 text-amber-600 border-amber-100' : 'bg-blue-50 text-blue-600 border-blue-100'}`}>
                          {row.officeType}
                        </span>
                     </td>
                     <td className={`px-4 py-3 text-center font-black ${row.articles > 0 ? 'text-blue-700' : 'text-slate-300'}`}>
                        {row.articles}
                     </td>
                     <td className="px-4 py-3 text-right font-black text-slate-800">
                        {row.postage > 0 ? formatCurrency(row.postage) : '-'}
                     </td>
                   </tr>
                 ))}
                 {detailedReportList.length === 0 && (
                   <tr>
                     <td colSpan={7} className="px-4 py-16 text-center text-slate-400 italic font-medium bg-slate-50">
                        No results match your selected filters.
                     </td>
                   </tr>
                 )}
               </tbody>
               {detailedReportList.length > 0 && (
                 <tfoot className="bg-slate-800 text-white font-black sticky bottom-0 z-10 border-t border-slate-700 shadow-[0_-2px_10px_rgba(0,0,0,0.1)]">
                    <tr>
                       <td colSpan={5} className="px-4 py-4 text-center text-[10px] tracking-widest uppercase">Page Total Summary</td>
                       <td className="px-4 py-4 text-center text-base">{detailedReportList.reduce((acc, r) => acc + r.articles, 0)}</td>
                       <td className="px-4 py-4 text-right text-base">{formatCurrency(detailedReportList.reduce((acc, r) => acc + r.postage, 0))}</td>
                    </tr>
                 </tfoot>
               )}
             </table>
           </div>
        </div>
      </div>

      {/* RSBT VOLUME SUMMARY SECTION */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <h2 className="text-lg font-black text-slate-800 flex items-center gap-2 mb-6">
          <FileSpreadsheet size={20} className="text-[#CE2029]" /> RSBT Cell Volume Matrix
        </h2>
        <div className="overflow-x-auto rounded-xl border border-slate-200">
          <table className="w-full text-xs text-left">
            <thead className="bg-slate-50 text-slate-500 font-black uppercase tracking-tighter text-[10px]">
              <tr>
                <th className="px-6 py-4 border-b">Category / Area</th>
                <th className="px-6 py-4 border-b text-center">BO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">BO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">PO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO International</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {['Rural', 'Urban', 'Total'].map((area) => (
                <tr key={area} className={`${area === 'Total' ? 'bg-slate-50 font-black text-slate-900' : 'text-slate-700 hover:bg-slate-50'} transition-colors`}>
                  <td className="px-6 py-4 font-bold">{area}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].boSpeed}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].boParcel}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].poSpeed}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].poParcel}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].poIntl}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

const QuickStatButton = ({ label, value, total, icon, onClick }: any) => {
  const percentage = total > 0 ? Math.round((value / total) * 100) : 0;
  return (
    <button 
      onClick={onClick}
      className="group w-full p-4 rounded-xl border border-slate-100 bg-slate-50 hover:bg-white hover:border-red-200 hover:shadow-md transition-all flex flex-col items-center justify-center text-center gap-1"
    >
      <div className="flex items-center gap-1.5 text-[9px] font-black text-slate-400 uppercase tracking-tighter group-hover:text-red-700 transition-colors">
        {icon} {label}
      </div>
      <div className="text-xl font-black text-slate-800">{value} <span className="text-[10px] text-slate-400 font-medium">/ {total}</span></div>
      <div className="w-full h-1 bg-slate-200 rounded-full mt-2 overflow-hidden">
        <div className="h-full bg-emerald-500 transition-all duration-700" style={{ width: `${percentage}%` }}></div>
      </div>
      <div className="text-[8px] font-black text-slate-400 mt-1 uppercase tracking-widest">{percentage}% Coverage</div>
    </button>
  );
};

export default RSBTCellReport;

import React, { useMemo, useState, useRef } from 'react';
import { BookingDataRow, MasterDataRow } from '../types';
import { FileSpreadsheet, Download, Printer, Home, Landmark, Filter, Search, Mail, Package, Globe, CheckCircle2, ClipboardList, RefreshCw } from 'lucide-react';
import { exportToPDF, exportToExcel, getProductCategory, formatCurrency } from '../utils';

interface RSBTCellReportProps {
  data: BookingDataRow[];
  masterData: MasterDataRow[];
}

type MailType = 'Speed Post' | 'Parcel' | 'International';
type BookingStatus = 'All' | 'Booked' | 'Not Booked';
type AreaFilter = 'All' | 'Rural' | 'Urban';
type OfficeTypeFilter = 'All' | 'P.O' | 'B.O';

const RSBTCellReport: React.FC<RSBTCellReportProps> = ({ data, masterData }) => {
  // 5 Filters State
  const [filterType, setFilterType] = useState<MailType>('Speed Post');
  const [filterSubDiv, setFilterSubDiv] = useState('');
  const [filterArea, setFilterArea] = useState<AreaFilter>('All');
  const [filterOfficeType, setFilterOfficeType] = useState<OfficeTypeFilter>('All');
  const [filterStatus, setFilterStatus] = useState<BookingStatus>('All');

  const detailRef = useRef<HTMLDivElement>(null);

  const resetFilters = () => {
    setFilterType('Speed Post');
    setFilterSubDiv('');
    setFilterArea('All');
    setFilterOfficeType('All');
    setFilterStatus('All');
  };

  // 1. Volume Stats for the summary table
  const volumeStats = useMemo<any>(() => {
    const results: any = { Rural: {}, Urban: {}, Total: {} };
    const categories = [
      { id: 'boSpeed', type: 'B.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'boParcel', type: 'B.O', targetCat: 'Parcel' },
      { id: 'poSpeed', type: 'P.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'poParcel', type: 'P.O', targetCat: 'Parcel' },
      { id: 'poIntl', type: 'P.O', targetCat: 'International' },
    ];

    categories.forEach(cat => {
      results.Rural[cat.id] = 0; results.Urban[cat.id] = 0; results.Total[cat.id] = 0;
      data.forEach(row => {
        const rowType = row.officeType === 'B.O' ? 'B.O' : 'P.O';
        const rowCat = getProductCategory(row.productName);
        let isMatch = rowCat === cat.targetCat;
        if (cat.isSpeed && isMatch) isMatch = row.productName.toLowerCase().includes('speed post');
        if (isMatch && rowType === cat.type) {
          const area = row.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
          results[area][cat.id] += row.articles;
          results.Total[cat.id] += row.articles;
        }
      });
    });
    return results;
  }, [data]);

  // 2. Performance Summaries
  const performanceStats = useMemo(() => {
    const stats = {
      bo: { total: 0, bookedSP: 0, bookedPar: 0 },
      po: { total: 0, bookedSP: 0, bookedPar: 0 },
    };

    const spBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Domestic' && r.productName.toLowerCase().includes('speed post')).map(r => r.officeId));
    const parBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Parcel').map(r => r.officeId));

    masterData.forEach(m => {
      const isBO = m.officeType === 'B.O';
      if (isBO) {
        stats.bo.total++;
        if (spBookedIds.has(m.officeId)) stats.bo.bookedSP++;
        if (parBookedIds.has(m.officeId)) stats.bo.bookedPar++;
      } else {
        stats.po.total++;
        if (spBookedIds.has(m.officeId)) stats.po.bookedSP++;
        if (parBookedIds.has(m.officeId)) stats.po.bookedPar++;
      }
    });
    return stats;
  }, [data, masterData]);

  // 3. Main Filtered List (7 Columns Logic)
  const detailedReportList = useMemo(() => {
    // Current bookings based on Mail Type selection
    const typeBookings = data.filter(r => {
      const cat = getProductCategory(r.productName);
      if (filterType === 'Speed Post') return cat === 'Domestic' && r.productName.toLowerCase().includes('speed post');
      if (filterType === 'Parcel') return cat === 'Parcel';
      return cat === 'International';
    });

    const bookingMap = new Map<string, { articles: number, postage: number }>();
    typeBookings.forEach(b => {
      const current = bookingMap.get(b.officeId) || { articles: 0, postage: 0 };
      current.articles += b.articles;
      current.postage += b.totalAmount;
      bookingMap.set(b.officeId, current);
    });

    return masterData
      .map(office => {
        const booking = bookingMap.get(office.officeId);
        return {
          ...office,
          articles: booking ? booking.articles : 0,
          postage: booking ? booking.postage : 0,
          isBooked: !!booking
        };
      })
      .filter(office => {
        // Filter 1: Sub-Division
        if (filterSubDiv && !office.subDivisionName.toLowerCase().includes(filterSubDiv.toLowerCase())) return false;

        // Filter 2: Rural/Urban
        if (filterArea !== 'All' && office.areaType !== filterArea) return false;

        // Filter 3: PO/BO
        if (filterOfficeType !== 'All' && office.officeType !== filterOfficeType) return false;

        // Filter 4: Booking Status
        if (filterStatus === 'Booked' && !office.isBooked) return false;
        if (filterStatus === 'Not Booked' && office.isBooked) return false;

        return true;
      })
      .sort((a, b) => a.officeName.localeCompare(b.officeName));
  }, [masterData, data, filterType, filterSubDiv, filterArea, filterOfficeType, filterStatus]);

  const handleQuickAction = (type: MailType, status: BookingStatus, officeType: OfficeTypeFilter) => {
    setFilterType(type);
    setFilterStatus(status);
    setFilterOfficeType(officeType);
    setTimeout(() => {
      detailRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  const exportReport = (format: 'pdf' | 'excel') => {
    const fileName = `RSBT_Detailed_${filterType}_${filterOfficeType}_${filterStatus}`;
    const headers = ['Sl No', 'Name of the Office', 'Office ID', 'Sub-Division Name', 'Office Type', 'Number', 'Postage'];

    const rows = detailedReportList.map((row, i) => [
      i + 1,
      row.officeName,
      row.officeId,
      row.subDivisionName,
      row.officeType,
      row.articles,
      row.postage.toFixed(2)
    ]);

    if (format === 'excel') {
      const excelData = detailedReportList.map((row, i) => ({
        'Sl No': i + 1,
        'Name of the Office': row.officeName,
        'Office ID': row.officeId,
        'Sub-Division Name': row.subDivisionName,
        'Office Type': row.officeType,
        'Number (Articles)': row.articles,
        'Postage': row.postage
      }));
      exportToExcel(excelData, fileName);
    } else {
      exportToPDF(headers, rows, `${filterType} Detailed Monitoring Report`, true);
    }
  };

  const getSubDivisions = useMemo(() => {
    return Array.from(new Set(masterData.map(m => m.subDivisionName))).sort();
  }, [masterData]);

  return (
    <div className="space-y-8 pb-10">
      {/* QUICK STAT CARDS */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2 border-b border-slate-100 pb-2">
            <div className="p-1.5 bg-amber-50 text-amber-600 rounded-lg"><Home size={18}/></div>
            Branch Office (BO) Performance
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <QuickStatButton 
              label="Speed Post Booked" 
              value={performanceStats.bo.bookedSP} 
              total={performanceStats.bo.total} 
              icon={<Mail size={16}/>}
              onClick={() => handleQuickAction('Speed Post', 'Booked', 'B.O')}
            />
            <QuickStatButton 
              label="Parcel Booked" 
              value={performanceStats.bo.bookedPar} 
              total={performanceStats.bo.total} 
              icon={<Package size={16}/>}
              onClick={() => handleQuickAction('Parcel', 'Booked', 'B.O')}
            />
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2 border-b border-slate-100 pb-2">
            <div className="p-1.5 bg-blue-50 text-blue-600 rounded-lg"><Landmark size={18}/></div>
            Sub Office / PO Performance
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <QuickStatButton 
              label="Speed Post Booked" 
              value={performanceStats.po.bookedSP} 
              total={performanceStats.po.total} 
              icon={<Mail size={16}/>}
              onClick={() => handleQuickAction('Speed Post', 'Booked', 'P.O')}
            />
            <QuickStatButton 
              label="Parcel Booked" 
              value={performanceStats.po.bookedPar} 
              total={performanceStats.po.total} 
              icon={<Package size={16}/>}
              onClick={() => handleQuickAction('Parcel', 'Booked', 'P.O')}
            />
          </div>
        </div>
      </div>

      {/* DETAILED MONITORING SECTION */}
      <div ref={detailRef} className="bg-white p-6 rounded-2xl shadow-lg border border-slate-200 space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div>
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2">
              <ClipboardList className="text-[#CE2029]" /> Detailed Monitoring Dashboard
            </h2>
            <p className="text-[11px] text-slate-500 font-medium">Filtering {detailedReportList.length} offices based on current criteria</p>
          </div>
          <div className="flex gap-2">
             <button onClick={resetFilters} className="flex items-center gap-1.5 px-3 py-2 bg-slate-100 text-slate-600 rounded-lg border border-slate-200 hover:bg-slate-200 transition-all text-xs font-bold shadow-sm">
               <RefreshCw size={14}/> RESET
             </button>
             <button onClick={() => exportReport('excel')} className="flex items-center gap-1.5 px-3 py-2 bg-green-50 text-green-700 rounded-lg border border-green-200 hover:bg-green-100 transition-all text-xs font-bold">
               <Download size={14}/> EXCEL
             </button>
             <button onClick={() => exportReport('pdf')} className="flex items-center gap-1.5 px-3 py-2 bg-red-50 text-[#CE2029] rounded-lg border border-red-200 hover:bg-red-100 transition-all text-xs font-bold">
               <Printer size={14}/> PDF REPORT
             </button>
          </div>
        </div>

        {/* 5 SEARCH FILTERS */}
        <div className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-5 gap-3 p-4 bg-slate-50 rounded-xl border border-slate-200 shadow-inner">
           {/* 1. Sub-Division */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">1. Sub-Division</label>
              <div className="relative">
                <input 
                  type="text"
                  placeholder="All Sub-Div..."
                  value={filterSubDiv}
                  onChange={e => setFilterSubDiv(e.target.value)}
                  className="w-full bg-white border border-slate-200 rounded-md pl-2 pr-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
                  list="subdiv-opts"
                />
                <datalist id="subdiv-opts">
                  {getSubDivisions.map(s => <option key={s} value={s} />)}
                </datalist>
              </div>
           </div>

           {/* 2. Rural/Urban */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">2. Rural/Urban</label>
              <select 
                value={filterArea} 
                onChange={e => setFilterArea(e.target.value as AreaFilter)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Areas</option>
                <option value="Rural">Rural Only</option>
                <option value="Urban">Urban Only</option>
              </select>
           </div>

           {/* 3. Booked/Not Booked */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">3. Status</label>
              <select 
                value={filterStatus} 
                onChange={e => setFilterStatus(e.target.value as BookingStatus)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Offices</option>
                <option value="Booked">Booked Only</option>
                <option value="Not Booked">Not Booked Only</option>
              </select>
           </div>

           {/* 4. Type (Mail Type) */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">4. Mail Type</label>
              <select 
                value={filterType} 
                onChange={e => setFilterType(e.target.value as MailType)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="Speed Post">Speed Post</option>
                <option value="Parcel">Parcel</option>
                <option value="International">International</option>
              </select>
           </div>

           {/* 5. PO/BO */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">5. PO/BO</label>
              <select 
                value={filterOfficeType} 
                onChange={e => setFilterOfficeType(e.target.value as OfficeTypeFilter)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Types</option>
                <option value="P.O">P.O Only</option>
                <option value="B.O">B.O Only</option>
              </select>
           </div>
        </div>

        {/* 7-COLUMN TABLE */}
        <div className="overflow-hidden rounded-xl border border-slate-200 shadow-inner">
           <div className="overflow-x-auto max-h-[500px] custom-scrollbar">
             <table className="w-full text-xs text-left">
               <thead className="bg-slate-800 text-white font-black uppercase tracking-wider sticky top-0 z-10">
                 <tr>
                    <th className="px-4 py-3 border-r border-slate-700 w-16">Sl No</th>
                    <th className="px-4 py-3 border-r border-slate-700">Name of the Office</th>
                    <th className="px-4 py-3 border-r border-slate-700">Office ID</th>
                    <th className="px-4 py-3 border-r border-slate-700">Sub-Division Name</th>
                    <th className="px-4 py-3 border-r border-slate-700 text-center">Office Type</th>
                    <th className="px-4 py-3 border-r border-slate-700 text-center">Number</th>
                    <th className="px-4 py-3 text-right">Postage</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-100 bg-white">
                 {detailedReportList.map((row, idx) => (
                   <tr key={row.officeId} className="hover:bg-slate-50 transition-colors">
                     <td className="px-4 py-3 text-slate-400 font-bold">{idx + 1}</td>
                     <td className="px-4 py-3 font-bold text-slate-800">{row.officeName}</td>
                     <td className="px-4 py-3 text-slate-500 font-mono text-[10px]">{row.officeId}</td>
                     <td className="px-4 py-3 text-slate-600 font-medium">{row.subDivisionName}</td>
                     <td className="px-4 py-3 text-center">
                        <span className={`px-2 py-0.5 rounded text-[9px] font-black border ${row.officeType === 'B.O' ? 'bg-amber-50 text-amber-600 border-amber-100' : 'bg-blue-50 text-blue-600 border-blue-100'}`}>
                          {row.officeType}
                        </span>
                     </td>
                     <td className={`px-4 py-3 text-center font-black ${row.articles > 0 ? 'text-blue-700' : 'text-slate-300'}`}>
                        {row.articles}
                     </td>
                     <td className="px-4 py-3 text-right font-black text-slate-800">
                        {row.postage > 0 ? formatCurrency(row.postage) : '-'}
                     </td>
                   </tr>
                 ))}
                 {detailedReportList.length === 0 && (
                   <tr>
                     <td colSpan={7} className="px-4 py-16 text-center text-slate-400 italic font-medium bg-slate-50">
                        No results match your selected filters.
                     </td>
                   </tr>
                 )}
               </tbody>
               {detailedReportList.length > 0 && (
                 <tfoot className="bg-slate-800 text-white font-black sticky bottom-0 z-10 border-t border-slate-700 shadow-[0_-2px_10px_rgba(0,0,0,0.1)]">
                    <tr>
                       <td colSpan={5} className="px-4 py-4 text-center text-[10px] tracking-widest uppercase">Page Total Summary</td>
                       <td className="px-4 py-4 text-center text-base">{detailedReportList.reduce((acc, r) => acc + r.articles, 0)}</td>
                       <td className="px-4 py-4 text-right text-base">{formatCurrency(detailedReportList.reduce((acc, r) => acc + r.postage, 0))}</td>
                    </tr>
                 </tfoot>
               )}
             </table>
           </div>
        </div>
      </div>

      {/* RSBT VOLUME SUMMARY SECTION */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <h2 className="text-lg font-black text-slate-800 flex items-center gap-2 mb-6">
          <FileSpreadsheet size={20} className="text-[#CE2029]" /> RSBT Cell Volume Matrix
        </h2>
        <div className="overflow-x-auto rounded-xl border border-slate-200">
          <table className="w-full text-xs text-left">
            <thead className="bg-slate-50 text-slate-500 font-black uppercase tracking-tighter text-[10px]">
              <tr>
                <th className="px-6 py-4 border-b">Category / Area</th>
                <th className="px-6 py-4 border-b text-center">BO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">BO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">PO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO International</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {['Rural', 'Urban', 'Total'].map((area) => (
                <tr key={area} className={`${area === 'Total' ? 'bg-slate-50 font-black text-slate-900' : 'text-slate-700 hover:bg-slate-50'} transition-colors`}>
                  <td className="px-6 py-4 font-bold">{area}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].boSpeed}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].boParcel}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].poSpeed}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].poParcel}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].poIntl}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

const QuickStatButton = ({ label, value, total, icon, onClick }: any) => {
  const percentage = total > 0 ? Math.round((value / total) * 100) : 0;
  return (
    <button 
      onClick={onClick}
      className="group w-full p-4 rounded-xl border border-slate-100 bg-slate-50 hover:bg-white hover:border-red-200 hover:shadow-md transition-all flex flex-col items-center justify-center text-center gap-1"
    >
      <div className="flex items-center gap-1.5 text-[9px] font-black text-slate-400 uppercase tracking-tighter group-hover:text-red-700 transition-colors">
        {icon} {label}
      </div>
      <div className="text-xl font-black text-slate-800">{value} <span className="text-[10px] text-slate-400 font-medium">/ {total}</span></div>
      <div className="w-full h-1 bg-slate-200 rounded-full mt-2 overflow-hidden">
        <div className="h-full bg-emerald-500 transition-all duration-700" style={{ width: `${percentage}%` }}></div>
      </div>
      <div className="text-[8px] font-black text-slate-400 mt-1 uppercase tracking-widest">{percentage}% Coverage</div>
    </button>
  );
};

export default RSBTCellReport;

import React, { useState, useMemo } from 'react';
import { BookingDataRow, ProductGroup, AnalysisSummary, OfficeSummary, MasterDataRow } from '../types';
import { PRODUCTS } from '../constants';
import { formatCurrency, exportToPDF, exportToExcel, getProductCategory } from '../utils';
import { BarChart, IndianRupee, Package, Globe, FileText, Download, Mail, CheckCircle, Printer, Palette, RefreshCw } from 'lucide-react';

interface DashboardAnalysisProps {
  data: BookingDataRow[];
  masterData: MasterDataRow[];
}

// Helper for PDF currency to ensure Rs. is used instead of symbol
const formatCurrencyPDF = (amount: number) => {
  return `Rs. ${amount.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
};

// Canonical Mapping Table: Groups variants found in raw data to UI Card names
const PRODUCT_CANONICAL_MAP: Record<string, string> = {
  // Retail Parcel Variants -> India Post Parcel Retail
  'indiapost parcel retail': 'India Post Parcel Retail',
  'indiapost parcel retail ': 'India Post Parcel Retail',
  'india post parcel retail': 'India Post Parcel Retail',
  'speedpost parcel retail': 'India Post Parcel Retail',
  'speed post parcel retail': 'India Post Parcel Retail',

  // Speed Post Variants
  'inland speed post': 'Inland Speed Post',
  'inland speed post document': 'Inland Speed Post Document',

  // Others
  'registered letter': 'Registered Letter',
  'gyan post': 'Gyan Post',
  'indiapost parcel contractual': 'Indiapost Parcel Contractual',
  'speed post parcel domestic': 'Speed Post Parcel Domestic',
  'international air parcel': 'International Air Parcel',
  'international speed post document': 'International Speed Post Document',
  'international speed post merchandise': 'International Speed Post Merchandise',
  'registered foreign letter': 'Registered Foreign Letter',
  'registered international small packets': 'Registered International Small Packets'
};

const DashboardAnalysis: React.FC<DashboardAnalysisProps> = ({ data, masterData }) => {
  const [selectedContext, setSelectedContext] = useState<string | null>(null);
  const [contextType, setContextType] = useState<'Category' | 'Product' | null>(null);
  const [cardColors, setCardColors] = useState<Record<string, string>>({});

  const reloadDashboard = () => {
    setSelectedContext(null);
    setContextType(null);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleColorChange = (key: string, color: string) => {
    setCardColors(prev => ({ ...prev, [key]: color }));
  };

  // 1. Determine Canonical Names for all data points
  const enrichedDataWithCanonical = useMemo(() => {
    return data.map(row => {
      const normalizedName = row.productName.toLowerCase().trim();
      const canonicalName = PRODUCT_CANONICAL_MAP[normalizedName] || row.productName;
      return { ...row, canonicalName };
    });
  }, [data]);

  // 2. Aggregate Product Card Stats (Product Performance)
  const productStats = useMemo(() => {
    const stats: Record<string, { articles: number; postage: number; revenue: number }> = {};
    PRODUCTS.ALL.forEach(p => stats[p] = { articles: 0, postage: 0, revenue: 0 });

    enrichedDataWithCanonical.forEach(row => {
      if (stats[row.canonicalName]) {
        stats[row.canonicalName].articles += row.articles;
        stats[row.canonicalName].postage += row.postage;
        stats[row.canonicalName].revenue += row.totalAmount;
      }
    });
    return stats;
  }, [enrichedDataWithCanonical]);

  // 3. Aggregate Vertical Stats (Domestic, Parcel, International)
  // These SUM UP from the product cards logic to ensure strict consistency.
  const revenueStats = useMemo(() => {
    const sumForList = (list: string[]) => {
      return list.reduce((acc, p) => {
        const s = productStats[p] || { articles: 0, postage: 0, revenue: 0 };
        return {
          articles: acc.articles + s.articles,
          postage: acc.postage + s.postage,
          revenue: acc.revenue + s.revenue
        };
      }, { articles: 0, postage: 0, revenue: 0 });
    };

    const domestic = sumForList(PRODUCTS.DOMESTIC);
    const parcel = sumForList(PRODUCTS.PARCEL);
    const international = sumForList(PRODUCTS.INTERNATIONAL);

    // TOTAL REVENUE = sum of these three verticals
    return {
      total: {
        articles: domestic.articles + parcel.articles + international.articles,
        postage: domestic.postage + parcel.postage + international.postage,
        revenue: domestic.revenue + parcel.revenue + international.revenue
      },
      domestic,
      parcel,
      international
    };
  }, [productStats]);

  // 4. Logic for Drill-down Reports
  const reportData = useMemo(() => {
    if (!selectedContext) return null;

    let filteredData = [];
    if (contextType === 'Category') {
      if (selectedContext === ProductGroup.ALL) {
        filteredData = enrichedDataWithCanonical;
      } else if (selectedContext === ProductGroup.DOMESTIC) {
        filteredData = enrichedDataWithCanonical.filter(d => getProductCategory(d.productName) === 'Domestic');
      } else if (selectedContext === ProductGroup.PARCEL) {
        filteredData = enrichedDataWithCanonical.filter(d => getProductCategory(d.productName) === 'Parcel');
      } else if (selectedContext === ProductGroup.INTERNATIONAL) {
        filteredData = enrichedDataWithCanonical.filter(d => getProductCategory(d.productName) === 'International');
      }
    } else {
      filteredData = enrichedDataWithCanonical.filter(d => d.canonicalName === selectedContext);
    }

    // Sub-Division Wise
    const subDivMap = new Map<string, AnalysisSummary>();
    filteredData.forEach(row => {
      const name = row.subDivision || 'Unknown Sub-Division';
      const current = subDivMap.get(name) || { subDivisionName: name, articleCount: 0, postageAmount: 0, totalRevenue: 0 };
      current.articleCount += row.articles;
      current.postageAmount += row.postage;
      current.totalRevenue += row.totalAmount;
      subDivMap.set(name, current);
    });
    const subDivReport = Array.from(subDivMap.values()).sort((a,b) => b.totalRevenue - a.totalRevenue);

    // PO Wise
    const poMap = new Map<string, OfficeSummary>();
    filteredData.forEach(row => {
      const name = row.officeJurisdiction || 'Unknown Jurisdiction';
      const current = poMap.get(name) || { officeName: name, articleCount: 0, postageAmount: 0, totalRevenue: 0 };
      current.articleCount += row.articles;
      current.postageAmount += row.postage;
      current.totalRevenue += row.totalAmount;
      poMap.set(name, current);
    });
    const poReport = Array.from(poMap.values()).sort((a,b) => b.totalRevenue - a.totalRevenue);

    return { subDivReport, poReport };
  }, [enrichedDataWithCanonical, selectedContext, contextType]);

  // 5. Non-Booking Analysis
  const nonBookingStats = useMemo(() => {
    const bookedIds = new Set(data.map(r => r.officeId));
    const allBOs = masterData.filter(m => m.officeType === 'B.O');
    const allPOs = masterData.filter(m => m.officeType !== 'B.O'); 

    const notBookedBOs = allBOs.filter(m => !bookedIds.has(m.officeId));
    const notBookedPOs = allPOs.filter(m => !bookedIds.has(m.officeId));

    const sorter = (a: MasterDataRow, b: MasterDataRow) => {
      if (a.subDivisionName === b.subDivisionName) return a.officeName.localeCompare(b.officeName);
      return a.subDivisionName.localeCompare(b.subDivisionName);
    };

    return {
      bo: { total: allBOs.length, booked: allBOs.length - notBookedBOs.length, notBooked: notBookedBOs.length, list: [...notBookedBOs].sort(sorter) },
      po: { total: allPOs.length, booked: allPOs.length - notBookedPOs.length, notBooked: notBookedPOs.length, list: [...notBookedPOs].sort(sorter) }
    };
  }, [data, masterData]);

  const handleCardClick = (context: string, type: 'Category' | 'Product') => {
    setSelectedContext(context);
    setContextType(type);
    setTimeout(() => {
      document.getElementById('report-section')?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const exportReport = (type: 'pdf' | 'excel', reportType: 'subdiv' | 'po') => {
    if (!reportData) return;
    const isSubDiv = reportType === 'subdiv';
    const rawData = isSubDiv ? reportData.subDivReport : reportData.poReport;
    const fileName = `${selectedContext} - ${isSubDiv ? 'SubDivision' : 'PO'} Report`;

    if (type === 'excel') {
      const exportData = rawData.map(r => ({
        [isSubDiv ? 'Sub Division Name' : 'Office Name']: isSubDiv ? (r as AnalysisSummary).subDivisionName : (r as OfficeSummary).officeName,
        'No of Articles': r.articleCount,
        'Total Postage': r.postageAmount,
        'Total Revenue': r.totalRevenue
      }));
      exportToExcel(exportData, fileName);
    } else {
      const headers = isSubDiv 
        ? ['Sl No', 'Name of the Sub Division', 'No of Articles Booked', 'Total Postage Amount', 'Total Revenue']
        : ['Sl No', 'Name of the POs', 'No of Articles Booked', 'Total Postage Amount', 'Total Revenue'];

      const rows = rawData.map((row, i) => [
        i + 1,
        isSubDiv ? (row as AnalysisSummary).subDivisionName : (row as OfficeSummary).officeName,
        row.articleCount,
        formatCurrencyPDF(row.postageAmount),
        formatCurrencyPDF(row.totalRevenue)
      ]);

      const totalArts = rawData.reduce((s, c) => s + c.articleCount, 0);
      const totalPostage = rawData.reduce((s, c) => s + c.postageAmount, 0);
      const totalRevenue = rawData.reduce((s, c) => s + c.totalRevenue, 0);
      rows.push(['', 'TOTAL', totalArts, formatCurrencyPDF(totalPostage), formatCurrencyPDF(totalRevenue)]);

      exportToPDF(headers, rows, fileName);
    }
  };

  return (
    <div className="space-y-8 pb-10">

      {/* SECTION 1: REVENUE VERTICALS */}
      <section>
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <IndianRupee className="text-red-700" /> Revenue Verticals
          </h2>
          <button 
            onClick={reloadDashboard}
            className="flex items-center gap-1.5 px-3 py-1.5 bg-white text-slate-600 rounded-lg border border-slate-200 hover:bg-slate-50 transition-all text-xs font-bold shadow-sm"
          >
            <RefreshCw size={14}/> RELOAD ANALYSIS
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <DetailedCard 
            title={ProductGroup.ALL} 
            data={revenueStats.total} 
            icon={<BarChart className="text-red-700" />} 
            colorClass="bg-red-50 border-red-200 hover:border-red-400"
            active={selectedContext === ProductGroup.ALL}
            onClick={() => handleCardClick(ProductGroup.ALL, 'Category')}
            customColor={cardColors[ProductGroup.ALL]}
            onColorChange={(color: string) => handleColorChange(ProductGroup.ALL, color)}
          />
          <DetailedCard 
            title={ProductGroup.DOMESTIC} 
            data={revenueStats.domestic} 
            icon={<FileText className="text-emerald-700" />} 
            colorClass="bg-emerald-50 border-emerald-200 hover:border-emerald-400"
            active={selectedContext === ProductGroup.DOMESTIC}
            onClick={() => handleCardClick(ProductGroup.DOMESTIC, 'Category')}
            customColor={cardColors[ProductGroup.DOMESTIC]}
            onColorChange={(color: string) => handleColorChange(ProductGroup.DOMESTIC, color)}
          />
          <DetailedCard 
            title={ProductGroup.PARCEL} 
            data={revenueStats.parcel} 
            icon={<Package className="text-amber-700" />} 
            colorClass="bg-amber-50 border-amber-200 hover:border-amber-400"
            active={selectedContext === ProductGroup.PARCEL}
            onClick={() => handleCardClick(ProductGroup.PARCEL, 'Category')}
            customColor={cardColors[ProductGroup.PARCEL]}
            onColorChange={(color: string) => handleColorChange(ProductGroup.PARCEL, color)}
          />
          <DetailedCard 
            title={ProductGroup.INTERNATIONAL} 
            data={revenueStats.international} 
            icon={<Globe className="text-blue-700" />} 
            colorClass="bg-blue-50 border-blue-200 hover:border-blue-400"
            active={selectedContext === ProductGroup.INTERNATIONAL}
            onClick={() => handleCardClick(ProductGroup.INTERNATIONAL, 'Category')}
            customColor={cardColors[ProductGroup.INTERNATIONAL]}
            onColorChange={(color: string) => handleColorChange(ProductGroup.INTERNATIONAL, color)}
          />
        </div>
      </section>

      {/* SECTION 2: PRODUCT CARDS */}
      <section>
        <h2 className="text-xl font-bold text-slate-800 mb-4 flex items-center gap-2">
          <Mail className="text-red-700" /> Product Performance
        </h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
          {PRODUCTS.ALL.map((product, idx) => (
            <DetailedCard
              key={product}
              title={product}
              data={productStats[product]}
              icon={null} 
              colorClass={getProductColor(idx)}
              active={selectedContext === product}
              onClick={() => handleCardClick(product, 'Product')}
              compact
              customColor={cardColors[product]}
              onColorChange={(color: string) => handleColorChange(product, color)}
            />
