                    </div>
                </div>
                {error && <div className="mt-4 p-3 bg-red-50 text-[#CE2029] rounded-lg text-xs border border-red-100">{error}</div>}
              </div>
            </div>
          </div>
        )}

        {rawBookingData.length > 0 && (
          <div className="space-y-6">
            {activeTab === 'datasheet' && <DataSheet data={enrichedBookingData} />}
            {activeTab === 'dashboard' && <DashboardAnalysis data={enrichedBookingData} masterData={masterData} />}
            {activeTab === 'rsbt' && <RSBTCellReport data={enrichedBookingData} masterData={masterData} />}
            {activeTab === 'booking' && <BookingReport data={enrichedBookingData} />}
          </div>
        )}
      </main>
    </div>
  );
}

