const convertToExportUrl = (inputUrl: string): string | null => {
  const url = inputUrl.trim();
  if (url.includes('docs.google.com/spreadsheets') && !url.includes('export?format=csv')) {
      const idMatch = url.match(/\/d\/([a-zA-Z0-9-_]+)/);
      if (idMatch && idMatch[1]) {
          const id = idMatch[1];
          const gidMatch = url.match(/[#&?]gid=([0-9]+)/);
          const gid = gidMatch ? gidMatch[1] : null;
          return `https://docs.google.com/spreadsheets/d/${id}/export?format=csv${gid ? `&gid=${gid}` : ''}`;
      }
  }
  return url;
};

type AppTab = 'datasheet' | 'dashboard' | 'rsbt' | 'booking';

function App() {
  const [activeTab, setActiveTab] = useState<AppTab>('datasheet');
  const [rawBookingData, setRawBookingData] = useState<RawBookingRow[]>([]);
  const [masterData, setMasterData] = useState<MasterDataRow[]>(DEFAULT_MASTER_DATA);
  const [isMasterDataLoading, setIsMasterDataLoading] = useState(false);
  const [masterDataSource, setMasterDataSource] = useState<'Default' | 'Synced'>('Default');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [customUrl, setCustomUrl] = useState('');

  useEffect(() => {
    handleSyncMasterData(true);
  }, []);

  const handleSyncMasterData = async (silent = false) => {
    if (!silent) setIsMasterDataLoading(true);
    try {
      const data = await fetchMasterDataFromUrl(MASTER_DATA_URL);
      if (data && data.length > 0) {
        setMasterData(data);
        setMasterDataSource('Synced');
        if(!silent) alert(`Successfully synced ${data.length} master data records.`);
      }
    } catch (e) {
      console.error("Sync failed", e);
    } finally {
      if (!silent) setIsMasterDataLoading(false);
    }
  };

  const enrichedBookingData: BookingDataRow[] = useMemo(() => {
    return rawBookingData.map(row => {
      const master = masterData.find(m => m.officeId === row.officeId);
      return {
        ...row,
        subDivision: master?.subDivisionName || 'Unknown Sub-Division',
        headOffice: master?.headOfficeName || 'Unknown',
        officeType: master?.officeType || 'Unknown',
        officeJurisdiction: master?.officeJurisdiction || 'Unknown Jurisdiction',
        areaType: master?.areaType || 'Rural'
      };
    });
  }, [rawBookingData, masterData]);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setLoading(true);
    setError(null);
    try {
      const rawData = await parseExcelFile(file);
      if (rawData.length === 0) throw new Error("No valid booking data found.");
      setRawBookingData(rawData);
      setActiveTab('dashboard'); 
    } catch (err: any) {
      setError(err.message || "Failed to parse file");
      alert(err.message || "Failed to parse file");
    } finally {
      setLoading(false);
      event.target.value = ''; 
    }
  };

  const loadFromUrl = async (inputUrl: string) => {
    setLoading(true);
    setError(null);
    const fetchUrl = convertToExportUrl(inputUrl);
    if (!fetchUrl) {
       setLoading(false);
       setError("Invalid URL format.");
       return;
    }
    try {
      const rawData = await fetchBookingDataFromUrl(fetchUrl);
      if (rawData.length === 0) throw new Error("No data found in provided sheet.");
      setRawBookingData(rawData);
      setActiveTab('dashboard');
    } catch (err: any) {
      setError("Failed to fetch data. Ensure sheet is 'Published to web'.");
    } finally {
      setLoading(false);
    }
  };

  // Resets the app to the main screen so the user can re-upload or select new data
  const triggerReupload = () => {
    setRawBookingData([]);
    setError(null);
    setCustomUrl('');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const hardReload = () => {
    if (confirm("This will clear all uploaded data and reload the app. Continue?")) {
      window.location.reload();
    }
  };

  return (
    <div className="min-h-screen bg-slate-100 font-sans">
      <header className="bg-[#CE2029] shadow-md sticky top-0 z-50 transition-all"> 
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <button onClick={hardReload} title="Hard Reload App" className="w-10 h-10 bg-white rounded-lg flex items-center justify-center text-[#CE2029] font-bold shadow-sm hover:scale-110 transition-transform active:scale-95">IP</button>
             <h1 className="text-xl font-bold text-white tracking-wide hidden lg:block">Mail Booking Monitoring</h1>
          </div>

          <div className="flex items-center gap-2 sm:gap-4 overflow-x-auto no-scrollbar">
             {rawBookingData.length > 0 && (
               <button 
                onClick={triggerReupload} 
                className="flex items-center gap-1.5 px-3 py-1.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-all text-[10px] font-black uppercase shadow-lg border border-blue-400"
                title="Go to main screen to re-upload"
               >
                 <ArrowLeft size={14}/> Re-upload
               </button>
             )}

             <div className="hidden xl:flex items-center gap-2 text-xs text-white/90 bg-white/10 px-3 py-1.5 rounded-full backdrop-blur-sm border border-white/20">
               <span className={`w-2 h-2 rounded-full ${masterDataSource === 'Synced' ? 'bg-green-400' : 'bg-amber-400'}`}></span>
               <span>Master Data: {masterDataSource}</span>
               <button onClick={() => handleSyncMasterData()} className="ml-2 p-1 hover:bg-white/20 rounded-full transition-colors" title="Sync Master Data">
                 <RefreshCw size={12} className={isMasterDataLoading ? 'animate-spin' : ''}/>
               </button>
             </div>

             <div className="flex gap-1 bg-black/10 p-1 rounded-lg">
                <NavTab active={activeTab === 'datasheet'} onClick={() => setActiveTab('datasheet')} label="Data" icon={<Table size={16}/>}/>
                <NavTab active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} label="Analysis" icon={<LayoutDashboard size={16}/>}/>
                <NavTab active={activeTab === 'rsbt'} onClick={() => setActiveTab('rsbt'} label="RSBT Cell" icon={<ClipboardList size={16}/>}/>
                <NavTab active={activeTab === 'booking'} onClick={() => setActiveTab('booking')} label="Booking Report" icon={<FileText size={16}/>}/>
             </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {loading && (
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[100] flex items-center justify-center">
            <div className="bg-white p-6 rounded-2xl shadow-2xl flex flex-col items-center gap-4">
              <RefreshCw className="text-[#CE2029] animate-spin" size={40}/>
              <span className="font-bold text-slate-800 tracking-wider">Processing Data...</span>
            </div>
          </div>
        )}

        {rawBookingData.length === 0 && (
          <div className="flex flex-col items-center justify-center min-h-[80vh]">
            <div className="bg-white p-0 rounded-2xl shadow-xl border border-slate-200 max-w-3xl w-full overflow-hidden">
              <div className="h-2 bg-[#CE2029]"></div>
              <div className="p-8 md:p-10">
                <div className="flex flex-col items-center text-center mb-8">
                    <div className="w-16 h-16 bg-[#CE2029] text-white rounded-2xl flex items-center justify-center mb-4 shadow-lg"><UploadCloud size={32} /></div>
                    <h2 className="text-3xl font-extrabold text-slate-800 mb-2">Operations Dashboard</h2>
                    <p className="text-slate-500">Select a report or upload a booking data file.</p>
                </div>
                <button onClick={() => loadFromUrl(ANNUAL_REPORT.url)} disabled={loading} className="w-full relative overflow-hidden group rounded-xl shadow-md mb-8">
                    <div className="absolute inset-0 bg-gradient-to-r from-[#CE2029] to-[#B31B24]"></div>
                    <div className="relative p-6 flex items-center justify-between">
                         <div className="flex items-center gap-4">
                            <FileSpreadsheet size={28} className="text-white/80" />
                            <div className="text-left"><h3 className="text-white font-bold">Annual Report FY 2025-26</h3></div>
                         </div>
                         <div className="bg-white text-[#CE2029] px-4 py-2 rounded-lg font-bold text-sm">View Report</div>
                    </div>
                </button>
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4 mb-8">
                  {MONTHLY_REPORTS.map((month) => (
                    <button key={month.name} onClick={() => loadFromUrl(month.url)} disabled={loading} className="p-3 rounded-xl border border-slate-200 bg-slate-50 hover:border-[#CE2029] hover:bg-white transition-all text-center">
                      <span className="font-semibold text-slate-600 text-xs">{month.name}</span>
                    </button>
                  ))}
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <label className="cursor-pointer block">
                      <div className="flex items-center gap-3 p-4 border border-dashed border-slate-300 rounded-xl bg-slate-50 hover:bg-red-50 hover:border-red-300 transition-all h-full">
                          <UploadCloud size={20} className="text-slate-400"/>
                          <span className="text-sm font-semibold text-slate-700">Upload Excel/CSV</span>
                          <input type="file" accept=".csv, .xlsx, .xls" onChange={handleFileUpload} className="hidden" />
                      </div>
                    </label>
                    <div className="flex items-center gap-2 p-1 border border-slate-300 rounded-xl bg-white shadow-sm">
                        <input type="text" value={customUrl} onChange={(e) => setCustomUrl(e.target.value)} placeholder="Google Sheet Link..." className="flex-1 min-w-0 pl-3 py-2 text-sm bg-transparent border-none focus:ring-0 text-slate-800"/>
                        <button onClick={() => loadFromUrl(customUrl)} disabled={loading} className="bg-[#CE2029] text-white p-2 rounded-lg transition-colors"><LinkIcon size={18}/></button>
                    </div>
                </div>
                {error && <div className="mt-4 p-3 bg-red-50 text-[#CE2029] rounded-lg text-xs border border-red-100">{error}</div>}
              </div>
            </div>
          </div>
        )}

        {rawBookingData.length > 0 && (
          <div className="space-y-6">
            {activeTab === 'datasheet' && <DataSheet data={enrichedBookingData} onReupload={triggerReupload} />}
            {activeTab === 'dashboard' && <DashboardAnalysis data={enrichedBookingData} masterData={masterData} onReupload={triggerReupload} />}
            {activeTab === 'rsbt' && <RSBTCellReport data={enrichedBookingData} masterData={masterData} onReupload={triggerReupload} />}
            {activeTab === 'booking' && <BookingReport data={enrichedBookingData} onReupload={triggerReupload} />}
          </div>
        )}
      </main>
    </div>
  );
}

const NavTab = ({ active, onClick, label, icon }: any) => (
  <button onClick={onClick} className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${
    active ? 'bg-white text-[#CE2029] shadow-sm' : 'text-white/80 hover:text-white hover:bg-white/10'
  }`}>
    {icon} <span className="hidden sm:inline">{label}</span>
  </button>
);

export default App;

import React, { useMemo, useState, useRef } from 'react';
import { BookingDataRow, MasterDataRow } from '../types';
import { FileSpreadsheet, Download, Printer, Home, Landmark, Filter, Search, Mail, Package, Globe, CheckCircle2, ClipboardList, RefreshCw, UploadCloud } from 'lucide-react';
import { exportToPDF, exportToExcel, getProductCategory, formatCurrency } from '../utils';

interface RSBTCellReportProps {
  data: BookingDataRow[];
  masterData: MasterDataRow[];
  onReupload?: () => void;
}

type MailType = 'Speed Post' | 'Parcel' | 'International';
type BookingStatus = 'All' | 'Booked' | 'Not Booked';
type AreaFilter = 'All' | 'Rural' | 'Urban';
type OfficeTypeFilter = 'All' | 'P.O' | 'B.O';

const RSBTCellReport: React.FC<RSBTCellReportProps> = ({ data, masterData, onReupload }) => {
  // 5 Filters State
  const [filterType, setFilterType] = useState<MailType>('Speed Post');
  const [filterSubDiv, setFilterSubDiv] = useState('');
  const [filterArea, setFilterArea] = useState<AreaFilter>('All');
  const [filterOfficeType, setFilterOfficeType] = useState<OfficeTypeFilter>('All');
  const [filterStatus, setFilterStatus] = useState<BookingStatus>('All');

  const detailRef = useRef<HTMLDivElement>(null);

  const resetFilters = () => {
    setFilterType('Speed Post');
    setFilterSubDiv('');
    setFilterArea('All');
    setFilterOfficeType('All');
    setFilterStatus('All');
  };

  // 1. Volume Stats for the summary table
  const volumeStats = useMemo<any>(() => {
    const results: any = { Rural: {}, Urban: {}, Total: {} };
    const categories = [
      { id: 'boSpeed', type: 'B.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'boParcel', type: 'B.O', targetCat: 'Parcel' },
      { id: 'poSpeed', type: 'P.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'poParcel', type: 'P.O', targetCat: 'Parcel' },
      { id: 'poIntl', type: 'P.O', targetCat: 'International' },
    ];

    categories.forEach(cat => {
      results.Rural[cat.id] = 0; results.Urban[cat.id] = 0; results.Total[cat.id] = 0;
      data.forEach(row => {
        const rowType = row.officeType === 'B.O' ? 'B.O' : 'P.O';
        const rowCat = getProductCategory(row.productName);
        let isMatch = rowCat === cat.targetCat;
        if (cat.isSpeed && isMatch) isMatch = row.productName.toLowerCase().includes('speed post');
        if (isMatch && rowType === cat.type) {
          const area = row.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
          results[area][cat.id] += row.articles;
          results.Total[cat.id] += row.articles;
        }
      });
    });
    return results;
  }, [data]);

  // 2. Performance Summaries
  const performanceStats = useMemo(() => {
    const stats = {
      bo: { total: 0, bookedSP: 0, bookedPar: 0 },
      po: { total: 0, bookedSP: 0, bookedPar: 0 },
    };

    const spBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Domestic' && r.productName.toLowerCase().includes('speed post')).map(r => r.officeId));
    const parBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Parcel').map(r => r.officeId));

    masterData.forEach(m => {
      const isBO = m.officeType === 'B.O';
      if (isBO) {
        stats.bo.total++;
        if (spBookedIds.has(m.officeId)) stats.bo.bookedSP++;
        if (parBookedIds.has(m.officeId)) stats.bo.bookedPar++;
      } else {
        stats.po.total++;
        if (spBookedIds.has(m.officeId)) stats.po.bookedSP++;
        if (parBookedIds.has(m.officeId)) stats.po.bookedPar++;
      }
    });
    return stats;
  }, [data, masterData]);

  // 3. Main Filtered List (7 Columns Logic)
  const detailedReportList = useMemo(() => {
    // Current bookings based on Mail Type selection
    const typeBookings = data.filter(r => {
      const cat = getProductCategory(r.productName);
      if (filterType === 'Speed Post') return cat === 'Domestic' && r.productName.toLowerCase().includes('speed post');
      if (filterType === 'Parcel') return cat === 'Parcel';
      return cat === 'International';
    });

    const bookingMap = new Map<string, { articles: number, postage: number }>();
    typeBookings.forEach(b => {
      const current = bookingMap.get(b.officeId) || { articles: 0, postage: 0 };
      current.articles += b.articles;
      current.postage += b.totalAmount;
      bookingMap.set(b.officeId, current);
    });

    return masterData
      .map(office => {
        const booking = bookingMap.get(office.officeId);
        return {
          ...office,
          articles: booking ? booking.articles : 0,
          postage: booking ? booking.postage : 0,
          isBooked: !!booking
        };
      })
      .filter(office => {
        // Filter 1: Sub-Division
        if (filterSubDiv && !office.subDivisionName.toLowerCase().includes(filterSubDiv.toLowerCase())) return false;

        // Filter 2: Rural/Urban
        if (filterArea !== 'All' && office.areaType !== filterArea) return false;

        // Filter 3: PO/BO
        if (filterOfficeType !== 'All' && office.officeType !== filterOfficeType) return false;

        // Filter 4: Booking Status
        if (filterStatus === 'Booked' && !office.isBooked) return false;
        if (filterStatus === 'Not Booked' && office.isBooked) return false;

        return true;
      })
      .sort((a, b) => a.officeName.localeCompare(b.officeName));
  }, [masterData, data, filterType, filterSubDiv, filterArea, filterOfficeType, filterStatus]);

  const handleQuickAction = (type: MailType, status: BookingStatus, officeType: OfficeTypeFilter) => {
    setFilterType(type);
    setFilterStatus(status);
    setFilterOfficeType(officeType);
    setTimeout(() => {
      detailRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  const exportReport = (format: 'pdf' | 'excel') => {
    const reportTitle = `${filterType} Booking Report`;
    const headers = ['Sl No', 'Name of the Office', 'Office ID', 'Sub-Division Name', 'Office Type', 'Number', 'Postage'];

    const rows: any[] = detailedReportList.map((row, i) => [
      i + 1,
      row.officeName,
      row.officeId,
      row.subDivisionName,
      row.officeType,
      row.articles,
      row.postage.toFixed(2)
    ]);

    const totalArticles = detailedReportList.reduce((acc, r) => acc + r.articles, 0);
    const totalPostage = detailedReportList.reduce((acc, r) => acc + r.postage, 0);

    if (format === 'excel') {
      const excelData = detailedReportList.map((row, i) => ({
        'Sl No': i + 1,
        'Name of the Office': row.officeName,
        'Office ID': row.officeId,
        'Sub-Division Name': row.subDivisionName,
        'Office Type': row.officeType,
        'Number (Articles)': row.articles,
        'Postage': row.postage
      }));
      // Add total row to Excel
      excelData.push({
        'Sl No': '',
        'Name of the Office': 'GRAND TOTAL',
        'Office ID': '',
        'Sub-Division Name': '',
        'Office Type': '',
        'Number (Articles)': totalArticles,
        'Postage': totalPostage
      } as any);
      exportToExcel(excelData, reportTitle.replace(/\s+/g, '_'));
    } else {
      // Add total row for PDF
      rows.push(['', 'GRAND TOTAL', '', '', '', totalArticles, totalPostage.toFixed(2)]);
      exportToPDF(headers, rows, reportTitle, true);
    }
  };

  const exportMatrixReport = () => {
    const headers = ['Category / Area', 'BO Speed Post', 'BO Parcel', 'PO Speed Post', 'PO Parcel', 'PO International'];
    const rows = ['Rural', 'Urban', 'Total'].map(area => [
      area,
      volumeStats[area].boSpeed,
      volumeStats[area].boParcel,
      volumeStats[area].poSpeed,
      volumeStats[area].poParcel,
      volumeStats[area].poIntl,
    ]);
    exportToPDF(headers, rows, 'RSBT Cell Volume Matrix Report', true);
  };

  const getSubDivisions = useMemo(() => {
    return Array.from(new Set(masterData.map(m => m.subDivisionName))).sort();
  }, [masterData]);

  return (
    <div className="space-y-8 pb-10">
      {/* QUICK STAT CARDS */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2 border-b border-slate-100 pb-2">
            <div className="p-1.5 bg-amber-50 text-amber-600 rounded-lg"><Home size={18}/></div>
            Branch Office (BO) Performance
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <QuickStatButton 
              label="Speed Post Booked" 
              value={performanceStats.bo.bookedSP} 
              total={performanceStats.bo.total} 
              icon={<Mail size={16}/>}
              onClick={() => handleQuickAction('Speed Post', 'Booked', 'B.O')}
            />
            <QuickStatButton 
              label="Parcel Booked" 
              value={performanceStats.bo.bookedPar} 
              total={performanceStats.bo.total} 
              icon={<Package size={16}/>}
              onClick={() => handleQuickAction('Parcel', 'Booked', 'B.O')}
            />
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2 border-b border-slate-100 pb-2">
            <div className="p-1.5 bg-blue-50 text-blue-600 rounded-lg"><Landmark size={18}/></div>
            Sub Office / PO Performance
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <QuickStatButton 
              label="Speed Post Booked" 
              value={performanceStats.po.bookedSP} 
              total={performanceStats.po.total} 
              icon={<Mail size={16}/>}
              onClick={() => handleQuickAction('Speed Post', 'Booked', 'P.O')}
            />
            <QuickStatButton 
              label="Parcel Booked" 
              value={performanceStats.po.bookedPar} 
              total={performanceStats.po.total} 
              icon={<Package size={16}/>}
              onClick={() => handleQuickAction('Parcel', 'Booked', 'P.O')}
            />
          </div>
        </div>
      </div>

      {/* DETAILED MONITORING SECTION */}
      <div ref={detailRef} className="bg-white p-6 rounded-2xl shadow-lg border border-slate-200 space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div>
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2">
              <ClipboardList className="text-[#CE2029]" /> Detailed Monitoring Dashboard
            </h2>
            <p className="text-[11px] text-slate-500 font-medium">Filtering {detailedReportList.length} offices based on current criteria</p>
          </div>
          <div className="flex gap-2 flex-wrap">
             <button onClick={onReupload} className="flex items-center gap-1.5 px-3 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-all text-xs font-bold shadow-md">
               <UploadCloud size={14}/> RE-UPLOAD EXCEL
             </button>
             <button onClick={resetFilters} className="flex items-center gap-1.5 px-3 py-2 bg-slate-100 text-slate-600 rounded-lg border border-slate-200 hover:bg-slate-200 transition-all text-xs font-bold shadow-sm">
               <RefreshCw size={14}/> RESET
             </button>
             <button onClick={() => exportReport('excel')} className="flex items-center gap-1.5 px-3 py-2 bg-green-50 text-green-700 rounded-lg border border-green-200 hover:bg-green-100 transition-all text-xs font-bold">
               <Download size={14}/> EXCEL
             </button>
             <button onClick={() => exportReport('pdf')} className="flex items-center gap-1.5 px-3 py-2 bg-red-50 text-[#CE2029] rounded-lg border border-red-200 hover:bg-red-100 transition-all text-xs font-bold">
               <Printer size={14}/> PRINT REPORT
             </button>
          </div>
        </div>

        {/* 5 SEARCH FILTERS */}
        <div className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-5 gap-3 p-4 bg-slate-50 rounded-xl border border-slate-200 shadow-inner">
           {/* 1. Sub-Division */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">1. Sub-Division</label>
              <div className="relative">
                <input 
                  type="text"
                  placeholder="All Sub-Div..."
                  value={filterSubDiv}
                  onChange={e => setFilterSubDiv(e.target.value)}
                  className="w-full bg-white border border-slate-200 rounded-md pl-2 pr-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
                  list="subdiv-opts"
                />
                <datalist id="subdiv-opts">
                  {getSubDivisions.map(s => <option key={s} value={s} />)}
                </datalist>
              </div>
           </div>

           {/* 2. Rural/Urban */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">2. Rural/Urban</label>
              <select 
                value={filterArea} 
                onChange={e => setFilterArea(e.target.value as AreaFilter)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Areas</option>
                <option value="Rural">Rural Only</option>
                <option value="Urban">Urban Only</option>
              </select>
           </div>

           {/* 3. Booked/Not Booked */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">3. Status</label>
              <select 
                value={filterStatus} 
                onChange={e => setFilterStatus(e.target.value as BookingStatus)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Offices</option>
                <option value="Booked">Booked Only</option>
                <option value="Not Booked">Not Booked Only</option>
              </select>
           </div>

           {/* 4. Type (Mail Type) */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">4. Mail Type</label>
              <select 
                value={filterType} 
                onChange={e => setFilterType(e.target.value as MailType)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="Speed Post">Speed Post</option>
                <option value="Parcel">Parcel</option>
                <option value="International">International</option>
              </select>
           </div>

           {/* 5. PO/BO */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">5. PO/BO</label>
              <select 
                value={filterOfficeType} 
                onChange={e => setFilterOfficeType(e.target.value as OfficeTypeFilter)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Types</option>
                <option value="P.O">P.O Only</option>
                <option value="B.O">B.O Only</option>
              </select>
           </div>
        </div>

        {/* 7-COLUMN TABLE */}
        <div className="overflow-hidden rounded-xl border border-slate-200 shadow-inner">
           <div className="overflow-x-auto max-h-[500px] custom-scrollbar">
             <table className="w-full text-xs text-left">
               <thead className="bg-slate-800 text-white font-black uppercase tracking-wider sticky top-0 z-10">
                 <tr>
                    <th className="px-4 py-3 border-r border-slate-700 w-16">Sl No</th>
                    <th className="px-4 py-3 border-r border-slate-700">Name of the Office</th>
                    <th className="px-4 py-3 border-r border-slate-700">Office ID</th>
                    <th className="px-4 py-3 border-r border-slate-700">Sub-Division Name</th>
                    <th className="px-4 py-3 border-r border-slate-700 text-center">Office Type</th>
                    <th className="px-4 py-3 border-r border-slate-700 text-center">Number</th>
                    <th className="px-4 py-3 text-right">Postage</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-100 bg-white">
                 {detailedReportList.map((row, idx) => (
                   <tr key={row.officeId} className="hover:bg-slate-50 transition-colors">
                     <td className="px-4 py-3 text-slate-400 font-bold">{idx + 1}</td>
                     <td className="px-4 py-3 font-bold text-slate-800">{row.officeName}</td>
                     <td className="px-4 py-3 text-slate-500 font-mono text-[10px]">{row.officeId}</td>
                     <td className="px-4 py-3 text-slate-600 font-medium">{row.subDivisionName}</td>
                     <td className="px-4 py-3 text-center">
                        <span className={`px-2 py-0.5 rounded text-[9px] font-black border ${row.officeType === 'B.O' ? 'bg-amber-50 text-amber-600 border-amber-100' : 'bg-blue-50 text-blue-600 border-blue-100'}`}>
                          {row.officeType}
                        </span>
                     </td>
                     <td className={`px-4 py-3 text-center font-black ${row.articles > 0 ? 'text-blue-700' : 'text-slate-300'}`}>
                        {row.articles}
                     </td>
                     <td className="px-4 py-3 text-right font-black text-slate-800">
                        {row.postage > 0 ? formatCurrency(row.postage) : '-'}
                     </td>
                   </tr>
                 ))}
                 {detailedReportList.length === 0 && (
                   <tr>
                     <td colSpan={7} className="px-4 py-16 text-center text-slate-400 italic font-medium bg-slate-50">
                        No results match your selected filters.
                     </td>
                   </tr>
                 )}
               </tbody>
               {detailedReportList.length > 0 && (
                 <tfoot className="bg-slate-800 text-white font-black sticky bottom-0 z-10 border-t border-slate-700 shadow-[0_-2px_10px_rgba(0,0,0,0.1)]">
                    <tr>
                       <td colSpan={5} className="px-4 py-4 text-center text-[10px] tracking-widest uppercase">Page Total Summary</td>
                       <td className="px-4 py-4 text-center text-base">{detailedReportList.reduce((acc, r) => acc + r.articles, 0)}</td>
                       <td className="px-4 py-4 text-right text-base">{formatCurrency(detailedReportList.reduce((acc, r) => acc + r.postage, 0))}</td>
                    </tr>
                 </tfoot>
               )}
             </table>
           </div>
        </div>
      </div>

      {/* RSBT VOLUME SUMMARY SECTION */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-lg font-black text-slate-800 flex items-center gap-2">
            <FileSpreadsheet size={20} className="text-[#CE2029]" /> RSBT Cell Volume Matrix
          </h2>
          <button onClick={exportMatrixReport} className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-800 text-white rounded-lg hover:bg-slate-900 transition-all text-xs font-bold shadow-sm">
            <Printer size={14}/> PRINT MATRIX
          </button>
        </div>
        <div className="overflow-x-auto rounded-xl border border-slate-200">
          <table className="w-full text-xs text-left">
            <thead className="bg-slate-50 text-slate-500 font-black uppercase tracking-tighter text-[10px]">
              <tr>
                <th className="px-6 py-4 border-b">Category / Area</th>
                <th className="px-6 py-4 border-b text-center">BO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">BO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">PO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO International</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {['Rural', 'Urban', 'Total'].map((area) => (
                <tr key={area} className={`${area === 'Total' ? 'bg-slate-50 font-black text-slate-900' : 'text-slate-700 hover:bg-slate-50'} transition-colors`}>
                  <td className="px-6 py-4 font-bold">{area}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].boSpeed}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].boParcel}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].poSpeed}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].poParcel}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].poIntl}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

const QuickStatButton = ({ label, value, total, icon, onClick }: any) => {
  const percentage = total > 0 ? Math.round((value / total) * 100) : 0;
  return (
    <button 
      onClick={onClick}
      className="group w-full p-4 rounded-xl border border-slate-100 bg-slate-50 hover:bg-white hover:border-red-200 hover:shadow-md transition-all flex flex-col items-center justify-center text-center gap-1"
    >
      <div className="flex items-center gap-1.5 text-[9px] font-black text-slate-400 uppercase tracking-tighter group-hover:text-red-700 transition-colors">
        {icon} {label}
      </div>
      <div className="text-xl font-black text-slate-800">{value} <span className="text-[10px] text-slate-400 font-medium">/ {total}</span></div>
      <div className="w-full h-1 bg-slate-200 rounded-full mt-2 overflow-hidden">
        <div className="h-full bg-emerald-500 transition-all duration-700" style={{ width: `${percentage}%` }}></div>
      </div>
      <div className="text-[8px] font-black text-slate-400 mt-1 uppercase tracking-widest">{percentage}% Coverage</div>
    </button>
  );
};

export default RSBTCellReport;

import React, { useMemo, useState, useRef } from 'react';
import { BookingDataRow, MasterDataRow } from '../types';
import { FileSpreadsheet, Download, Printer, Home, Landmark, Filter, Search, Mail, Package, Globe, CheckCircle2, ClipboardList, RefreshCw, UploadCloud } from 'lucide-react';
import { exportToPDF, exportToExcel, getProductCategory, formatCurrency } from '../utils';

interface RSBTCellReportProps {
  data: BookingDataRow[];
  masterData: MasterDataRow[];
  onReupload?: () => void;
}

type MailType = 'Speed Post' | 'Parcel' | 'International Mail';
type BookingStatus = 'All' | 'Booked' | 'Not Booked';
type AreaFilter = 'All' | 'Rural' | 'Urban';
type OfficeTypeFilter = 'All' | 'P.O' | 'B.O';

const RSBTCellReport: React.FC<RSBTCellReportProps> = ({ data, masterData, onReupload }) => {
  // 5 Filters State
  const [filterType, setFilterType] = useState<MailType>('Speed Post');
  const [filterSubDiv, setFilterSubDiv] = useState('');
  const [filterArea, setFilterArea] = useState<AreaFilter>('All');
  const [filterOfficeType, setFilterOfficeType] = useState<OfficeTypeFilter>('All');
  const [filterStatus, setFilterStatus] = useState<BookingStatus>('All');

  const detailRef = useRef<HTMLDivElement>(null);

  const resetFilters = () => {
    setFilterType('Speed Post');
    setFilterSubDiv('');
    setFilterArea('All');
    setFilterOfficeType('All');
    setFilterStatus('All');
  };

  // 1. Volume Stats for the summary table
  const volumeStats = useMemo<any>(() => {
    const results: any = { Rural: {}, Urban: {}, Total: {} };
    const categories = [
      { id: 'boSpeed', type: 'B.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'boParcel', type: 'B.O', targetCat: 'Parcel' },
      { id: 'poSpeed', type: 'P.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'poParcel', type: 'P.O', targetCat: 'Parcel' },
      { id: 'poIntl', type: 'P.O', targetCat: 'International' },
    ];

    categories.forEach(cat => {
      results.Rural[cat.id] = 0; results.Urban[cat.id] = 0; results.Total[cat.id] = 0;
      data.forEach(row => {
        const rowType = row.officeType === 'B.O' ? 'B.O' : 'P.O';
        const rowCat = getProductCategory(row.productName);
        let isMatch = rowCat === cat.targetCat;
        if (cat.isSpeed && isMatch) isMatch = row.productName.toLowerCase().includes('speed post');
        if (isMatch && rowType === cat.type) {
          const area = row.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
          results[area][cat.id] += row.articles;
          results.Total[cat.id] += row.articles;
        }
      });
    });
    return results;
  }, [data]);

  // 2. Performance Summaries
  const performanceStats = useMemo(() => {
    const stats = {
      bo: { total: 0, bookedSP: 0, bookedPar: 0 },
      po: { total: 0, bookedSP: 0, bookedPar: 0 },
    };

    const spBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Domestic' && r.productName.toLowerCase().includes('speed post')).map(r => r.officeId));
    const parBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Parcel').map(r => r.officeId));

    masterData.forEach(m => {
      const isBO = m.officeType === 'B.O';
      if (isBO) {
        stats.bo.total++;
        if (spBookedIds.has(m.officeId)) stats.bo.bookedSP++;
        if (parBookedIds.has(m.officeId)) stats.bo.bookedPar++;
      } else {
        stats.po.total++;
        if (spBookedIds.has(m.officeId)) stats.po.bookedSP++;
        if (parBookedIds.has(m.officeId)) stats.po.bookedPar++;
      }
    });
    return stats;
  }, [data, masterData]);

  // 3. Main Filtered List (7 Columns Logic)
  const detailedReportList = useMemo(() => {
    // Current bookings based on Mail Type selection
    const typeBookings = data.filter(r => {
      const cat = getProductCategory(r.productName);
      if (filterType === 'Speed Post') return cat === 'Domestic' && r.productName.toLowerCase().includes('speed post');
      if (filterType === 'Parcel') return cat === 'Parcel';
      return cat === 'International';
    });

    const bookingMap = new Map<string, { articles: number, postage: number }>();
    typeBookings.forEach(b => {
      const current = bookingMap.get(b.officeId) || { articles: 0, postage: 0 };
      current.articles += b.articles;
      current.postage += b.totalAmount;
      bookingMap.set(b.officeId, current);
    });

    return masterData
      .map(office => {
        const booking = bookingMap.get(office.officeId);
        return {
          ...office,
          articles: booking ? booking.articles : 0,
          postage: booking ? booking.postage : 0,
          isBooked: !!booking
        };
      })
      .filter(office => {
        // Filter 1: Sub-Division
        if (filterSubDiv && !office.subDivisionName.toLowerCase().includes(filterSubDiv.toLowerCase())) return false;

        // Filter 2: Rural/Urban
        if (filterArea !== 'All' && office.areaType !== filterArea) return false;

        // Filter 3: PO/BO
        if (filterOfficeType !== 'All' && office.officeType !== filterOfficeType) return false;

        // Filter 4: Booking Status
        if (filterStatus === 'Booked' && !office.isBooked) return false;
        if (filterStatus === 'Not Booked' && office.isBooked) return false;

        return true;
      })
      .sort((a, b) => a.officeName.localeCompare(b.officeName));
  }, [masterData, data, filterType, filterSubDiv, filterArea, filterOfficeType, filterStatus]);

  const handleQuickAction = (type: MailType, status: BookingStatus, officeType: OfficeTypeFilter) => {
    setFilterType(type);
    setFilterStatus(status);
    setFilterOfficeType(officeType);
    setTimeout(() => {
      detailRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  const exportReport = (format: 'pdf' | 'excel') => {
    // Naming logic as per user request
    const reportTitle = `${filterType} Booking Report`;
    const headers = ['Sl No', 'Name of the Office', 'Office ID', 'Sub-Division Name', 'Office Type', 'Number', 'Postage'];

    const rows: any[] = detailedReportList.map((row, i) => [
      i + 1,
      row.officeName,
      row.officeId,
      row.subDivisionName,
      row.officeType,
      row.articles,
      row.postage.toFixed(2)
    ]);

    const totalArticles = detailedReportList.reduce((acc, r) => acc + r.articles, 0);
    const totalPostage = detailedReportList.reduce((acc, r) => acc + r.postage, 0);

    if (format === 'excel') {
      const excelData = detailedReportList.map((row, i) => ({
        'Sl No': i + 1,
        'Name of the Office': row.officeName,
        'Office ID': row.officeId,
        'Sub-Division Name': row.subDivisionName,
        'Office Type': row.officeType,
        'Number (Articles)': row.articles,
        'Postage': row.postage
      }));
      // Add total row to Excel
      excelData.push({
        'Sl No': '',
        'Name of the Office': 'GRAND TOTAL',
        'Office ID': '',
        'Sub-Division Name': '',
        'Office Type': '',
        'Number (Articles)': totalArticles,
        'Postage': totalPostage
      } as any);
      exportToExcel(excelData, reportTitle.replace(/\s+/g, '_'));
    } else {
      // Add total row to PDF
      rows.push(['', 'GRAND TOTAL', '', '', '', totalArticles, totalPostage.toFixed(2)]);
      exportToPDF(headers, rows, reportTitle, true);
    }
  };

  const exportMatrixReport = () => {
    const headers = ['Category / Area', 'BO Speed Post', 'BO Parcel', 'PO Speed Post', 'PO Parcel', 'PO International'];
    const rows = ['Rural', 'Urban', 'Total'].map(area => [
      area,
      volumeStats[area].boSpeed,
      volumeStats[area].boParcel,
      volumeStats[area].poSpeed,
      volumeStats[area].poParcel,
      volumeStats[area].poIntl,
    ]);
    exportToPDF(headers, rows, 'RSBT Cell Volume Matrix Report', true);
  };

  const getSubDivisions = useMemo(() => {
    return Array.from(new Set(masterData.map(m => m.subDivisionName))).sort();
  }, [masterData]);

  return (
    <div className="space-y-8 pb-10">
      {/* QUICK STAT CARDS */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2 border-b border-slate-100 pb-2">
            <div className="p-1.5 bg-amber-50 text-amber-600 rounded-lg"><Home size={18}/></div>
            Branch Office (BO) Performance
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <QuickStatButton 
              label="Speed Post Booked" 
              value={performanceStats.bo.bookedSP} 
              total={performanceStats.bo.total} 
              icon={<Mail size={16}/>}
              onClick={() => handleQuickAction('Speed Post', 'Booked', 'B.O')}
            />
            <QuickStatButton 
              label="Parcel Booked" 
              value={performanceStats.bo.bookedPar} 
              total={performanceStats.bo.total} 
              icon={<Package size={16}/>}
              onClick={() => handleQuickAction('Parcel', 'Booked', 'B.O')}
            />
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2 border-b border-slate-100 pb-2">
            <div className="p-1.5 bg-blue-50 text-blue-600 rounded-lg"><Landmark size={18}/></div>
            Sub Office / PO Performance
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <QuickStatButton 
              label="Speed Post Booked" 
              value={performanceStats.po.bookedSP} 
              total={performanceStats.po.total} 
              icon={<Mail size={16}/>}
              onClick={() => handleQuickAction('Speed Post', 'Booked', 'P.O')}
            />
            <QuickStatButton 
              label="Parcel Booked" 
              value={performanceStats.po.bookedPar} 
              total={performanceStats.po.total} 
              icon={<Package size={16}/>}
              onClick={() => handleQuickAction('Parcel', 'Booked', 'P.O')}
            />
          </div>
        </div>
      </div>

      {/* DETAILED MONITORING SECTION */}
      <div ref={detailRef} className="bg-white p-6 rounded-2xl shadow-lg border border-slate-200 space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div>
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2">
              <ClipboardList className="text-[#CE2029]" /> Detailed Monitoring Dashboard
            </h2>
            <p className="text-[11px] text-slate-500 font-medium">Filtering {detailedReportList.length} offices based on current criteria</p>
          </div>
          <div className="flex gap-2 flex-wrap">
             <button onClick={onReupload} className="flex items-center gap-1.5 px-3 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-all text-xs font-bold shadow-md">
               <UploadCloud size={14}/> RE-UPLOAD EXCEL
             </button>
             <button onClick={resetFilters} className="flex items-center gap-1.5 px-3 py-2 bg-slate-100 text-slate-600 rounded-lg border border-slate-200 hover:bg-slate-200 transition-all text-xs font-bold shadow-sm">
               <RefreshCw size={14}/> RESET
             </button>
             <button onClick={() => exportReport('excel')} className="flex items-center gap-1.5 px-3 py-2 bg-green-50 text-green-700 rounded-lg border border-green-200 hover:bg-green-100 transition-all text-xs font-bold">
               <Download size={14}/> EXCEL
             </button>
             <button onClick={() => exportReport('pdf')} className="flex items-center gap-1.5 px-3 py-2 bg-red-50 text-[#CE2029] rounded-lg border border-red-200 hover:bg-red-100 transition-all text-xs font-bold">
               <Printer size={14}/> PRINT REPORT
             </button>
          </div>
        </div>

        {/* 5 SEARCH FILTERS */}
        <div className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-5 gap-3 p-4 bg-slate-50 rounded-xl border border-slate-200 shadow-inner">
           {/* 1. Sub-Division */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">1. Sub-Division</label>
              <div className="relative">
                <input 
                  type="text"
                  placeholder="All Sub-Div..."
                  value={filterSubDiv}
                  onChange={e => setFilterSubDiv(e.target.value)}
                  className="w-full bg-white border border-slate-200 rounded-md pl-2 pr-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
                  list="subdiv-opts"
                />
                <datalist id="subdiv-opts">
                  {getSubDivisions.map(s => <option key={s} value={s} />)}
                </datalist>
              </div>
           </div>

           {/* 2. Rural/Urban */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">2. Rural/Urban</label>
              <select 
                value={filterArea} 
                onChange={e => setFilterArea(e.target.value as AreaFilter)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Areas</option>
                <option value="Rural">Rural Only</option>
                <option value="Urban">Urban Only</option>
              </select>
           </div>

           {/* 3. Booked/Not Booked */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">3. Status</label>
              <select 
                value={filterStatus} 
                onChange={e => setFilterStatus(e.target.value as BookingStatus)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Offices</option>
                <option value="Booked">Booked Only</option>
                <option value="Not Booked">Not Booked Only</option>
              </select>
           </div>

           {/* 4. Type (Mail Type) */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">4. Mail Type</label>
              <select 
                value={filterType} 
                onChange={e => setFilterType(e.target.value as MailType)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="Speed Post">Speed Post</option>
                <option value="Parcel">Parcel</option>
                <option value="International Mail">International Mail</option>
              </select>
           </div>

           {/* 5. PO/BO */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">5. PO/BO</label>
              <select 
                value={filterOfficeType} 
                onChange={e => setFilterOfficeType(e.target.value as OfficeTypeFilter)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Types</option>
                <option value="P.O">P.O Only</option>
                <option value="B.O">B.O Only</option>
              </select>
           </div>
        </div>

        {/* 7-COLUMN TABLE */}
        <div className="overflow-hidden rounded-xl border border-slate-200 shadow-inner">
           <div className="overflow-x-auto max-h-[500px] custom-scrollbar">
             <table className="w-full text-xs text-left">
               <thead className="bg-slate-800 text-white font-black uppercase tracking-wider sticky top-0 z-10">
                 <tr>
                    <th className="px-4 py-3 border-r border-slate-700 w-16">Sl No</th>
                    <th className="px-4 py-3 border-r border-slate-700">Name of the Office</th>
                    <th className="px-4 py-3 border-r border-slate-700">Office ID</th>
                    <th className="px-4 py-3 border-r border-slate-700">Sub-Division Name</th>
                    <th className="px-4 py-3 border-r border-slate-700 text-center">Office Type</th>
                    <th className="px-4 py-3 border-r border-slate-700 text-center">Number</th>
                    <th className="px-4 py-3 text-right">Postage</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-100 bg-white">
                 {detailedReportList.map((row, idx) => (
                   <tr key={row.officeId} className="hover:bg-slate-50 transition-colors">
                     <td className="px-4 py-3 text-slate-400 font-bold">{idx + 1}</td>
                     <td className="px-4 py-3 font-bold text-slate-800">{row.officeName}</td>
                     <td className="px-4 py-3 text-slate-500 font-mono text-[10px]">{row.officeId}</td>
                     <td className="px-4 py-3 text-slate-600 font-medium">{row.subDivisionName}</td>
                     <td className="px-4 py-3 text-center">
                        <span className={`px-2 py-0.5 rounded text-[9px] font-black border ${row.officeType === 'B.O' ? 'bg-amber-50 text-amber-600 border-amber-100' : 'bg-blue-50 text-blue-600 border-blue-100'}`}>
                          {row.officeType}
                        </span>
                     </td>
                     <td className={`px-4 py-3 text-center font-black ${row.articles > 0 ? 'text-blue-700' : 'text-slate-300'}`}>
                        {row.articles}
                     </td>
                     <td className="px-4 py-3 text-right font-black text-slate-800">
                        {row.postage > 0 ? formatCurrency(row.postage) : '-'}
                     </td>
                   </tr>
                 ))}
                 {detailedReportList.length === 0 && (
                   <tr>
                     <td colSpan={7} className="px-4 py-16 text-center text-slate-400 italic font-medium bg-slate-50">
                        No results match your selected filters.
                     </td>
                   </tr>
                 )}
               </tbody>
               {detailedReportList.length > 0 && (
                 <tfoot className="bg-slate-800 text-white font-black sticky bottom-0 z-10 border-t border-slate-700 shadow-[0_-2px_10px_rgba(0,0,0,0.1)]">
                    <tr>
                       <td colSpan={5} className="px-4 py-4 text-center text-[10px] tracking-widest uppercase">Page Total Summary</td>
                       <td className="px-4 py-4 text-center text-base">{detailedReportList.reduce((acc, r) => acc + r.articles, 0)}</td>
                       <td className="px-4 py-4 text-right text-base">{formatCurrency(detailedReportList.reduce((acc, r) => acc + r.postage, 0))}</td>
                    </tr>
                 </tfoot>
               )}
             </table>
           </div>
        </div>
      </div>

      {/* RSBT VOLUME SUMMARY SECTION */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-lg font-black text-slate-800 flex items-center gap-2">
            <FileSpreadsheet size={20} className="text-[#CE2029]" /> RSBT Cell Volume Matrix
          </h2>
