  };

  return (
    <div className="bg-white p-6 rounded-2xl shadow-lg border border-slate-200 flex flex-col min-h-0 h-full">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6 shrink-0">
        <div>
          <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <FileText className="text-[#CE2029]" /> Cumulative Booking Report
          </h2>
          <p className="text-[11px] text-slate-500 font-medium">Detailed breakdown of articles across all three mail verticals</p>
        </div>

        <div className="flex flex-1 max-w-lg w-full relative gap-2">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
            <input
              type="text"
              placeholder="Filter by Office Name or ID..."
              className="pl-10 w-full border border-slate-200 rounded-lg py-2 text-sm focus:ring-2 focus:ring-[#CE2029] focus:outline-none bg-slate-50 shadow-inner"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={onReupload}
            className="px-3 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-all text-[10px] font-black uppercase shadow-md flex items-center gap-1.5"
          >
            <UploadCloud size={14}/> RE-UPLOAD
          </button>
        </div>

        <div className="flex gap-2">
          <button onClick={handleExportExcel} title="Export to Excel" className="p-2 bg-green-50 text-green-700 rounded-lg border border-green-200 hover:bg-green-100 transition-all shadow-sm">
            <Download size={20} />
          </button>
          <button onClick={handleExportPDF} title="Export to PDF" className="p-2 bg-red-50 text-[#CE2029] rounded-lg border border-red-200 hover:bg-red-100 transition-all shadow-sm">
            <Printer size={20} />
          </button>
        </div>
      </div>

      <div className="overflow-x-auto rounded-xl border border-slate-200 flex-1 min-h-0 shadow-inner">
        <div className="min-w-[1200px]">
          <table className="w-full text-xs text-left border-collapse">
            <thead className="bg-slate-800 text-white font-black uppercase tracking-wider sticky top-0 z-10 shadow-md">
              <tr>
                <th className="px-4 py-3 border-r border-slate-700 w-16">Sl No</th>
                <th className="px-4 py-3 border-r border-slate-700 min-w-[200px]">Name of Office</th>
                <th className="px-4 py-3 border-r border-slate-700">Office ID</th>
                <th className="px-4 py-3 border-r border-slate-700 text-center">Type</th>
                <th className="px-4 py-3 border-r border-slate-700 text-center bg-blue-900/30">Dom Articles</th>
                <th className="px-4 py-3 border-r border-slate-700 text-right bg-blue-900/30">Dom Postage</th>
                <th className="px-4 py-3 border-r border-slate-700 text-center bg-amber-900/30">Par Articles</th>
                <th className="px-4 py-3 border-r border-slate-700 text-right bg-amber-900/30">Par Postage</th>
                <th className="px-4 py-3 border-r border-slate-700 text-center bg-purple-900/30">Int Articles</th>
                <th className="px-4 py-3 text-right bg-purple-900/30">Int Postage</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {filteredData.map((row, idx) => (
                <tr key={row.officeId} className="hover:bg-slate-50 transition-colors group">
                  <td className="px-4 py-3 text-slate-400 font-bold">{idx + 1}</td>
                  <td className="px-4 py-3 font-black text-slate-800">{row.officeName}</td>
                  <td className="px-4 py-3 text-slate-500 font-mono tracking-tighter text-[10px]">{row.officeId}</td>
                  <td className="px-4 py-3 text-center">
                    <span className={`px-2 py-0.5 rounded text-[9px] font-black border ${row.officeType === 'B.O' ? 'bg-amber-50 text-amber-600 border-amber-100' : 'bg-blue-50 text-blue-600 border-blue-100'}`}>
                      {row.officeType}
                    </span>
                  </td>
                  <td className="px-4 py-3 text-center text-blue-700 font-black bg-blue-50/10">{row.domArticles || '-'}</td>
                  <td className="px-4 py-3 text-right font-bold text-slate-900 bg-blue-50/10">{row.domPostage > 0 ? formatCurrency(row.domPostage) : '-'}</td>
                  <td className="px-4 py-3 text-center text-amber-700 font-black bg-amber-50/10">{row.parcelArticles || '-'}</td>
                  <td className="px-4 py-3 text-right font-bold text-slate-900 bg-amber-50/10">{row.parcelPostage > 0 ? formatCurrency(row.parcelPostage) : '-'}</td>
                  <td className="px-4 py-3 text-center text-purple-700 font-black bg-purple-50/10">{row.intlArticles || '-'}</td>
                  <td className="px-4 py-3 text-right font-bold text-slate-900 bg-purple-50/10">{row.intlPostage > 0 ? formatCurrency(row.intlPostage) : '-'}</td>
                </tr>
              ))}
            </tbody>
            <tfoot className="bg-slate-800 text-white font-black border-t border-slate-700 sticky bottom-0 z-20 shadow-[0_-2px_10px_rgba(0,0,0,0.1)]">
              <tr>
                <td colSpan={4} className="px-4 py-4 text-center tracking-widest text-[10px] uppercase">Combined Grand Totals</td>
                <td className="px-4 py-4 text-center text-base text-blue-400">{reportTotals.domArticles}</td>
                <td className="px-4 py-4 text-right text-base text-blue-400">{formatCurrency(reportTotals.domPostage)}</td>
                <td className="px-4 py-4 text-center text-amber-400">{reportTotals.parcelArticles}</td>
                <td className="px-4 py-4 text-right text-base text-amber-400">{formatCurrency(reportTotals.parcelPostage)}</td>
                <td className="px-4 py-4 text-center text-purple-400">{reportTotals.intlArticles}</td>
                <td className="px-4 py-4 text-right text-base text-purple-400">{formatCurrency(reportTotals.intlPostage)}</td>
              </tr>
            </tfoot>
          </table>
        </div>
      </div>
    </div>
  );
};

export default BookingReport;

import React, { useState, useMemo } from 'react';
import { BookingDataRow, ProductGroup, AnalysisSummary, OfficeSummary, MasterDataRow } from '../types';
import { PRODUCTS } from '../constants';
import { formatCurrency, exportToPDF, exportToExcel, getProductCategory } from '../utils';
import { BarChart, IndianRupee, Package, Globe, FileText, Download, Mail, CheckCircle, Printer, Palette, UploadCloud, ChevronDown, ListFilter } from 'lucide-react';

interface DashboardAnalysisProps {
  data: BookingDataRow[];
  masterData: MasterDataRow[];
  onReupload?: () => void;
}

type BookingReportType = 'BO_BOOKED' | 'BO_NOT_BOOKED' | 'PO_BOOKED' | 'PO_NOT_BOOKED';

// Helper for PDF currency to ensure Rs. is used instead of symbol
const formatCurrencyPDF = (amount: number) => {
  return `Rs. ${amount.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
};

// Canonical Mapping Table: Groups variants found in raw data to UI Card names
const PRODUCT_CANONICAL_MAP: Record<string, string> = {
  // Retail Parcel Variants -> India Post Parcel Retail
  'indiapost parcel retail': 'India Post Parcel Retail',
  'indiapost parcel retail ': 'India Post Parcel Retail',
  'india post parcel retail': 'India Post Parcel Retail',
  'speedpost parcel retail': 'India Post Parcel Retail',
  'speed post parcel retail': 'India Post Parcel Retail',

  // Speed Post Variants
  'inland speed post': 'Inland Speed Post',
  'inland speed post document': 'Inland Speed Post Document',

  // Others
  'registered letter': 'Registered Letter',
  'gyan post': 'Gyan Post',
  'indiapost parcel contractual': 'Indiapost Parcel Contractual',
  'speed post parcel domestic': 'Speed Post Parcel Domestic',
  'international air parcel': 'International Air Parcel',
  'international speed post document': 'International Speed Post Document',
  'international speed post merchandise': 'International Speed Post Merchandise',
  'registered foreign letter': 'Registered Foreign Letter',
  'registered international small packets': 'Registered International Small Packets'
};

const DashboardAnalysis: React.FC<DashboardAnalysisProps> = ({ data, masterData, onReupload }) => {
  const [selectedContext, setSelectedContext] = useState<string | null>(null);
  const [contextType, setContextType] = useState<'Category' | 'Product' | null>(null);
  const [cardColors, setCardColors] = useState<Record<string, string>>({});
  const [selectedBookingReport, setSelectedBookingReport] = useState<BookingReportType | null>(null);

  const handleColorChange = (key: string, color: string) => {
    setCardColors(prev => ({ ...prev, [key]: color }));
  };

  // 1. Determine Canonical Names for all data points
  const enrichedDataWithCanonical = useMemo(() => {
    return data.map(row => {
      const normalizedName = row.productName.toLowerCase().trim();
      const canonicalName = PRODUCT_CANONICAL_MAP[normalizedName] || row.productName;
      return { ...row, canonicalName };
    });
  }, [data]);

  // 2. Aggregate Product Card Stats (Product Performance)
  const productStats = useMemo(() => {
    const stats: Record<string, { articles: number; postage: number; revenue: number }> = {};
    PRODUCTS.ALL.forEach(p => stats[p] = { articles: 0, postage: 0, revenue: 0 });

    enrichedDataWithCanonical.forEach(row => {
      if (stats[row.canonicalName]) {
        stats[row.canonicalName].articles += row.articles;
        stats[row.canonicalName].postage += row.postage;
        stats[row.canonicalName].revenue += row.totalAmount;
      }
    });
    return stats;
  }, [enrichedDataWithCanonical]);

  // 3. Aggregate Vertical Stats (Domestic, Parcel, International)
  const revenueStats = useMemo(() => {
    const sumForList = (list: string[]) => {
      return list.reduce((acc, p) => {
        const s = productStats[p] || { articles: 0, postage: 0, revenue: 0 };
        return {
          articles: acc.articles + s.articles,
          postage: acc.postage + s.postage,
          revenue: acc.revenue + s.revenue
        };
      }, { articles: 0, postage: 0, revenue: 0 });
    };

    const domestic = sumForList(PRODUCTS.DOMESTIC);
    const parcel = sumForList(PRODUCTS.PARCEL);
    const international = sumForList(PRODUCTS.INTERNATIONAL);

    return {
      total: {
        articles: domestic.articles + parcel.articles + international.articles,
        postage: domestic.postage + parcel.postage + international.postage,
        revenue: domestic.revenue + parcel.revenue + international.revenue
      },
      domestic,
      parcel,
      international
    };
  }, [productStats]);

  // 4. Logic for Drill-down Reports
  const reportData = useMemo(() => {
    if (!selectedContext) return null;

    let filteredData = [];
    if (contextType === 'Category') {
      if (selectedContext === ProductGroup.ALL) {
        filteredData = enrichedDataWithCanonical;
      } else if (selectedContext === ProductGroup.DOMESTIC) {
        filteredData = enrichedDataWithCanonical.filter(d => getProductCategory(d.productName) === 'Domestic');
      } else if (selectedContext === ProductGroup.PARCEL) {
        filteredData = enrichedDataWithCanonical.filter(d => getProductCategory(d.productName) === 'Parcel');
      } else if (selectedContext === ProductGroup.INTERNATIONAL) {
        filteredData = enrichedDataWithCanonical.filter(d => getProductCategory(d.productName) === 'International');
      }
    } else {
      filteredData = enrichedDataWithCanonical.filter(d => d.canonicalName === selectedContext);
    }

    // Sub-Division Wise
    const subDivMap = new Map<string, AnalysisSummary>();
    filteredData.forEach(row => {
      const name = row.subDivision || 'Unknown Sub-Division';
      const current = subDivMap.get(name) || { subDivisionName: name, articleCount: 0, postageAmount: 0, totalRevenue: 0 };
      current.articleCount += row.articles;
      current.postageAmount += row.postage;
      current.totalRevenue += row.totalAmount;
      subDivMap.set(name, current);
    });
    const subDivReport = Array.from(subDivMap.values()).sort((a,b) => b.totalRevenue - a.totalRevenue);

    // PO Wise
    const poMap = new Map<string, OfficeSummary>();
    filteredData.forEach(row => {
      const name = row.officeJurisdiction || 'Unknown Jurisdiction';
      const current = poMap.get(name) || { officeName: name, articleCount: 0, postageAmount: 0, totalRevenue: 0 };
      current.articleCount += row.articles;
      current.postageAmount += row.postage;
      current.totalRevenue += row.totalAmount;
      poMap.set(name, current);
    });
    const poReport = Array.from(poMap.values()).sort((a,b) => b.totalRevenue - a.totalRevenue);

    return { subDivReport, poReport };
  }, [enrichedDataWithCanonical, selectedContext, contextType]);

  // 5. Booking & Non-Booking Detailed Lists
  const bookingAnalysisData = useMemo(() => {
    // Aggregate data per office
    const officeBookingSummary = new Map<string, { articles: number, postage: number }>();
    data.forEach(row => {
      const current = officeBookingSummary.get(row.officeId) || { articles: 0, postage: 0 };
      current.articles += row.articles;
      current.postage += row.totalAmount;
      officeBookingSummary.set(row.officeId, current);
    });

    // Classify all master data
    const results = {
      BO_BOOKED: [] as any[],
      BO_NOT_BOOKED: [] as any[],
      PO_BOOKED: [] as any[],
      PO_NOT_BOOKED: [] as any[]
    };

    masterData.forEach(office => {
      const stats = officeBookingSummary.get(office.officeId) || { articles: 0, postage: 0 };
      const isBooked = stats.articles > 0;
      const isBO = office.officeType === 'B.O';

      const item = {
        ...office,
        articles: stats.articles,
        postage: stats.postage
      };

      if (isBO) {
        if (isBooked) results.BO_BOOKED.push(item);
        else results.BO_NOT_BOOKED.push(item);
      } else {
        if (isBooked) results.PO_BOOKED.push(item);
        else results.PO_NOT_BOOKED.push(item);
      }
    });

    // Sorting: Sub-Division Wise, then by metric (postage/articles) in decreasing order
    const sorter = (a: any, b: any) => {
      // Primary: Sub-Division
      const subComp = a.subDivisionName.localeCompare(b.subDivisionName);
      if (subComp !== 0) return subComp;
      // Secondary: Postage Desc
      if (b.postage !== a.postage) return b.postage - a.postage;
      // Tertiary: Articles Desc
      return b.articles - a.articles;
    };

    results.BO_BOOKED.sort(sorter);
    results.BO_NOT_BOOKED.sort(sorter);
    results.PO_BOOKED.sort(sorter);
    results.PO_NOT_BOOKED.sort(sorter);

    return results;
  }, [data, masterData]);

  const handleCardClick = (context: string, type: 'Category' | 'Product') => {
    setSelectedContext(context);
    setContextType(type);
    setSelectedBookingReport(null); // Clear other drill-down
    setTimeout(() => {
      document.getElementById('report-section')?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const handleBookingReportClick = (type: BookingReportType) => {
    setSelectedBookingReport(type);
    setSelectedContext(null); // Clear other drill-down
    setTimeout(() => {
      document.getElementById('booking-detailed-section')?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const exportReport = (type: 'pdf' | 'excel', reportType: 'subdiv' | 'po') => {
    if (!reportData) return;
    const isSubDiv = reportType === 'subdiv';
    const rawData = isSubDiv ? reportData.subDivReport : reportData.poReport;
    const fileName = `${selectedContext} - ${isSubDiv ? 'SubDivision' : 'PO'} Report`;

    if (type === 'excel') {
      const exportData = rawData.map(r => ({
        [isSubDiv ? 'Sub Division Name' : 'Office Name']: isSubDiv ? (r as AnalysisSummary).subDivisionName : (r as OfficeSummary).officeName,
        'No of Articles': r.articleCount,
        'Total Postage': r.postageAmount,
        'Total Revenue': r.totalRevenue
      }));
      exportToExcel(exportData, fileName);
    } else {
      const headers = isSubDiv 
        ? ['Sl No', 'Name of the Sub Division', 'No of Articles Booked', 'Total Postage Amount', 'Total Revenue']
        : ['Sl No', 'Name of the POs', 'No of Articles Booked', 'Total Postage Amount', 'Total Revenue'];

      const rows = rawData.map((row, i) => [
        i + 1,
        isSubDiv ? (row as AnalysisSummary).subDivisionName : (row as OfficeSummary).officeName,
        row.articleCount,
        formatCurrencyPDF(row.postageAmount),
        formatCurrencyPDF(row.totalRevenue)
      ]);

      const totalArts = rawData.reduce((s, c) => s + c.articleCount, 0);
      const totalPostage = rawData.reduce((s, c) => s + c.postageAmount, 0);
      const totalRevenue = rawData.reduce((s, c) => s + c.totalRevenue, 0);
      rows.push(['', 'TOTAL', totalArts, formatCurrencyPDF(totalPostage), formatCurrencyPDF(totalRevenue)]);

      exportToPDF(headers, rows, fileName);
    }
  };

  const exportBookingReport = (type: 'pdf' | 'excel') => {
    if (!selectedBookingReport) return;
    const list = bookingAnalysisData[selectedBookingReport];
    const titleMap: Record<BookingReportType, string> = {
      BO_BOOKED: 'BOs Booked Report',
      BO_NOT_BOOKED: 'BOs Not Booked Report',
      PO_BOOKED: 'POs Booked Report',
      PO_NOT_BOOKED: 'POs Not Booked Report'
    };
    const title = titleMap[selectedBookingReport];

    if (type === 'excel') {
      const excelData = list.map((r, i) => ({
        'Sl No': i + 1,
        'Name of the Office': r.officeName,
        'Sub-Division': r.subDivisionName,
        'Post Office Jurisdiction': r.officeJurisdiction,
        'No of Articles Booked': r.articles,
        'Postage Amount': r.postage
      }));
      exportToExcel(excelData, title);
    } else {
      const headers = ['Sl No', 'Name of the office', 'Post Office jurisdiction', 'No of articles Booked', 'Postage Amount'];
      const rows = list.map((r, i) => [
        i + 1,
        r.officeName,
        r.officeJurisdiction,
        r.articles,
        formatCurrencyPDF(r.postage)
      ]);
      const totalArts = list.reduce((s, c) => s + c.articles, 0);
      const totalPostage = list.reduce((s, c) => s + c.postage, 0);
      rows.push(['', 'GRAND TOTAL', '', totalArts, formatCurrencyPDF(totalPostage)]);

      exportToPDF(headers, rows, title, true);
    }
  };

  return (
    <div className="space-y-8 pb-10">

      {/* SECTION 1: REVENUE VERTICALS */}
      <section>
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-4">
          <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <IndianRupee className="text-red-700" /> Revenue Analysis Dashboard
          </h2>
          <div className="flex gap-2 w-full sm:w-auto">
            <button 
              onClick={onReupload}
              className="flex-1 sm:flex-none flex items-center justify-center gap-1.5 px-3 py-1.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-all text-xs font-bold shadow-md"
            >
              <UploadCloud size={14}/> RE-UPLOAD DATA
            </button>
          </div>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <DetailedCard 
            title={ProductGroup.ALL} 
            data={revenueStats.total} 
            icon={<BarChart className="text-red-700" />} 
            colorClass="bg-red-50 border-red-200 hover:border-red-400"
            active={selectedContext === ProductGroup.ALL}
            onClick={() => handleCardClick(ProductGroup.ALL, 'Category')}
            customColor={cardColors[ProductGroup.ALL]}
            onColorChange={(color: string) => handleColorChange(ProductGroup.ALL, color)}
          />
          <DetailedCard 
            title={ProductGroup.DOMESTIC} 
            data={revenueStats.domestic} 
            icon={<FileText className="text-emerald-700" />} 
            colorClass="bg-emerald-50 border-emerald-200 hover:border-emerald-400"
            active={selectedContext === ProductGroup.DOMESTIC}
            onClick={() => handleCardClick(ProductGroup.DOMESTIC, 'Category')}
            customColor={cardColors[ProductGroup.DOMESTIC]}
            onColorChange={(color: string) => handleColorChange(ProductGroup.DOMESTIC, color)}
          />
          <DetailedCard 
            title={ProductGroup.PARCEL} 
            data={revenueStats.parcel} 
            icon={<Package className="text-amber-700" />} 
            colorClass="bg-amber-50 border-amber-200 hover:border-amber-400"
            active={selectedContext === ProductGroup.PARCEL}
            onClick={() => handleCardClick(ProductGroup.PARCEL, 'Category')}
            customColor={cardColors[ProductGroup.PARCEL]}
            onColorChange={(color: string) => handleColorChange(ProductGroup.PARCEL, color)}
          />
          <DetailedCard 
            title={ProductGroup.INTERNATIONAL} 
            data={revenueStats.international} 
            icon={<Globe className="text-blue-700" />} 
            colorClass="bg-blue-50 border-blue-200 hover:border-blue-400"
            active={selectedContext === ProductGroup.INTERNATIONAL}
            onClick={() => handleCardClick(ProductGroup.INTERNATIONAL, 'Category')}
            customColor={cardColors[ProductGroup.INTERNATIONAL]}
            onColorChange={(color: string) => handleColorChange(ProductGroup.INTERNATIONAL, color)}
          />
        </div>
      </section>

      {/* SECTION 2: PRODUCT CARDS */}
      <section>
        <h2 className="text-xl font-bold text-slate-800 mb-4 flex items-center gap-2">
          <Mail className="text-red-700" /> Product Performance
        </h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
          {PRODUCTS.ALL.map((product, idx) => (
            <DetailedCard
              key={product}
              title={product}
              data={productStats[product]}
              icon={null} 
              colorClass={getProductColor(idx)}
              active={selectedContext === product}
              onClick={() => handleCardClick(product, 'Product')}
              compact
              customColor={cardColors[product]}
              onColorChange={(color: string) => handleColorChange(product, color)}
            />
          ))}
        </div>
      </section>

      {/* SECTION 3: DRILL DOWN REPORT SECTION */}
      <div id="report-section" className="space-y-6">
        {selectedContext && reportData && (
          <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 animate-in fade-in slide-in-from-bottom-4 duration-500 shadow-sm">
             <div className="mb-6 border-b border-slate-200 pb-4">
               <h2 className="text-2xl font-bold text-slate-800">Reports: <span className="text-red-700">{selectedContext}</span></h2>
             </div>
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
               <ReportTable 
                  title="Sub-Division Wise Report"
                  headers={['Sl No', 'Sub Division', 'Articles', 'Postage', 'Revenue']}
                  rows={reportData.subDivReport.map((r, i) => [i+1, r.subDivisionName, r.articleCount, r.postageAmount, r.totalRevenue])}
                  onExportExcel={() => exportReport('excel', 'subdiv')}
                  onExportPDF={() => exportReport('pdf', 'subdiv')}
               />
               <ReportTable 
                  title="Post Office Wise Report"
                  headers={['Sl No', 'Post Office', 'Articles', 'Postage', 'Revenue']}
                  rows={reportData.poReport.map((r, i) => [i+1, r.officeName, r.articleCount, r.postageAmount, r.totalRevenue])}
                  onExportExcel={() => exportReport('excel', 'po')}
                  onExportPDF={() => exportReport('pdf', 'po')}
               />
             </div>
          </div>
        )}
      </div>

      {/* SECTION 4: BOOKING & NON-BOOKING ANALYSIS */}
      <section className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
         <h2 className="text-xl font-bold text-slate-800 mb-6 flex items-center gap-2">
           <CheckCircle className="text-red-700"/> Booking & Non-Booking Analysis
         </h2>
         <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
           <SummaryCountCard 
              label="BOs Booked" 
              value={bookingAnalysisData.BO_BOOKED.length} 
              color="text-green-700" 
