            <input
              type="text"
              placeholder="Filter by Office Name or ID..."
              className="pl-10 w-full border border-slate-200 rounded-lg py-2 text-sm focus:ring-2 focus:ring-[#CE2029] focus:outline-none bg-slate-50 shadow-inner"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="flex items-center gap-1.5 min-w-[140px]">
            <select
              value={officeTypeFilter}
              onChange={e => setOfficeTypeFilter(e.target.value as OfficeTypeFilter)}
              className="w-full border border-slate-200 rounded-lg py-2 px-3 text-xs font-bold focus:ring-2 focus:ring-[#CE2029] focus:outline-none bg-white shadow-sm appearance-none cursor-pointer"
            >
              <option value="All">All Type</option>
              <option value="P.O">P.Os only</option>
              <option value="B.O">B.Os only</option>
            </select>
          </div>

          <button 
