import React, { useMemo, useState } from 'react';
import { BookingDataRow } from '../types';
import { formatCurrency, exportToPDF, exportToExcel, getProductCategory } from '../utils';
import { FileText, Download, Printer, Search, UploadCloud, Filter } from 'lucide-react';

interface BookingReportProps {
  data: BookingDataRow[];
  onReupload?: () => void;
}

type OfficeTypeFilter = 'All' | 'P.O' | 'B.O';

const BookingReport: React.FC<BookingReportProps> = ({ data, onReupload }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [officeTypeFilter, setOfficeTypeFilter] = useState<OfficeTypeFilter>('All');

  const reportData = useMemo(() => {
    const officeMap = new Map<string, any>();

    data.forEach(row => {
      const id = row.officeId;
      if (!officeMap.has(id)) {
        officeMap.set(id, {
          officeName: row.officeName,
          officeId: row.officeId,
          officeType: row.officeType || 'Unknown',
          officeJurisdiction: row.officeJurisdiction || 'Unknown Jurisdiction',
          subDivision: row.subDivision || 'Unknown Sub-Division',
          domArticles: 0,
          domPostage: 0,
          domAmount: 0,
          parcelArticles: 0,
          parcelPostage: 0,
          parcelAmount: 0,
          intlArticles: 0,
          intlPostage: 0,
          intlAmount: 0
        });
      }

      const stats = officeMap.get(id);
      const cat = getProductCategory(row.productName);

      if (cat === 'Domestic') {
        stats.domArticles += row.articles;
        stats.domPostage += row.postage;
        stats.domAmount += row.totalAmount;
      } else if (cat === 'Parcel') {
        stats.parcelArticles += row.articles;
        stats.parcelPostage += row.postage;
        stats.parcelAmount += row.totalAmount;
      } else if (cat === 'International') {
        stats.intlArticles += row.articles;
        stats.intlPostage += row.postage;
        stats.intlAmount += row.totalAmount;
      }
    });

    const result = Array.from(officeMap.values());
    // Sorting in decreasing order of Combined Amount (Domestic + Parcel + International)
    return result.sort((a, b) => {
      const totalA = a.domAmount + a.parcelAmount + a.intlAmount;
      const totalB = b.domAmount + b.parcelAmount + b.intlAmount;
      if (totalB !== totalA) return totalB - totalA;
      return a.officeName.localeCompare(b.officeName);
    });
  }, [data]);

  const filteredData = useMemo(() => {
    let filtered = reportData;

    if (searchTerm) {
      filtered = filtered.filter(r => 
        r.officeName.toLowerCase().includes(searchTerm.toLowerCase()) || 
        r.officeId.toLowerCase().includes(searchTerm.toLowerCase()) ||
        r.officeJurisdiction.toLowerCase().includes(searchTerm.toLowerCase()) ||
