      'Parcel Amount': r.parcelAmount,
      'International Mail Articles': r.intlArticles,
      'International Mail Postage': r.intlPostage,
      'International Mail Amount': r.intlAmount
    }));
    exportToExcel(exportData, 'Booking_Report');
  };

