}

type MailType = 'All Type' | 'Speed Post' | 'Parcel' | 'International Mail' | 'Gyan Post';
type BookingStatus = 'All' | 'Booked' | 'Not Booked' | 'less than 5 article booked offices' | '5+ articles booked';
type AreaFilter = 'All' | 'Rural' | 'Urban';
type OfficeTypeFilter = 'All' | 'P.O' | 'B.O';

const RSBTCellReport: React.FC<RSBTCellReportProps> = ({ data, masterData, onReupload }) => {
  // 5 Filters State
  const [filterType, setFilterType] = useState<MailType>('All Type');
  const [filterSubDiv, setFilterSubDiv] = useState('');
  const [filterArea, setFilterArea] = useState<AreaFilter>('All');
  const [filterOfficeType, setFilterOfficeType] = useState<OfficeTypeFilter>('All');
  const [filterStatus, setFilterStatus] = useState<BookingStatus>('All');

  const detailRef = useRef<HTMLDivElement>(null);

  // 1. Volume Stats for the summary table
  const volumeStats = useMemo<any>(() => {
    const results: any = { Rural: {}, Urban: {}, Total: {} };
    const categories = [
      { id: 'boSpeed', type: 'B.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'boParcel', type: 'B.O', targetCat: 'Parcel' },
      { id: 'poSpeed', type: 'P.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'poParcel', type: 'P.O', targetCat: 'Parcel' },
      { id: 'poIntl', type: 'P.O', targetCat: 'International' },
    ];

    categories.forEach(cat => {
      results.Rural[cat.id] = 0; results.Urban[cat.id] = 0; results.Total[cat.id] = 0;
      data.forEach(row => {
        const rowType = row.officeType === 'B.O' ? 'B.O' : 'P.O';
        const rowCat = getProductCategory(row.productName);
        let isMatch = rowCat === cat.targetCat;
        if (cat.isSpeed && isMatch) isMatch = row.productName.toLowerCase().includes('speed post');
        if (isMatch && rowType === cat.type) {
          const area = row.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
          results[area][cat.id] += row.articles;
          results.Total[cat.id] += row.articles;
        }
      });
    });
    return results;
  }, [data]);

  // 2. Performance Summaries
  const performanceStats = useMemo(() => {
    const stats = {
      bo: { total: 0, bookedSP: 0, bookedPar: 0 },
      po: { total: 0, bookedSP: 0, bookedPar: 0 },
    };

    const spBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Domestic' && r.productName.toLowerCase().includes('speed post')).map(r => r.officeId));
    const parBookedIds = new Set(data.filter(r => getProductCategory(r.productName) === 'Parcel').map(r => r.officeId));

    masterData.forEach(m => {
      const isBO = m.officeType === 'B.O';
      if (isBO) {
        stats.bo.total++;
        if (spBookedIds.has(m.officeId)) stats.bo.bookedSP++;
        if (parBookedIds.has(m.officeId)) stats.bo.bookedPar++;
      } else {
        stats.po.total++;
        if (spBookedIds.has(m.officeId)) stats.po.bookedSP++;
        if (parBookedIds.has(m.officeId)) stats.po.bookedPar++;
      }
    });
    return stats;
  }, [data, masterData]);

  // 3. Main Filtered List (8 Columns Logic)
  const detailedReportList = useMemo(() => {
    // Current bookings based on Mail Type selection
    const typeBookings = data.filter(r => {
      if (filterType === 'All Type') return true;
      const cat = getProductCategory(r.productName);
      if (filterType === 'Speed Post') return cat === 'Domestic' && r.productName.toLowerCase().includes('speed post');
      if (filterType === 'Gyan Post') return cat === 'Domestic' && r.productName.toLowerCase().includes('gyan post');
      if (filterType === 'Parcel') return cat === 'Parcel';
      return cat === 'International';
    });

    const bookingMap = new Map<string, { articles: number, postage: number, amount: number }>();
    typeBookings.forEach(b => {
      const current = bookingMap.get(b.officeId) || { articles: 0, postage: 0, amount: 0 };
      current.articles += b.articles;
      current.postage += b.postage; // Column E
      current.amount += b.totalAmount; // Column K
      bookingMap.set(b.officeId, current);
    });

    const filtered = masterData
      .map(office => {
        const booking = bookingMap.get(office.officeId);
        return {
          ...office,
          articles: booking ? booking.articles : 0,
          postage: booking ? booking.postage : 0,
          amount: booking ? booking.amount : 0,
          isBooked: !!booking
        };
      })
      .filter(office => {
        // Filter 1: Sub-Division
        if (filterSubDiv && !office.subDivisionName.toLowerCase().includes(filterSubDiv.toLowerCase())) return false;

        // Filter 2: Rural/Urban
        if (filterArea !== 'All' && office.areaType !== filterArea) return false;

        // Filter 3: PO/BO
        if (filterOfficeType !== 'All' && office.officeType !== filterOfficeType) return false;

        // Filter 4: Booking Status
        if (filterStatus === 'Booked' && !office.isBooked) return false;
        if (filterStatus === 'Not Booked' && office.isBooked) return false;
        if (filterStatus === 'less than 5 article booked offices' && (!office.isBooked || office.articles >= 5)) return false;
        if (filterStatus === '5+ articles booked' && (!office.isBooked || office.articles < 5)) return false;

        return true;
      });

    // Updated Sorting: Primary by Sub-Division (A-Z), Secondary by Office Name (A-Z)
    return filtered.sort((a, b) => {
      const subComp = a.subDivisionName.localeCompare(b.subDivisionName);
      if (subComp !== 0) return subComp;
      return a.officeName.localeCompare(b.officeName);
    });
  }, [masterData, data, filterType, filterSubDiv, filterArea, filterOfficeType, filterStatus]);

  const handleQuickAction = (type: MailType, status: BookingStatus, officeType: OfficeTypeFilter) => {
    setFilterType(type);
    setFilterStatus(status);
    setFilterOfficeType(officeType);
    setTimeout(() => {
      detailRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  const exportReport = (format: 'pdf' | 'excel') => {
    const reportTitle = `${filterType} Booking Report (Sub-Division Wise)`;
    const headers = ['Sl No', 'Name of the Office', 'Office ID', 'Sub-Division Name', 'Office Type', 'Number', 'Postage', 'Amount'];

    const rows: any[] = detailedReportList.map((row, i) => [
      i + 1,
      row.officeName,
      row.officeId,
      row.subDivisionName,
      row.officeType,
      row.articles,
      row.postage.toFixed(2),
      row.amount.toFixed(2)
    ]);

    const totalArticles = detailedReportList.reduce((acc, r) => acc + r.articles, 0);
    const totalPostage = detailedReportList.reduce((acc, r) => acc + r.postage, 0);
    const totalAmount = detailedReportList.reduce((acc, r) => acc + r.amount, 0);

    if (format === 'excel') {
      const excelData = detailedReportList.map((row, i) => ({
        'Sl No': i + 1,
        'Name of the Office': row.officeName,
        'Office ID': row.officeId,
        'Sub-Division Name': row.subDivisionName,
        'Office Type': row.officeType,
        'Number (Articles)': row.articles,
        'Postage': row.postage,
        'Amount': row.amount
      }));
      // Add total row to Excel
      excelData.push({
        'Sl No': '',
        'Name of the Office': 'GRAND TOTAL',
        'Office ID': '',
        'Sub-Division Name': '',
        'Office Type': '',
        'Number (Articles)': totalArticles,
        'Postage': totalPostage,
        'Amount': totalAmount
      } as any);
      exportToExcel(excelData, reportTitle.replace(/\s+/g, '_'));
    } else {
      // Add total row to PDF
      rows.push(['', 'GRAND TOTAL', '', '', '', totalArticles, totalPostage.toFixed(2), totalAmount.toFixed(2)]);
      exportToPDF(headers, rows, reportTitle, true);
    }
  };

  const exportMatrixReport = () => {
    const headers = ['Category / Area', 'BO Speed Post', 'BO Parcel', 'PO Speed Post', 'PO Parcel', 'PO International'];
    const rows = ['Rural', 'Urban', 'Total'].map(area => [
      area,
      volumeStats[area].boSpeed,
      volumeStats[area].boParcel,
      volumeStats[area].poSpeed,
      volumeStats[area].poParcel,
      volumeStats[area].poIntl,
    ]);
    exportToPDF(headers, rows, 'RSBT Cell Volume Matrix Report', true);
  };

  const getSubDivisions = useMemo(() => {
    return Array.from(new Set(masterData.map(m => m.subDivisionName))).sort();
  }, [masterData]);

  return (
    <div className="space-y-8 pb-10">
      {/* QUICK STAT CARDS */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2 border-b border-slate-100 pb-2">
            <div className="p-1.5 bg-amber-50 text-amber-600 rounded-lg"><Home size={18}/></div>
            Branch Office (BO) Performance
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <QuickStatButton 
              label="Speed Post Booked" 
              value={performanceStats.bo.bookedSP} 
              total={performanceStats.bo.total} 
              icon={<Mail size={16}/>}
              onClick={() => handleQuickAction('Speed Post', 'Booked', 'B.O')}
            />
            <QuickStatButton 
              label="Parcel Booked" 
              value={performanceStats.bo.bookedPar} 
              total={performanceStats.bo.total} 
              icon={<Package size={16}/>}
              onClick={() => handleQuickAction('Parcel', 'Booked', 'B.O')}
            />
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2 border-b border-slate-100 pb-2">
            <div className="p-1.5 bg-blue-50 text-blue-600 rounded-lg"><Landmark size={18}/></div>
            Sub Office / PO Performance
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <QuickStatButton 
              label="Speed Post Booked" 
              value={performanceStats.po.bookedSP} 
              total={performanceStats.po.total} 
              icon={<Mail size={16}/>}
              onClick={() => handleQuickAction('Speed Post', 'Booked', 'P.O')}
            />
            <QuickStatButton 
              label="Parcel Booked" 
              value={performanceStats.po.bookedPar} 
              total={performanceStats.po.total} 
              icon={<Package size={16}/>}
              onClick={() => handleQuickAction('Parcel', 'Booked', 'P.O')}
            />
          </div>
        </div>
      </div>

      {/* DETAILED MONITORING SECTION */}
      <div ref={detailRef} className="bg-white p-6 rounded-2xl shadow-lg border border-slate-200 space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div>
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2">
              <ClipboardList className="text-[#CE2029]" /> Detailed Monitoring Dashboard
            </h2>
            <p className="text-[11px] text-slate-500 font-medium">Monitoring {detailedReportList.length} offices sorted by Sub-Division</p>
          </div>
          <div className="flex gap-2 flex-wrap">
             <button onClick={onReupload} className="flex items-center gap-1.5 px-3 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-all text-xs font-bold shadow-md">
               <UploadCloud size={14}/> RE-UPLOAD EXCEL
             </button>
             <button onClick={() => exportReport('excel')} className="flex items-center gap-1.5 px-3 py-2 bg-green-50 text-green-700 rounded-lg border border-green-200 hover:bg-green-100 transition-all text-xs font-bold">
               <Download size={14}/> EXCEL
             </button>
             <button onClick={() => exportReport('pdf')} className="flex items-center gap-1.5 px-3 py-2 bg-red-50 text-[#CE2029] rounded-lg border border-red-200 hover:bg-red-100 transition-all text-xs font-bold">
               <Printer size={14}/> PRINT REPORT
             </button>
          </div>
        </div>

        {/* 5 SEARCH FILTERS */}
        <div className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-5 gap-3 p-4 bg-slate-50 rounded-xl border border-slate-200 shadow-inner">
           {/* 1. Sub-Division */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">1. Sub-Division</label>
              <div className="relative">
                <input 
                  type="text"
                  placeholder="All Sub-Div..."
                  value={filterSubDiv}
                  onChange={e => setFilterSubDiv(e.target.value)}
                  className="w-full bg-white border border-slate-200 rounded-md pl-2 pr-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
                  list="subdiv-opts"
                />
                <datalist id="subdiv-opts">
                  {getSubDivisions.map(s => <option key={s} value={s} />)}
                </datalist>
              </div>
           </div>

           {/* 2. Rural/Urban */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">2. Rural/Urban</label>
              <select 
                value={filterArea} 
                onChange={e => setFilterArea(e.target.value as AreaFilter)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Areas</option>
                <option value="Rural">Rural Only</option>
                <option value="Urban">Urban Only</option>
              </select>
           </div>

           {/* 3. Booked/Not Booked */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">3. Status</label>
              <select 
                value={filterStatus} 
                onChange={e => setFilterStatus(e.target.value as BookingStatus)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Status</option>
                <option value="Booked">Booked (Any)</option>
                <option value="Not Booked">Not Booked (0)</option>
                <option value="less than 5 article booked offices">less than 5 article booked offices</option>
                <option value="5+ articles booked">5+ articles booked</option>
              </select>
           </div>

           {/* 4. Type (Mail Type) */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">4. Mail Type</label>
              <select 
                value={filterType} 
                onChange={e => setFilterType(e.target.value as MailType)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All Type">All Type</option>
                <option value="Speed Post">Speed Post</option>
                <option value="Gyan Post">Gyan Post</option>
                <option value="Parcel">Parcel</option>
                <option value="International Mail">International Mail</option>
              </select>
           </div>

           {/* 5. PO/BO */}
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">5. PO/BO</label>
              <select 
                value={filterOfficeType} 
                onChange={e => setFilterOfficeType(e.target.value as OfficeTypeFilter)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Types</option>
                <option value="P.O">P.O Only</option>
                <option value="B.O">B.O Only</option>
              </select>
           </div>
        </div>

        {/* 8-COLUMN TABLE */}
        <div className="overflow-hidden rounded-xl border border-slate-200 shadow-inner">
           <div className="overflow-x-auto max-h-[500px] custom-scrollbar">
             <table className="w-full text-xs text-left">
               <thead className="bg-slate-800 text-white font-black uppercase tracking-wider sticky top-0 z-10">
                 <tr>
                    <th className="px-4 py-3 border-r border-slate-700 w-16">Sl No</th>
                    <th className="px-4 py-3 border-r border-slate-700">Name of the Office</th>
                    <th className="px-4 py-3 border-r border-slate-700">Office ID</th>
                    <th className="px-4 py-3 border-r border-slate-700">Sub-Division Name</th>
                    <th className="px-4 py-3 border-r border-slate-700 text-center">Office Type</th>
                    <th className="px-4 py-3 border-r border-slate-700 text-center">Number</th>
                    <th className="px-4 py-3 border-r border-slate-700 text-right">Postage</th>
                    <th className="px-4 py-3 text-right">Amount</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-100 bg-white">
                 {detailedReportList.map((row, idx) => (
                   <tr key={row.officeId} className="hover:bg-slate-50 transition-colors">
                     <td className="px-4 py-3 text-slate-400 font-bold">{idx + 1}</td>
                     <td className="px-4 py-3 font-bold text-slate-800">{row.officeName}</td>
                     <td className="px-4 py-3 text-slate-500 font-mono text-[10px]">{row.officeId}</td>
                     <td className="px-4 py-3 text-slate-600 font-medium">{row.subDivisionName}</td>
                     <td className="px-4 py-3 text-center">
                        <span className={`px-2 py-0.5 rounded text-[9px] font-black border ${row.officeType === 'B.O' ? 'bg-amber-50 text-amber-600 border-amber-100' : 'bg-blue-50 text-blue-600 border-blue-100'}`}>
                          {row.officeType}
                        </span>
                     </td>
                     <td className={`px-4 py-3 text-center font-black ${row.articles > 0 ? (row.articles < 5 ? 'text-orange-600' : 'text-blue-700') : 'text-slate-300'}`}>
                        {row.articles}
                     </td>
                     <td className="px-4 py-3 text-right font-black text-slate-800">
                        {row.postage > 0 ? row.postage.toFixed(2) : '-'}
                     </td>
                     <td className="px-4 py-3 text-right font-black text-slate-900 bg-slate-50/50">
                        {row.amount > 0 ? formatCurrency(row.amount) : '-'}
                     </td>
                   </tr>
                 ))}
                 {detailedReportList.length === 0 && (
                   <tr>
                     <td colSpan={8} className="px-4 py-16 text-center text-slate-400 italic font-medium bg-slate-50">
                        No results match your selected filters.
                     </td>
                   </tr>
                 )}
               </tbody>
               {detailedReportList.length > 0 && (
                 <tfoot className="bg-slate-800 text-white font-black sticky bottom-0 z-10 border-t border-slate-700 shadow-[0_-2px_10px_rgba(0,0,0,0.1)]">
                    <tr>
                       <td colSpan={5} className="px-4 py-4 text-center text-[10px] tracking-widest uppercase">Page Total Summary</td>
                       <td className="px-4 py-4 text-center text-base">{detailedReportList.reduce((acc, r) => acc + r.articles, 0)}</td>
                       <td className="px-4 py-4 text-right text-base">{detailedReportList.reduce((acc, r) => acc + r.postage, 0).toFixed(2)}</td>
                       <td className="px-4 py-4 text-right text-base">{formatCurrency(detailedReportList.reduce((acc, r) => acc + r.amount, 0))}</td>
                    </tr>
                 </tfoot>
               )}
             </table>
           </div>
        </div>
      </div>

      {/* RSBT VOLUME SUMMARY SECTION */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-lg font-black text-slate-800 flex items-center gap-2">
            <FileSpreadsheet size={20} className="text-[#CE2029]" /> RSBT Cell Volume Matrix
          </h2>
          <button onClick={exportMatrixReport} className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-800 text-white rounded-lg hover:bg-slate-900 transition-all text-xs font-bold shadow-sm">
            <Printer size={14}/> PRINT MATRIX
          </button>
        </div>
        <div className="overflow-x-auto rounded-xl border border-slate-200">
          <table className="w-full text-xs text-left">
            <thead className="bg-slate-50 text-slate-500 font-black uppercase tracking-tighter text-[10px]">
              <tr>
                <th className="px-6 py-4 border-b">Category / Area</th>
                <th className="px-6 py-4 border-b text-center">BO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">BO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO Speed Post</th>
                <th className="px-6 py-4 border-b text-center">PO Parcel</th>
                <th className="px-6 py-4 border-b text-center">PO International</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {['Rural', 'Urban', 'Total'].map((area) => (
                <tr key={area} className={`${area === 'Total' ? 'bg-slate-50 font-black text-slate-900' : 'text-slate-700 hover:bg-slate-50'} transition-colors`}>
                  <td className="px-6 py-4 font-bold">{area}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].boSpeed}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].boParcel}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].poSpeed}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].poParcel}</td>
                  <td className="px-6 py-4 text-center">{volumeStats[area].poIntl}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

const QuickStatButton = ({ label, value, total, icon, onClick }: any) => {
  const percentage = total > 0 ? Math.round((value / total) * 100) : 0;
  return (
    <button 
      onClick={onClick}
      className="group w-full p-4 rounded-xl border border-slate-100 bg-slate-50 hover:bg-white hover:border-red-200 hover:shadow-md transition-all flex flex-col items-center justify-center text-center gap-1"
    >
      <div className="flex items-center gap-1.5 text-[9px] font-black text-slate-400 uppercase tracking-tighter group-hover:text-red-700 transition-colors">
        {icon} {label}
      </div>
      <div className="text-xl font-black text-slate-800">{value} <span className="text-[10px] text-slate-400 font-medium">/ {total}</span></div>
      <div className="w-full h-1 bg-slate-200 rounded-full mt-2 overflow-hidden">
        <div className="h-full bg-emerald-500 transition-all duration-700" style={{ width: `${percentage}%` }}></div>
      </div>
      <div className="text-[8px] font-black text-slate-400 mt-1 uppercase tracking-widest">{percentage}% Coverage</div>
    </button>
  );
};

export default RSBTCellReport;

