export const getProductCategory = (productName: string): 'Domestic' | 'Parcel' | 'International' | 'Other' => {
  const name = productName.toLowerCase().trim();

  const isDomestic = PRODUCTS.DOMESTIC.some(p => p.toLowerCase().trim() === name);
  if (isDomestic) return 'Domestic';

  const isParcel = PRODUCTS.PARCEL.some(p => p.toLowerCase().trim() === name);
  if (isParcel) return 'Parcel';

  const isInternational = PRODUCTS.INTERNATIONAL.some(p => p.toLowerCase().trim() === name);
  if (isInternational) return 'International';

  return 'Other';
};

// Helper to safely parse numbers that might contain commas, currency symbols, or be strings
const parseNumber = (val: any): number => {
  if (val === null || val === undefined || val === '') return 0;
  if (typeof val === 'number') {
     return isNaN(val) ? 0 : val;
  }

  // Convert to string and trim
  let strVal = String(val).trim();
  if (!strVal) return 0;

  // Remove commas (thousands separator)
  strVal = strVal.replace(/,/g, '');

  // Remove currency symbols and non-numeric chars but keep decimal and minus
  strVal = strVal.replace(/[^0-9.-]/g, '');

  const num = parseFloat(strVal);
  return isNaN(num) ? 0 : num;
};

export const parseExcelFile = (file: File): Promise<RawBookingRow[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const data = e.target?.result;
      if (!data) return reject("No data read");

      const workbook = XLSX.read(data, { type: 'binary' });
      const sheetName = workbook.SheetNames[0];
      const sheet = workbook.Sheets[sheetName];
      const jsonData = XLSX.utils.sheet_to_json(sheet, { header: 1 }) as any[][];

      const parsedData: RawBookingRow[] = [];

      jsonData.forEach((row, index) => {
        // Skip header row if it contains text in the numeric columns
        if (index === 0) {
           const rawVal = String(row[3] || '').replace(/,/g, '');
           const potentialNumber = parseFloat(rawVal);
           if (isNaN(potentialNumber)) return;
        }

        const officeId = row[0] ? String(row[0]).trim() : '';
        if (!officeId || officeId.toLowerCase() === 'office id') return; 

        const entry: RawBookingRow = {
          officeId: officeId,
          officeName: row[1] ? String(row[1]).trim() : '',
          productName: row[2] ? String(row[2]).trim() : '',
          articles: parseNumber(row[3]),
          postage: parseNumber(row[4]),
          vas: parseNumber(row[5]),
          tax: parseNumber(row[6]),
          prepaidFm: parseNumber(row[7]),
          prepaidPs: parseNumber(row[8]),
          prepaidSs: parseNumber(row[9]),
          totalAmount: parseNumber(row[10]),
          avgWeight: parseNumber(row[11]),
        };
        parsedData.push(entry);
      });

      resolve(parsedData);
    };
    reader.onerror = (err) => reject(err);
    reader.readAsBinaryString(file);
  });
};

const parseCSVLine = (text: string): string[] => {
  const result: string[] = [];
  let current = '';
  let inQuote = false;

  for (let i = 0; i < text.length; i++) {
    const char = text[i];
    if (char === '"') {
      inQuote = !inQuote;
    } else if (char === ',' && !inQuote) {
      result.push(current.trim());
      current = '';
    } else {
      current += char;
    }
  }
  result.push(current.trim());
  return result.map(field => {
    let f = field;
    if (f.startsWith('"') && f.endsWith('"')) {
      f = f.slice(1, -1);
    }
    return f.replace(/""/g, '"').trim();
  });
};

export const fetchMasterDataFromUrl = async (url: string): Promise<MasterDataRow[]> => {
  try {
    const response = await fetch(url, { cache: 'no-store' });
    if (!response.ok) throw new Error('Network response was not ok');
    const text = await response.text();

    const lines = text.split(/\r?\n/);
    const masterData: MasterDataRow[] = [];

    lines.forEach((line, index) => {
      if (index === 0) return; // Skip header
      if (!line.trim()) return;

      const row = parseCSVLine(line);
      if (!row[0]) return;

      masterData.push({
        officeId: row[0].trim(),
        officeName: row[1] ? row[1].trim() : '',
        officeType: row[2] ? row[2].trim() : '',
        officeJurisdiction: row[3] ? row[3].trim() : '',
        headOfficeName: row[4] ? row[4].trim() : '',
        subDivisionName: row[5] ? row[5].trim() : '',
        areaType: row[6] ? row[6].trim() : 'Rural',
      });
    });
    return masterData;
  } catch (error) {
    console.error("Failed to fetch master data", error);
    return DEFAULT_MASTER_DATA;
  }
};

export const fetchBookingDataFromUrl = async (url: string): Promise<RawBookingRow[]> => {
  try {
    // Adding no-cache headers can sometimes help bypass stale redirect issues in certain environments
    const response = await fetch(url, { 
      method: 'GET',
      headers: { 'Accept': 'text/csv' },
      cache: 'no-store'
    });

    if (!response.ok) {
       if (response.status === 404) throw new Error("File not found. Ensure the Google Sheet is 'Published to the web' as a CSV.");
       if (response.status === 403) throw new Error("Access Denied. Ensure the Google Sheet is 'Published to the web'. Standard sharing links do not work.");
       throw new Error(`HTTP Error ${response.status}: Failed to retrieve sheet data.`);
    }

    const text = await response.text();

    const lines = text.split(/\r?\n/);
    const parsedData: RawBookingRow[] = [];

    lines.forEach((line, index) => {
      if (!line.trim()) return;
      const row = parseCSVLine(line);

      // Basic validation for the row
      if (row.length < 11) return;

      // Skip header row
      if (index === 0) {
         const rawVal = String(row[3] || '').replace(/,/g, '');
         const potentialNumber = parseFloat(rawVal);
         if (isNaN(potentialNumber)) return;
      }

      const officeId = row[0] ? String(row[0]).trim() : '';
      if (!officeId || officeId.toLowerCase() === 'office id') return;

      const entry: RawBookingRow = {
        officeId: officeId,
        officeName: row[1] ? String(row[1]).trim() : '',
        productName: row[2] ? String(row[2]).trim() : '',
        articles: parseNumber(row[3]),
        postage: parseNumber(row[4]),
        vas: parseNumber(row[5]),
        tax: parseNumber(row[6]),
        prepaidFm: parseNumber(row[7]),
        prepaidPs: parseNumber(row[8]),
        prepaidSs: parseNumber(row[9]),
        totalAmount: parseNumber(row[10]),
        avgWeight: parseNumber(row[11]),
      };
      parsedData.push(entry);
    });

    return parsedData;
  } catch (error: any) {
    console.error("Fetch booking data error:", error);
    if (error.message.includes('Failed to fetch')) {
       throw new Error("Network blocked. This usually means the Google Sheet is NOT 'Published to the web'. Standard sharing will not work due to CORS policy.");
    }
    throw error;
  }
};

export const formatCurrency = (val: number) => {
  return new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR' }).format(val);
};

export const exportToPDF = (headers: string[], data: any[][], title: string, landscape = false) => {
  const doc = new jsPDF(landscape ? 'l' : 'p', 'mm', 'a4');
  doc.text(title, 14, 15);
  autoTable(doc, {
    head: [headers],
    body: data,
    startY: 20,
    theme: 'grid',
    styles: { fontSize: 8 },
    headStyles: { fillColor: [206, 32, 41] } 
  });
  doc.save(`${title.replace(/\s+/g, '_')}.pdf`);
};

export const exportToExcel = (data: any[], fileName: string) => {
  const ws = XLSX.utils.json_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Report");
  XLSX.writeFile(wb, `${fileName}.xlsx`);
};

import React, { useMemo, useState } from 'react';
import { BookingDataRow, MasterDataRow } from '../types';
import { formatCurrency, exportToPDF, exportToExcel } from '../utils';
import { Landmark, Building2, ChevronRight, ChevronDown, Download, Printer, Search, UploadCloud } from 'lucide-react';

interface HOReportProps {
  data: BookingDataRow[];
  masterData: MasterDataRow[];
  onReupload?: () => void;
}

// Local interface for office stats within the hierarchy
interface GroupedOffice extends MasterDataRow {
  articles: number;
  postage: number;
  amount: number;
}

const HOReport: React.FC<HOReportProps> = ({ data, masterData, onReupload }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [expandedHO, setExpandedHO] = useState<string | null>(null);

  const hoList = ['Angul H.O', 'Dhenkanal H.O'];

  const reportData = useMemo(() => {
    // Map of Head Office -> Map of Account Office (SO) -> List of Offices (SO + BOs)
    const hoMap = new Map<string, Map<string, GroupedOffice[]>>();

    // Initialize map
    hoList.forEach(ho => hoMap.set(ho, new Map<string, GroupedOffice[]>()));

    // Grouping logic
    masterData.forEach(m => {
      const hoName = m.headOfficeName;
      if (!hoMap.has(hoName)) return; // Only track Angul and Dhenkanal

      const hoGroup = hoMap.get(hoName)!;
      const juris = m.officeJurisdiction;

      if (!hoGroup.has(juris)) {
        hoGroup.set(juris, []);
      }

      const stats = data
        .filter(d => d.officeId === m.officeId)
        .reduce((acc, curr) => ({
          articles: acc.articles + curr.articles,
          postage: acc.postage + curr.postage,
          amount: acc.amount + curr.totalAmount
        }), { articles: 0, postage: 0, amount: 0 });

      hoGroup.get(juris)!.push({
        ...m,
        ...stats
      });
    });

    return hoMap;
  }, [data, masterData]);

  const toggleHO = (ho: string) => {
    setExpandedHO(expandedHO === ho ? null : ho);
  };

  const exportHOData = (ho: string, format: 'pdf' | 'excel') => {
    const hoGroup = reportData.get(ho);
    if (!hoGroup) return;

    const flatList: GroupedOffice[] = [];
    Array.from(hoGroup.entries())
      .sort((a, b) => a[0].localeCompare(b[0]))
      .forEach(([juris, offices]) => {
        offices.sort((a, b) => {
          if (a.officeType === 'P.O' && b.officeType === 'B.O') return -1;
          if (a.officeType === 'B.O' && b.officeType === 'P.O') return 1;
          return a.officeName.localeCompare(b.officeName);
        });
        flatList.push(...offices);
      });

    const title = `${ho} - Detailed Hierarchy Report`;
    if (format === 'excel') {
      const excelData = flatList.map((off, idx) => ({
        'Sl No': idx + 1,
        'Head Office': off.headOfficeName,
        'Account Office': off.officeJurisdiction,
        'Office Name': off.officeName,
        'Type': off.officeType,
        'Articles': off.articles,
        'Postage': off.postage,
        'Revenue': off.amount
      }));
      exportToExcel(excelData, title.replace(/\s+/g, '_'));
    } else {
      const headers = ['Sl No', 'Account Office', 'Office Name', 'Type', 'Articles', 'Postage', 'Revenue'];
      const rows = flatList.map((off, idx) => [
        idx + 1,
        off.officeJurisdiction,
        off.officeName,
        off.officeType,
        off.articles,
        off.postage.toFixed(2),
        formatCurrency(off.amount)
      ]);
      const totals = flatList.reduce((acc, curr) => ({
        articles: acc.articles + curr.articles,
        postage: acc.postage + curr.postage,
        amount: acc.amount + curr.amount
      }), { articles: 0, postage: 0, amount: 0 });
      rows.push(['', 'GRAND TOTAL', '', '', totals.articles, totals.postage.toFixed(2), formatCurrency(totals.amount)]);
      exportToPDF(headers, rows, title, true);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <div>
          <h2 className="text-2xl font-black text-slate-800 flex items-center gap-2">
            <Landmark className="text-[#CE2029]" /> Head Office (HO) Wise Report
          </h2>
          <p className="text-xs text-slate-500 font-medium">Hierarchy: HO > Account Office (SO) > BOs</p>
        </div>
        <div className="flex gap-2 w-full md:w-auto">
          <div className="relative flex-1 md:w-64">
            <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
            <input
              type="text"
              placeholder="Search in HO reports..."
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              className="pl-10 w-full border border-slate-200 rounded-lg py-2 text-sm focus:ring-2 focus:ring-[#CE2029] focus:outline-none bg-slate-50 shadow-inner"
            />
          </div>
          <button onClick={onReupload} className="p-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 shadow-md">
             <UploadCloud size={20}/>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {hoList.map(ho => {
          const hoGroup = reportData.get(ho);
          if (!hoGroup) return null;

          // Added explicit generic type to reduce to fix 'unknown' property access errors
          const hoStats = Array.from(hoGroup.values()).flat().reduce<{ articles: number; postage: number; amount: number; count: number }>((acc, curr) => ({
            articles: acc.articles + curr.articles,
            postage: acc.postage + curr.postage,
            amount: acc.amount + curr.amount,
            count: acc.count + 1
          }), { articles: 0, postage: 0, amount: 0, count: 0 });

          return (
            <div key={ho} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-full">
               <div 
                 onClick={() => toggleHO(ho)}
                 className="p-6 cursor-pointer hover:bg-slate-50 transition-colors flex justify-between items-center group"
               >
                 <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-red-50 text-[#CE2029] rounded-xl flex items-center justify-center shadow-inner group-hover:scale-110 transition-transform">
                       <Landmark size={24}/>
                    </div>
                    <div>
                      <h3 className="text-xl font-bold text-slate-800">{ho}</h3>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{hoStats.count} Total Offices</p>
                    </div>
                 </div>
                 {expandedHO === ho ? <ChevronDown className="text-slate-400"/> : <ChevronRight className="text-slate-400"/>}
               </div>

               <div className="grid grid-cols-3 border-t border-slate-100 bg-slate-50/50">
                  <StatItem label="Articles" value={hoStats.articles} color="text-blue-700" />
                  <StatItem label="Postage" value={hoStats.postage.toFixed(2)} color="text-amber-700" />
                  <StatItem label="Revenue" value={formatCurrency(hoStats.amount)} color="text-emerald-700" />
               </div>

               {expandedHO === ho && (
                 <div className="flex-1 overflow-hidden flex flex-col p-4 bg-slate-50 border-t border-slate-100 animate-in fade-in slide-in-from-top-2 duration-300">
                    <div className="flex justify-between items-center mb-4">
