/**
 * Converts various Google Sheets URL formats to a direct CSV export/pub URL.
 */
const convertToExportUrl = (inputUrl: string): string | null => {
  const url = inputUrl.trim();
  if (!url) return null;

  if (url.includes('docs.google.com/spreadsheets')) {
    // If it's a "Published to web" long ID (d/e format)
    if (url.includes('/d/e/')) {
      const parts = url.split('/pub');
      const baseUrl = parts[0];
      const gidMatch = url.match(/[#&?]gid=([0-9]+)/);
      const gid = gidMatch ? gidMatch[1] : '0';
      return `${baseUrl}/pub?gid=${gid}&single=true&output=csv`;
    }

    // Standard /d/ spreadsheet ID format
    const idMatch = url.match(/\/d\/([a-zA-Z0-9-_]+)/);
    if (idMatch && idMatch[1]) {
      const id = idMatch[1];
      const gidMatch = url.match(/[#&?]gid=([0-9]+)/);
      const gid = gidMatch ? gidMatch[1] : null;

      // We prefer /pub format as it's more CORS-friendly for browsers when 'Published to web'
      return `https://docs.google.com/spreadsheets/d/${id}/pub?gid=${gid || 0}&single=true&output=csv`;
    }
  }
  return url;
};

