/**
 * Converts Google Sheets URLs to direct CSV export URLs.
 * Handles both /d/ID/edit and /d/e/PUB_ID/pub formats.
 */
const convertToExportUrl = (inputUrl: string): string | null => {
  let url = inputUrl.trim();
  if (!url) return null;

  if (url.includes('docs.google.com/spreadsheets')) {
    // Check if it's a published web link (/d/e/...)
    if (url.includes('/d/e/')) {
      const parts = url.split('/pub');
      const baseUrl = parts[0];
      const gidMatch = url.match(/[#&?]gid=([0-9]+)/);
      const gid = gidMatch ? gidMatch[1] : '0';
      return `${baseUrl}/pub?gid=${gid}&single=true&output=csv`;
    }

    // Standard /d/ spreadsheet ID format
    const idMatch = url.match(/\/d\/([a-zA-Z0-9-_]+)/);
    if (idMatch && idMatch[1]) {
      const id = idMatch[1];
      const gidMatch = url.match(/[#&?]gid=([0-9]+)/);
      const gid = gidMatch ? gidMatch[1] : '0';
      // For standard URLs, the 'export?format=csv' endpoint is reliable
      return `https://docs.google.com/spreadsheets/d/${id}/export?format=csv&gid=${gid}`;
    }
  }
  return url;
};

