                    <p className="text-slate-500 max-w-lg mx-auto">Analyze booking performance across Angul Division. Select a preset report or define a custom period.</p>
                </div>

                {/* Periodic Selection Section */}
                <div className="bg-slate-50 border border-slate-200 rounded-2xl p-6 mb-8 shadow-inner">
                    <div className="flex items-center gap-2 mb-4">
                        <CalendarRange className="text-[#CE2029]" size={20}/>
                        <h3 className="font-bold text-slate-700">Custom Period Selection</h3>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 items-end">
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">From Month</label>
                            <select 
                                value={fromMonthIndex} 
                                onChange={(e) => setFromMonthIndex(parseInt(e.target.value))}
                                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2.5 text-sm font-bold shadow-sm focus:ring-2 focus:ring-[#CE2029] focus:outline-none"
                            >
                                {MONTHLY_REPORTS.map((m, idx) => (
                                    <option key={m.name} value={idx}>{m.name}</option>
                                ))}
                            </select>
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">To Month</label>
                            <select 
                                value={toMonthIndex} 
                                onChange={(e) => setToMonthIndex(parseInt(e.target.value))}
                                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2.5 text-sm font-bold shadow-sm focus:ring-2 focus:ring-[#CE2029] focus:outline-none"
                            >
                                {MONTHLY_REPORTS.map((m, idx) => (
                                    <option key={m.name} value={idx}>{m.name}</option>
                                ))}
                            </select>
                        </div>
                        <button 
                            onClick={loadSelectedPeriod} 
                            disabled={loading}
                            className="bg-[#CE2029] text-white font-black uppercase text-xs tracking-widest px-6 py-3 rounded-lg shadow-lg hover:bg-red-700 transition-all hover:scale-[1.02] active:scale-95 disabled:opacity-50"
                        >
                            Load Selected Period
                        </button>
                    </div>
                    <p className="text-[10px] text-slate-400 mt-3 italic font-medium">Select a start and end month to aggregate multi-month data automatically.</p>
                </div>

                <div className="flex items-center gap-4 mb-4">
                  <div className="h-px bg-slate-200 flex-1"></div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Quick Selection</span>
                  <div className="h-px bg-slate-200 flex-1"></div>
                </div>

                <button onClick={loadAnnualReport} disabled={loading} className="w-full relative overflow-hidden group rounded-xl shadow-md mb-8">
                    <div className="absolute inset-0 bg-gradient-to-r from-[#CE2029] to-[#B31B24]"></div>
                    <div className="relative p-6 flex items-center justify-between">
                         <div className="flex items-center gap-4">
                            <FileSpreadsheet size={28} className="text-white/80" />
                            <div className="text-left">
                                <h3 className="text-white font-bold">Annual Report FY 2025-26</h3>
                                <p className="text-white/60 text-xs">Aggregated (April 2025 - March 2026)</p>
                            </div>
                         </div>
                         <div className="bg-white text-[#CE2029] px-4 py-2 rounded-lg font-bold text-sm hover:scale-105 transition-transform">Load Full Year</div>
                    </div>
                </button>

                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4 mb-8">
                  {MONTHLY_REPORTS.map((month) => (
                    <button key={month.name} onClick={() => loadFromUrl(month.url)} disabled={loading} className="p-3 rounded-xl border border-slate-200 bg-slate-50 hover:border-[#CE2029] hover:bg-white transition-all text-center group shadow-sm">
                      <span className="font-semibold text-slate-600 text-[11px] group-hover:text-[#CE2029] uppercase tracking-wider">{month.name}</span>
                    </button>
                  ))}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <label className="cursor-pointer block">
                      <div className="flex items-center gap-3 p-4 border border-dashed border-slate-300 rounded-xl bg-slate-50 hover:bg-red-50 hover:border-red-300 transition-all h-full">
                          <UploadCloud size={20} className="text-slate-400"/>
                          <span className="text-sm font-semibold text-slate-700">Upload Excel/CSV File</span>
                          <input type="file" accept=".csv, .xlsx, .xls" onChange={handleFileUpload} className="hidden" />
                      </div>
                    </label>
                    <div className="flex items-center gap-2 p-1 border border-slate-300 rounded-xl bg-white shadow-sm overflow-hidden">
                        <input type="text" value={customUrl} onChange={(e) => setCustomUrl(e.target.value)} placeholder="Custom Google Sheet Link..." className="flex-1 min-w-0 pl-3 py-2 text-sm bg-transparent border-none focus:ring-0 text-slate-800"/>
                        <button onClick={() => loadFromUrl(customUrl)} disabled={loading} className="bg-[#CE2029] text-white p-2.5 rounded-lg transition-colors hover:bg-red-700"><LinkIcon size={18}/></button>
                    </div>
                </div>

                {error && (
                  <div className="mt-6 p-4 bg-red-50 border border-red-200 rounded-xl">
                    <div className="flex gap-3">
                      <AlertCircle className="text-[#CE2029] shrink-0" size={20}/>
                      <div>
                        <p className="text-sm font-bold text-[#CE2029]">Connection Error</p>
                        <p className="text-xs text-red-600 mt-1">{error}</p>
                        <div className="mt-3 flex items-start gap-2 p-2 bg-white/60 rounded border border-red-100">
                           <Info size={14} className="text-slate-500 shrink-0 mt-0.5" />
                           <p className="text-[10px] text-slate-600 leading-normal font-medium">
                             <strong>Tip:</strong> Ensure your Google Sheet is <strong>Published to the web</strong> (File > Share > Publish to web) and select <strong>CSV</strong> format. Normal shared links are often blocked by security policies.
                           </p>
                        </div>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {rawBookingData.length > 0 && (
          <div className="space-y-6 animate-in fade-in duration-500">
            {activeTab === 'datasheet' && <DataSheet data={enrichedBookingData} onReupload={triggerReupload} />}
            {activeTab === 'dashboard' && <DashboardAnalysis data={enrichedBookingData} masterData={masterData} onReupload={triggerReupload} />}
            {activeTab === 'rsbt' && <RSBTCellReport data={enrichedBookingData} masterData={masterData} onReupload={triggerReupload} />}
            {activeTab === 'booking' && <BookingReport data={enrichedBookingData} masterData={masterData} onReupload={triggerReupload} />}
          </div>
        )}
      </main>
    </div>
  );
}

const NavTab = ({ active, onClick, label, icon }: any) => (
  <button onClick={onClick} className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${
    active ? 'bg-white text-[#CE2029] shadow-sm' : 'text-white/80 hover:text-white hover:bg-white/10'
  }`}>
    {icon} <span className="hidden sm:inline">{label}</span>
  </button>
);

export default App;

import React, { useMemo, useState, useRef } from 'react';
import { BookingDataRow, MasterDataRow } from '../types';
import { FileSpreadsheet, Download, Printer, Home, Landmark, Mail, Package, ClipboardList, UploadCloud, MailX, PackageX } from 'lucide-react';
import { exportToPDF, exportToExcel, getProductCategory, formatCurrency } from '../utils';

interface RSBTCellReportProps {
  data: BookingDataRow[];
  masterData: MasterDataRow[];
  onReupload?: () => void;
}

type MailType = 'All Type' | 'Speed Post' | 'Parcel' | 'International Mail' | 'Gyan Post';
type BookingStatus = 'All' | 'Booked' | 'Not Booked' | 'less than 5 article booked offices' | '5+ articles booked';
type AreaFilter = 'All' | 'Rural' | 'Urban';
type OfficeTypeFilter = 'All' | 'P.O' | 'B.O';

const RSBTCellReport: React.FC<RSBTCellReportProps> = ({ data, masterData, onReupload }) => {
  // 5 Filters State
  const [filterType, setFilterType] = useState<MailType>('All Type');
  const [filterSubDiv, setFilterSubDiv] = useState('');
  const [filterArea, setFilterArea] = useState<AreaFilter>('All');
  const [filterOfficeType, setFilterOfficeType] = useState<OfficeTypeFilter>('All');
  const [filterStatus, setFilterStatus] = useState<BookingStatus>('All');

  const detailRef = useRef<HTMLDivElement>(null);

  // 1. Volume Stats for the summary table
  const volumeStats = useMemo<any>(() => {
    const results: any = { Rural: {}, Urban: {}, Total: {} };
    const categories = [
      { id: 'boSpeed', type: 'B.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'boParcel', type: 'B.O', targetCat: 'Parcel' },
      { id: 'poSpeed', type: 'P.O', targetCat: 'Domestic', isSpeed: true },
      { id: 'poParcel', type: 'P.O', targetCat: 'Parcel' },
      { id: 'poIntl', type: 'P.O', targetCat: 'International' },
    ];

    categories.forEach(cat => {
      results.Rural[cat.id] = 0; results.Urban[cat.id] = 0; results.Total[cat.id] = 0;
      data.forEach(row => {
        const rowType = row.officeType === 'B.O' ? 'B.O' : 'P.O';
        const rowCat = getProductCategory(row.productName);
        let isMatch = rowCat === cat.targetCat;
        if (cat.isSpeed && isMatch) isMatch = row.productName.toLowerCase().includes('speed post');
        if (isMatch && rowType === cat.type) {
          const area = row.areaType?.toLowerCase().includes('urban') ? 'Urban' : 'Rural';
          results[area][cat.id] += row.articles;
          results.Total[cat.id] += row.articles;
        }
      });
    });
    return results;
  }, [data]);

  // 2. Performance Summaries with revised booking logic (Revenue > 0)
  const performanceStats = useMemo(() => {
    const stats = {
      bo: { total: 0, bookedSP: 0, bookedPar: 0, notBookedSP: 0, notBookedPar: 0 },
      po: { total: 0, bookedSP: 0, bookedPar: 0, notBookedSP: 0, notBookedPar: 0 },
    };

    const officePerf = new Map<string, { spArts: number, spAmt: number, parArts: number, parAmt: number }>();

    data.forEach(row => {
      const cat = getProductCategory(row.productName);
      const isSP = cat === 'Domestic' && row.productName.toLowerCase().includes('speed post');
      const isPar = cat === 'Parcel';

      const current = officePerf.get(row.officeId) || { spArts: 0, spAmt: 0, parArts: 0, parAmt: 0 };
      if (isSP) {
        current.spArts += row.articles;
        current.spAmt += row.totalAmount;
      }
      if (isPar) {
        current.parArts += row.articles;
        current.parAmt += row.totalAmount;
      }
      officePerf.set(row.officeId, current);
    });

    masterData.forEach(m => {
      const isBO = m.officeType === 'B.O';
      const p = officePerf.get(m.officeId) || { spArts: 0, spAmt: 0, parArts: 0, parAmt: 0 };

      // Office is booked only if Articles > 0 AND Amount > 0
      const hasSP = p.spArts > 0 && p.spAmt > 0;
      const hasPar = p.parArts > 0 && p.parAmt > 0;

      if (isBO) {
        stats.bo.total++;
        if (hasSP) stats.bo.bookedSP++; else stats.bo.notBookedSP++;
        if (hasPar) stats.bo.bookedPar++; else stats.bo.notBookedPar++;
      } else {
        stats.po.total++;
        if (hasSP) stats.po.bookedSP++; else stats.po.notBookedSP++;
        if (hasPar) stats.po.bookedPar++; else stats.po.notBookedPar++;
      }
    });
    return stats;
  }, [data, masterData]);

  // 3. Main Filtered List (8 Columns Logic)
  const detailedReportList = useMemo(() => {
    // Current bookings based on Mail Type selection
    const typeBookings = data.filter(r => {
      if (filterType === 'All Type') return true;
      const cat = getProductCategory(r.productName);
      if (filterType === 'Speed Post') return cat === 'Domestic' && r.productName.toLowerCase().includes('speed post');
      if (filterType === 'Gyan Post') return cat === 'Domestic' && r.productName.toLowerCase().includes('gyan post');
      if (filterType === 'Parcel') return cat === 'Parcel';
      return cat === 'International';
    });

    const bookingMap = new Map<string, { articles: number, postage: number, amount: number }>();
    typeBookings.forEach(b => {
      const current = bookingMap.get(b.officeId) || { articles: 0, postage: 0, amount: 0 };
      current.articles += b.articles;
      current.postage += b.postage;
      current.amount += b.totalAmount;
      bookingMap.set(b.officeId, current);
    });

    const filtered = masterData
      .map(office => {
        const booking = bookingMap.get(office.officeId);
        return {
          ...office,
          articles: booking ? booking.articles : 0,
          postage: booking ? booking.postage : 0,
          amount: booking ? booking.amount : 0,
          // Refined definition: Booked only if revenue > 0
          isActuallyBooked: booking ? (booking.articles > 0 && booking.amount > 0) : false
        };
      })
      .filter(office => {
        if (filterSubDiv && !office.subDivisionName.toLowerCase().includes(filterSubDiv.toLowerCase())) return false;
        if (filterArea !== 'All' && office.areaType !== filterArea) return false;
        if (filterOfficeType !== 'All' && office.officeType !== filterOfficeType) return false;

        if (filterStatus === 'Booked' && !office.isActuallyBooked) return false;
        if (filterStatus === 'Not Booked' && office.isActuallyBooked) return false;
        if (filterStatus === 'less than 5 article booked offices' && (!office.isActuallyBooked || office.articles >= 5)) return false;
        if (filterStatus === '5+ articles booked' && (!office.isActuallyBooked || office.articles < 5)) return false;

        return true;
      });

    return filtered.sort((a, b) => a.officeName.localeCompare(b.officeName));
  }, [masterData, data, filterType, filterSubDiv, filterArea, filterOfficeType, filterStatus]);

  const handleQuickAction = (type: MailType, status: BookingStatus, officeType: OfficeTypeFilter) => {
    setFilterType(type);
    setFilterStatus(status);
    setFilterOfficeType(officeType);
    setTimeout(() => {
      detailRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  const exportReport = (format: 'pdf' | 'excel') => {
    const reportTitle = `${filterType} Booking Report (Office Wise A-Z)`;
    const headers = ['Sl No', 'Name of the Office', 'Office ID', 'Sub-Division Name', 'Office Type', 'Number', 'Postage', 'Amount'];

    const rows: any[] = detailedReportList.map((row, i) => [
      i + 1,
      row.officeName,
      row.officeId,
      row.subDivisionName,
      row.officeType,
      row.articles,
      row.postage.toFixed(2),
      row.amount.toFixed(2)
    ]);

    const totalArticles = detailedReportList.reduce((acc, r) => acc + r.articles, 0);
    const totalPostage = detailedReportList.reduce((acc, r) => acc + r.postage, 0);
    const totalAmount = detailedReportList.reduce((acc, r) => acc + r.amount, 0);

    if (format === 'excel') {
      const excelData = detailedReportList.map((row, i) => ({
        'Sl No': i + 1,
        'Name of the Office': row.officeName,
        'Office ID': row.officeId,
        'Sub-Division Name': row.subDivisionName,
        'Office Type': row.officeType,
        'Number (Articles)': row.articles,
        'Postage': row.postage,
        'Amount': row.amount
      }));
      excelData.push({
        'Sl No': '',
        'Name of the Office': 'GRAND TOTAL',
        'Office ID': '',
        'Sub-Division Name': '',
        'Office Type': '',
        'Number (Articles)': totalArticles,
        'Postage': totalPostage,
        'Amount': totalAmount
      } as any);
      exportToExcel(excelData, reportTitle.replace(/\s+/g, '_'));
    } else {
      rows.push(['', 'GRAND TOTAL', '', '', '', totalArticles, totalPostage.toFixed(2), totalAmount.toFixed(2)]);
      exportToPDF(headers, rows, reportTitle, true);
    }
  };

  const exportMatrixReport = () => {
    const headers = ['Category / Area', 'BO Speed Post', 'BO Parcel', 'PO Speed Post', 'PO Parcel', 'PO International'];
    const rows = ['Rural', 'Urban', 'Total'].map(area => [
      area,
      volumeStats[area].boSpeed,
      volumeStats[area].boParcel,
      volumeStats[area].poSpeed,
      volumeStats[area].poParcel,
      volumeStats[area].poIntl,
    ]);
    exportToPDF(headers, rows, 'RSBT Cell Volume Matrix Report', true);
  };

  const getSubDivisions = useMemo(() => {
    return Array.from(new Set(masterData.map(m => m.subDivisionName))).sort();
  }, [masterData]);

  return (
    <div className="space-y-8 pb-10">
      {/* QUICK STAT CARDS */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2 border-b border-slate-100 pb-2">
            <div className="p-1.5 bg-amber-50 text-amber-600 rounded-lg"><Home size={18}/></div>
            Branch Office (BO) Performance
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <QuickStatButton 
              label="SP Booked" 
              value={performanceStats.bo.bookedSP} 
              total={performanceStats.bo.total} 
              icon={<Mail size={16}/>}
              color="emerald"
              onClick={() => handleQuickAction('Speed Post', 'Booked', 'B.O')}
            />
            <QuickStatButton 
              label="SP Not Booked" 
              value={performanceStats.bo.notBookedSP} 
              total={performanceStats.bo.total} 
              icon={<MailX size={16}/>}
              color="rose"
              onClick={() => handleQuickAction('Speed Post', 'Not Booked', 'B.O')}
            />
            <QuickStatButton 
              label="Parcel Booked" 
              value={performanceStats.bo.bookedPar} 
              total={performanceStats.bo.total} 
              icon={<Package size={16}/>}
              color="amber"
              onClick={() => handleQuickAction('Parcel', 'Booked', 'B.O')}
            />
            <QuickStatButton 
              label="Parcel Not Booked" 
              value={performanceStats.bo.notBookedPar} 
              total={performanceStats.bo.total} 
              icon={<PackageX size={16}/>}
              color="rose"
              onClick={() => handleQuickAction('Parcel', 'Not Booked', 'B.O')}
            />
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2 border-b border-slate-100 pb-2">
            <div className="p-1.5 bg-blue-50 text-blue-600 rounded-lg"><Landmark size={18}/></div>
            Sub Office / PO Performance
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <QuickStatButton 
              label="SP Booked" 
              value={performanceStats.po.bookedSP} 
              total={performanceStats.po.total} 
              icon={<Mail size={16}/>}
              color="blue"
              onClick={() => handleQuickAction('Speed Post', 'Booked', 'P.O')}
            />
            <QuickStatButton 
              label="SP Not Booked" 
              value={performanceStats.po.notBookedSP} 
              total={performanceStats.po.total} 
              icon={<MailX size={16}/>}
              color="rose"
              onClick={() => handleQuickAction('Speed Post', 'Not Booked', 'P.O')}
            />
            <QuickStatButton 
              label="Parcel Booked" 
              value={performanceStats.po.bookedPar} 
              total={performanceStats.po.total} 
              icon={<Package size={16}/>}
              color="amber"
              onClick={() => handleQuickAction('Parcel', 'Booked', 'P.O')}
            />
            <QuickStatButton 
              label="Parcel Not Booked" 
              value={performanceStats.po.notBookedPar} 
              total={performanceStats.po.total} 
              icon={<PackageX size={16}/>}
              color="rose"
              onClick={() => handleQuickAction('Parcel', 'Not Booked', 'P.O')}
            />
          </div>
        </div>
      </div>

      {/* DETAILED MONITORING SECTION */}
      <div ref={detailRef} className="bg-white p-6 rounded-2xl shadow-lg border border-slate-200 space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div>
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2">
              <ClipboardList className="text-[#CE2029]" /> Detailed Monitoring Dashboard
            </h2>
            <p className="text-[11px] text-slate-500 font-medium">Monitoring {detailedReportList.length} offices sorted Alphabetically (A-Z)</p>
          </div>
          <div className="flex gap-2 flex-wrap">
             <button onClick={onReupload} className="flex items-center gap-1.5 px-3 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-all text-xs font-bold shadow-md">
               <UploadCloud size={14}/> RE-UPLOAD EXCEL
             </button>
             <button onClick={() => exportReport('excel')} className="flex items-center gap-1.5 px-3 py-2 bg-green-50 text-green-700 rounded-lg border border-green-200 hover:bg-green-100 transition-all text-xs font-bold">
               <Download size={14}/> EXCEL
             </button>
             <button onClick={() => exportReport('pdf')} className="flex items-center gap-1.5 px-3 py-2 bg-red-50 text-[#CE2029] rounded-lg border border-red-200 hover:bg-red-100 transition-all text-xs font-bold">
               <Printer size={14}/> PRINT REPORT
             </button>
          </div>
        </div>

        {/* 5 SEARCH FILTERS */}
        <div className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-5 gap-3 p-4 bg-slate-50 rounded-xl border border-slate-200 shadow-inner">
           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">1. Sub-Division</label>
              <div className="relative">
                <input 
                  type="text"
                  placeholder="All Sub-Div..."
                  value={filterSubDiv}
                  onChange={e => setFilterSubDiv(e.target.value)}
                  className="w-full bg-white border border-slate-200 rounded-md pl-2 pr-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
                  list="subdiv-opts"
                />
                <datalist id="subdiv-opts">
                  {getSubDivisions.map(s => <option key={s} value={s} />)}
                </datalist>
              </div>
           </div>

           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">2. Rural/Urban</label>
              <select 
                value={filterArea} 
                onChange={e => setFilterArea(e.target.value as AreaFilter)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Areas</option>
                <option value="Rural">Rural Only</option>
                <option value="Urban">Urban Only</option>
              </select>
           </div>

           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">3. Status</label>
              <select 
                value={filterStatus} 
                onChange={e => setFilterStatus(e.target.value as BookingStatus)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
                <option value="All">All Status</option>
                <option value="Booked">Booked (Revenue > 0)</option>
                <option value="Not Booked">Not Booked (Revenue = 0)</option>
                <option value="less than 5 article booked offices">less than 5 article booked offices</option>
                <option value="5+ articles booked">5+ articles booked</option>
              </select>
           </div>

           <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400">4. Mail Type</label>
              <select 
                value={filterType} 
                onChange={e => setFilterType(e.target.value as MailType)}
                className="w-full bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs font-bold focus:ring-1 focus:ring-red-500 outline-none shadow-sm"
              >
